for code in MEM_PATH_UNREACHABLE MEM_INDEX_STALE MEM_VALIDATE_ERRORS MEM_CONFLICT_HIGH; do
  if grep -q "$code:" "$ROOT/bin/modules/health.cjs"; then
    pass "health.cjs CHECKS catalog includes $code"
