     && /usr/bin/grep -q "top-3" "$ROOT/$wf" \
     && /usr/bin/grep -q "direct_dependents" "$ROOT/$wf" \
     && /usr/bin/grep -q "get_neighbors" "$ROOT/$wf"; then
