K36_TMP=$(mktemp -d)
K36_TMP=$(cd "$K36_TMP" && pwd -P)
mkdir -p "$K36_TMP/.devt/state"
echo '{}' > "$K36_TMP/.devt/config.json"
# preflight-brief.json::topic.resolution_path is populated even on degraded
