if grep -qE 'LANE_GRAPH_IMPACT_BLOCK=' "$ROOT/workflows/code-review-parallel.md"; then
  pass "K34: code-review-parallel.md bash-computes LANE_GRAPH_IMPACT_BLOCK (no orchestrator judgment)"
else
