# K50 — every workflow that dispatches an output-writing agent MUST have at
# least one assert-artifact-present Layer-1 call. cal #19 §9 Surprise 3:
# field discovered 23 state subcommands exist but only 8 referenced in
# workflows — exactly the integration gap this gate locks. Coverage matrix:
# any workflow that contains `Task(subagent_type="devt:<agent>"` for an
# agent declared in io-contracts.yaml MUST also reference
# `assert-artifact-present` at least once. Curator dispatches with
# `outputs.primary: null` would auto-pass the runtime check but the gate
# still requires the call for audit-trail consistency.
K50_FAIL=""
# Agents whose outputs.primary is NOT null per io-contracts.yaml.
# (Curator IS included even though its primary is curation-summary.md,
# matching its io-contract.)
K50_OUTPUT_WRITERS="programmer tester code-reviewer docs-writer architect retro verifier researcher debugger curator"
for wf in "$ROOT"/workflows/*.md; do
  # Skip if no Task dispatch at all (orchestration-only workflows like next.md, pause.md).
  if ! grep -q 'Task(subagent_type="devt:' "$wf" 2>/dev/null; then continue; fi
  # Determine which output-writing agents this workflow dispatches.
  dispatched=""
  for ag in $K50_OUTPUT_WRITERS; do
    if grep -q "Task(subagent_type=\"devt:${ag}\"" "$wf" 2>/dev/null; then
      dispatched="$dispatched $ag"
    fi
  done
  if [ -z "$dispatched" ]; then continue; fi
  # Workflow dispatches at least one output-writer — require Layer-1.
  if ! grep -q "assert-artifact-present" "$wf" 2>/dev/null; then
    K50_FAIL="$K50_FAIL $(basename "$wf")"
  fi
done
if [ -z "$K50_FAIL" ]; then
  pass "K50: every workflow dispatching output-writing agents has Layer-1 assert-artifact-present (11 workflows checked)"
else
  fail "K50: workflows missing Layer-1 claim-check despite dispatching output-writers:$K50_FAIL"
fi

# K51 — substance-aware Layer-1 + Layer-2 stub-blocking. cal #20 §1 friction:
# Layer-1 recorded verdict=success on 65/72-byte stubs because the check was
# file-presence-only; Layer-2 would PASS false-positive if a stub won the
# latest-timestamp slot. Substance-aware Layer-1 now persists
# substance_verdict; Layer-2 BLOCKS when latest=success but
# substance_verdict=stub. Successful retry overwriting stub-record stays the
# happy path. Five-state matrix: large-substantive | stub | substantive
# | Layer-2-blocks-on-stub | Layer-2-resolves-on-retry.
K51_TMP=$(mktemp -d)
mkdir -p "$K51_TMP/.devt/state"
echo '{}' > "$K51_TMP/.devt/config.json"
cat > "$K51_TMP/.devt/state/workflow.yaml" <<EOF_K51
active: true
workflow_id: test-wf-K51
workflow_type: dev
phase: implement
first_created_at: "2026-06-04T10:00:00Z"
created_at: "2026-06-04T10:00:00Z"
EOF_K51
# Large substantive file (>1000 B → size short-circuit)
{ yes "fill line for size short-circuit test" 2>/dev/null || true; } | head -50 > "$K51_TMP/.devt/state/impl-summary.md" || true
K51_LARGE=$(cd "$K51_TMP" && node "$CLI" state assert-artifact-present programmer 2>/dev/null | jq -r '.substance_verdict' 2>/dev/null || echo "")
# Stub file (header-only — em-dash)
echo "# Impl — in progress" > "$K51_TMP/.devt/state/impl-summary.md"
rm -f "$K51_TMP/.devt/state/claim-check-failures.jsonl"
cd "$K51_TMP" && node "$CLI" state assert-artifact-present programmer > /dev/null 2>&1
cd "$ROOT"
K51_STUB=$(tail -1 "$K51_TMP/.devt/state/claim-check-failures.jsonl" 2>/dev/null | jq -r '.substance_verdict' 2>/dev/null || echo "")
K51_L2_BLOCK=$(cd "$K51_TMP" && node "$CLI" state assert-claim-checks-resolved 2>/dev/null | jq -r '.ok' 2>/dev/null || echo "")
# Substantive retry
cat > "$K51_TMP/.devt/state/impl-summary.md" <<EOF_K51_SUB
# Implementation Summary

## Files Modified

- src/auth.py — redis-backed rate-limit middleware enforcing 100 requests per minute per token. Token resolution uses the existing decode_jwt helper; configurable via RATE_LIMIT_PER_MINUTE env var. Fail-open on redis outage with a structured warning log.
- tests/test_auth.py — covers limit reached, token refill, fail-open, overflow burst, concurrent-request paths.

Sliding-window counters chosen over fixed-window to avoid boundary burst effect.
EOF_K51_SUB
cd "$K51_TMP" && node "$CLI" state assert-artifact-present programmer > /dev/null 2>&1
cd "$ROOT"
K51_RETRY=$(tail -1 "$K51_TMP/.devt/state/claim-check-failures.jsonl" 2>/dev/null | jq -r '.substance_verdict' 2>/dev/null || echo "")
K51_L2_PASS=$(cd "$K51_TMP" && node "$CLI" state assert-claim-checks-resolved 2>/dev/null | jq -r '.ok' 2>/dev/null || echo "")
if [ "$K51_LARGE" = "substantive" ] && [ "$K51_STUB" = "stub" ] && [ "$K51_L2_BLOCK" = "false" ] && \
   [ "$K51_RETRY" = "substantive" ] && [ "$K51_L2_PASS" = "true" ]; then
  pass "K51: substance-aware Layer-1 + Layer-2 stub-blocking (large→substantive | stub→stub+L2-blocks | retry→substantive+L2-passes)"
else
  fail "K51: substance-aware verdict misfired (large=$K51_LARGE stub=$K51_STUB L2-block=$K51_L2_BLOCK retry=$K51_RETRY L2-pass=$K51_L2_PASS)"
fi
rm -rf "$K51_TMP"

# K52 — assert-file-quiescent mtime-stability primitive. cal #20 §3 fix:
# substance-check-race guard that ensures the file isn't actively being
# written before any reader fires. Three states: stable file passes; missing
# file fails fast; settle window honored (≥ requested settle_ms latency).
K52_TMP=$(mktemp -d)
mkdir -p "$K52_TMP/.devt/state"
echo '{}' > "$K52_TMP/.devt/config.json"
echo "stable content for quiescence test" > "$K52_TMP/.devt/state/stable.md"
K52_STABLE=$(cd "$K52_TMP" && node "$CLI" state assert-file-quiescent .devt/state/stable.md --settle-ms=100 --timeout-ms=2000 2>/dev/null | jq -r '.ok' 2>/dev/null || echo "")
K52_MISSING=$(cd "$K52_TMP" && node "$CLI" state assert-file-quiescent .devt/state/missing.md --settle-ms=100 --timeout-ms=500 2>/dev/null | jq -r '.ok' 2>/dev/null || echo "")
K52_LATENCY=$(cd "$K52_TMP" && node "$CLI" state assert-file-quiescent .devt/state/stable.md --settle-ms=100 --timeout-ms=2000 2>/dev/null | jq -r '.total_ms' 2>/dev/null || echo "0")
if [ "$K52_STABLE" = "true" ] && [ "$K52_MISSING" = "false" ] && [ "$K52_LATENCY" -ge 100 ]; then
  pass "K52: assert-file-quiescent (stable=true | missing=false | latency≥settle_ms — got ${K52_LATENCY}ms)"
else
  fail "K52: mtime-stability misfired (stable=$K52_STABLE missing=$K52_MISSING latency=$K52_LATENCY)"
fi
rm -rf "$K52_TMP"

# K53 — assert-lanes-quiesced workflow-mechanical opt-in gate. Reads
# workflow.yaml::lanes[*].status; blocks if any are still in_flight; passes
# when all are terminal. Available for workflows that own the lane lifecycle
# tightly (orchestrator updates status away from in_flight after each Task
# returns). Not the default path — mtime-stability is the mechanical primary;
# this is the strict opt-in for projects that prefer the explicit contract.
K53_TMP=$(mktemp -d)
mkdir -p "$K53_TMP/.devt/state"
echo '{}' > "$K53_TMP/.devt/config.json"
cat > "$K53_TMP/.devt/state/workflow.yaml" <<EOF_K53_BLOCK
active: true
workflow_type: code_review_parallel
phase: dispatch_lanes
first_created_at: "2026-06-05T10:00:00Z"
created_at: "2026-06-05T10:00:00Z"
lanes:
  - id: L1
    community: auth
    review_file: .devt/state/review-lane-L1.md
    status: in_flight
    redispatch_count: 0
  - id: L2
    community: billing
    review_file: .devt/state/review-lane-L2.md
    status: in_flight
    redispatch_count: 0
EOF_K53_BLOCK
K53_BLOCK=$(cd "$K53_TMP" && node "$CLI" state assert-lanes-quiesced 2>/dev/null | jq -r '.ok' 2>/dev/null || echo "")
K53_INFLIGHT=$(cd "$K53_TMP" && node "$CLI" state assert-lanes-quiesced 2>/dev/null | jq -r '.in_flight_count' 2>/dev/null || echo "")
# Now flip both to terminal
cat > "$K53_TMP/.devt/state/workflow.yaml" <<EOF_K53_PASS
active: true
workflow_type: code_review_parallel
phase: substance_check_lanes
first_created_at: "2026-06-05T10:00:00Z"
created_at: "2026-06-05T10:00:00Z"
lanes:
  - id: L1
    community: auth
    review_file: .devt/state/review-lane-L1.md
    status: substance_pass
    redispatch_count: 0
  - id: L2
    community: billing
    review_file: .devt/state/review-lane-L2.md
    status: deferred
    redispatch_count: 0
EOF_K53_PASS
K53_PASS=$(cd "$K53_TMP" && node "$CLI" state assert-lanes-quiesced 2>/dev/null | jq -r '.ok' 2>/dev/null || echo "")
K53_TERMINAL=$(cd "$K53_TMP" && node "$CLI" state assert-lanes-quiesced 2>/dev/null | jq -r '.terminal_count' 2>/dev/null || echo "")
if [ "$K53_BLOCK" = "false" ] && [ "$K53_INFLIGHT" = "2" ] && \
   [ "$K53_PASS" = "true" ] && [ "$K53_TERMINAL" = "2" ]; then
  pass "K53: assert-lanes-quiesced (in_flight×2 → block | terminal×2 → pass)"
else
  fail "K53: lanes-quiesced gate misfired (block=$K53_BLOCK in_flight=$K53_INFLIGHT pass=$K53_PASS terminal=$K53_TERMINAL)"
fi
rm -rf "$K53_TMP"

# K54 — council surface integrity. Anti-regression for the 4-file council
# surface (SKILL.md, commands/council.md, references/council-offramp.md,
# workflow integrations). Verifies: (a) all 3 canonical files exist; (b)
# 4 workflows that integrate council still reference the canonical offramp
# path. Protects against quiet drift between SKILL.md prose and workflow
# references — a known failure shape from v0.73.x prose-drift incidents.
K54_FAIL=""
[ -f "$ROOT/skills/council/SKILL.md" ] || K54_FAIL="$K54_FAIL skills/council/SKILL.md"
[ -f "$ROOT/commands/council.md" ] || K54_FAIL="$K54_FAIL commands/council.md"
[ -f "$ROOT/references/council-offramp.md" ] || K54_FAIL="$K54_FAIL references/council-offramp.md"
# Workflows that reference the canonical offramp path. Field + canonical
# integration paths per offramp doc §3 (clarify, research, specify) plus the
# memory workflows that surface council in their context (memory-promote,
# memory-reject). All MUST cite the canonical path.
K54_REF_PATH="references/council-offramp.md"
for wf in clarify-task.md research-task.md; do
  if [ -f "$ROOT/workflows/$wf" ]; then
    if ! grep -q "$K54_REF_PATH" "$ROOT/workflows/$wf" 2>/dev/null; then
      K54_FAIL="$K54_FAIL workflows/$wf-missing-offramp-ref"
    fi
  fi
done
if [ -z "$K54_FAIL" ]; then
  pass "K54: council surface integrity (SKILL + command + offramp + 2 workflow integrations all present)"
else
  fail "K54: council surface drift:$K54_FAIL"
fi

# K55 — council-trace CLI emits records to gate-trace.jsonl with stage,
# slug, model metadata + workflow_id/workflow_type/phase enrichment.
# Enables cal cycles to measure council usage (per workflow_type, per
# session, per stage). Three-stage matrix exercised: stage-2 (advisor
# batch), stage-3 (peer review batch), stage-4 (chairman with model).
K55_TMP=$(mktemp -d)
mkdir -p "$K55_TMP/.devt/state"
echo '{}' > "$K55_TMP/.devt/config.json"
cat > "$K55_TMP/.devt/state/workflow.yaml" <<EOF_K55
active: true
workflow_id: test-wf-K55
workflow_type: code_review
phase: implement
first_created_at: "2026-06-05T10:00:00Z"
created_at: "2026-06-05T10:00:00Z"
EOF_K55
(cd "$K55_TMP" && node "$CLI" state council-trace stage-2 --slug=test-decision >/dev/null 2>&1) || true
(cd "$K55_TMP" && node "$CLI" state council-trace stage-3 --slug=test-decision >/dev/null 2>&1) || true
(cd "$K55_TMP" && node "$CLI" state council-trace stage-4 --slug=test-decision --model=opus >/dev/null 2>&1) || true
K55_COUNT=$(awk '/"source":"council"/' "$K55_TMP/.devt/state/gate-trace.jsonl" 2>/dev/null | wc -l | tr -d ' ')
K55_S4_MODEL=$(awk '/"stage":"stage-4"/{print}' "$K55_TMP/.devt/state/gate-trace.jsonl" 2>/dev/null | jq -r '.model' 2>/dev/null || echo "")
K55_S2_TYPE=$(awk '/"stage":"stage-2"/{print}' "$K55_TMP/.devt/state/gate-trace.jsonl" 2>/dev/null | jq -r '.workflow_type' 2>/dev/null || echo "")
if [ "$K55_COUNT" = "3" ] && [ "$K55_S4_MODEL" = "opus" ] && [ "$K55_S2_TYPE" = "code_review" ]; then
  pass "K55: council-trace emits 3 records with stage + metadata + workflow_type enrichment"
else
  fail "K55: council-trace misfired (records=$K55_COUNT s4_model=$K55_S4_MODEL s2_type=$K55_S2_TYPE)"
fi
rm -rf "$K55_TMP"

# K56 — multi-instance isolation via DEVT_WORKFLOW_ID env var. Three states:
# (a) unset → getStateDir() returns legacy path; existing writes work unchanged
# (b) set with safe id → writes route to per-instance subdir
# (c) set with unsafe id (path traversal attempt) → falls back to legacy + stderr warn
K56_TMP=$(mktemp -d)
mkdir -p "$K56_TMP/.devt/state"
echo '{}' > "$K56_TMP/.devt/config.json"
# State (a): env unset
(cd "$K56_TMP" && unset DEVT_WORKFLOW_ID && node "$CLI" state update k56_legacy=true >/dev/null 2>&1) || true
K56_A_OK=$([ -f "$K56_TMP/.devt/state/workflow.yaml" ] && echo "true" || echo "false")
# State (b): env set with safe id
(cd "$K56_TMP" && DEVT_WORKFLOW_ID=test_inst node "$CLI" state update k56_perinst=true >/dev/null 2>&1) || true
K56_B_OK=$([ -f "$K56_TMP/.devt/state/test_inst/workflow.yaml" ] && echo "true" || echo "false")
# State (c): unsafe id → expected legacy fallback + stderr warn
K56_C_STDERR=$(cd "$K56_TMP" && DEVT_WORKFLOW_ID="../etc" node "$CLI" state update k56_unsafe=true 2>&1 >/dev/null || true)
K56_C_WARN=$(echo "$K56_C_STDERR" | grep -c "rejected" || true)
if [ "$K56_A_OK" = "true" ] && [ "$K56_B_OK" = "true" ] && [ "$K56_C_WARN" -ge 1 ]; then
  pass "K56: DEVT_WORKFLOW_ID isolation (unset→legacy | safe→perinst | unsafe→legacy+warn)"
else
  fail "K56: multi-instance isolation misfired (a=$K56_A_OK b=$K56_B_OK c-warn=$K56_C_WARN)"
fi
rm -rf "$K56_TMP"

# K57 — new-instance + list-instances CLI round-trip. new-instance creates
# subdir + index entry; list-instances enumerates with tag + file_count.
K57_TMP=$(mktemp -d)
mkdir -p "$K57_TMP/.devt/state"
echo '{}' > "$K57_TMP/.devt/config.json"
K57_WFID=$(cd "$K57_TMP" && node "$CLI" state new-instance --tag=K57-test 2>/dev/null | jq -r .wf_id 2>/dev/null || echo "")
K57_SUBDIR_OK=$([ -n "$K57_WFID" ] && [ -d "$K57_TMP/.devt/state/$K57_WFID" ] && echo "true" || echo "false")
K57_INDEX_OK=$([ -n "$K57_WFID" ] && [ -f "$K57_TMP/.devt/state/.instances/$K57_WFID.json" ] && echo "true" || echo "false")
K57_LIST=$(cd "$K57_TMP" && node "$CLI" state list-instances 2>/dev/null)
K57_LIST_COUNT=$(echo "$K57_LIST" | jq -r '.count' 2>/dev/null || echo "0")
K57_LIST_TAG=$(echo "$K57_LIST" | jq -r '.instances[0].tag' 2>/dev/null || echo "")
if [ "$K57_SUBDIR_OK" = "true" ] && [ "$K57_INDEX_OK" = "true" ] && \
   [ "$K57_LIST_COUNT" = "1" ] && [ "$K57_LIST_TAG" = "K57-test" ]; then
  pass "K57: new-instance + list-instances round-trip (subdir + index + enumeration with tag)"
else
  fail "K57: instance lifecycle misfired (subdir=$K57_SUBDIR_OK index=$K57_INDEX_OK count=$K57_LIST_COUNT tag=$K57_LIST_TAG)"
fi
rm -rf "$K57_TMP"

# K58 — assert-council-not-recent re-run prevention. Closes offramp §4
# anti-pattern: re-running council on a decision a transcript already exists
# for. Glob check on .devt/state/council-<slug>-*.md at the root.
K58_TMP=$(mktemp -d)
mkdir -p "$K58_TMP/.devt/state"
echo '{}' > "$K58_TMP/.devt/config.json"
K58_NONE=$(cd "$K58_TMP" && node "$CLI" state assert-council-not-recent "test-slug" 2>/dev/null | jq -r '.ok' 2>/dev/null || echo "")
touch "$K58_TMP/.devt/state/council-test-slug-20260605-100000.md"
K58_FOUND=$(cd "$K58_TMP" && node "$CLI" state assert-council-not-recent "test-slug" 2>/dev/null | jq -r '.ok' 2>/dev/null || echo "")
K58_WARN=$(cd "$K58_TMP" && node "$CLI" state assert-council-not-recent "test-slug" --warn 2>/dev/null | jq -r '.warn' 2>/dev/null || echo "")
if [ "$K58_NONE" = "true" ] && [ "$K58_FOUND" = "false" ] && [ "$K58_WARN" = "true" ]; then
  pass "K58: assert-council-not-recent (no-prior→ok | prior→block | --warn→ok+warn)"
else
  fail "K58: re-run prevention misfired (none=$K58_NONE found=$K58_FOUND warn=$K58_WARN)"
fi
rm -rf "$K58_TMP"

# K59 — council-validation-material annotated JSON. Existence tags + optional
# inline file contents for direct prompt injection. Closes SKILL.md Stage 1
# prose-only "tag EXISTS/MISSING" instruction.
K59_TMP=$(mktemp -d)
mkdir -p "$K59_TMP/.devt/state" "$K59_TMP/.devt/rules"
echo '{}' > "$K59_TMP/.devt/config.json"
echo "# coding standards content" > "$K59_TMP/.devt/rules/coding-standards.md"
K59_OUT=$(cd "$K59_TMP" && node "$CLI" state council-validation-material .devt/rules/coding-standards.md .devt/rules/missing.md --inline 2>/dev/null)
K59_EXISTS=$(echo "$K59_OUT" | jq -r '.entries[0].exists' 2>/dev/null || echo "")
K59_MISSING=$(echo "$K59_OUT" | jq -r '.entries[1].exists' 2>/dev/null || echo "")
K59_CONTENT=$(echo "$K59_OUT" | jq -r '.entries[0].content' 2>/dev/null || echo "")
# Path-traversal rejection
K59_TRAVERSAL=$(cd "$K59_TMP" && node "$CLI" state council-validation-material "../etc/passwd" 2>/dev/null | jq -r '.entries[0].reason' 2>/dev/null || echo "")
if [ "$K59_EXISTS" = "true" ] && [ "$K59_MISSING" = "false" ] && \
   [ "${K59_CONTENT:0:1}" = "#" ] && [[ "$K59_TRAVERSAL" == *"rejected"* ]]; then
  pass "K59: council-validation-material (exists+missing tags + --inline contents + path-traversal rejected)"
else
  fail "K59: validation-material misfired (exists=$K59_EXISTS missing=$K59_MISSING content-head=${K59_CONTENT:0:1} traversal=${K59_TRAVERSAL:0:30})"
fi
rm -rf "$K59_TMP"

# K60 — assert-advisor-diversity. Catches the degenerate case where all 5
# advisors return identical Recommendation (SKILL.md natural-tensions design
# collapsed). Three states: collapsed → block, diverse → pass, fewer than 2
# files → not applicable.
K60_TMP=$(mktemp -d)
mkdir -p "$K60_TMP/.devt/state"
echo '{}' > "$K60_TMP/.devt/config.json"
# State (a): 5 identical recommendations → block
mkdir -p "$K60_TMP/collapsed"
for i in 1 2 3 4 5; do
  cat > "$K60_TMP/collapsed/advisor-$i.md" <<EOF_K60_COL
## Options Considered
- Option A
- Option B

## Recommendation
Pick Option A and proceed with the standard approach.
EOF_K60_COL
done
K60_COLLAPSED=$(cd "$K60_TMP" && node "$CLI" state assert-advisor-diversity collapsed 2>/dev/null | jq -r '.ok' 2>/dev/null || echo "")
# State (b): 5 diverse recommendations → pass
mkdir -p "$K60_TMP/diverse"
for i in 1 2 3 4 5; do
  cat > "$K60_TMP/diverse/advisor-$i.md" <<EOF_K60_DIV
## Recommendation
Approach $i: different reasoning chain $i
EOF_K60_DIV
done
K60_DIVERSE=$(cd "$K60_TMP" && node "$CLI" state assert-advisor-diversity diverse 2>/dev/null | jq -r '.ok' 2>/dev/null || echo "")
if [ "$K60_COLLAPSED" = "false" ] && [ "$K60_DIVERSE" = "true" ]; then
  pass "K60: assert-advisor-diversity (5 identical → block | 5 different → pass)"
else
  fail "K60: diversity check misfired (collapsed=$K60_COLLAPSED diverse=$K60_DIVERSE)"
fi
rm -rf "$K60_TMP"

# K61 — assert-council-budget soft-cap. Counts council-trace stage-4 emits
# in the current workflow window (anchored at first_created_at). Default
# budget = 1 per offramp §4 anti-pattern.
K61_TMP=$(mktemp -d)
mkdir -p "$K61_TMP/.devt/state"
echo '{}' > "$K61_TMP/.devt/config.json"
cat > "$K61_TMP/.devt/state/workflow.yaml" <<EOF_K61
active: true
workflow_id: test-wf-K61
workflow_type: dev
phase: clarify
first_created_at: "2026-06-05T00:00:00Z"
created_at: "2026-06-05T00:00:00Z"
EOF_K61
K61_ZERO=$(cd "$K61_TMP" && node "$CLI" state assert-council-budget --max-per-workflow=1 2>/dev/null | jq -r '.ok' 2>/dev/null || echo "")
(cd "$K61_TMP" && node "$CLI" state council-trace stage-4 --slug=decision-1 >/dev/null 2>&1) || true
K61_ONE=$(cd "$K61_TMP" && node "$CLI" state assert-council-budget --max-per-workflow=1 2>/dev/null | jq -r '.ok' 2>/dev/null || echo "")
K61_TWO=$(cd "$K61_TMP" && node "$CLI" state assert-council-budget --max-per-workflow=2 2>/dev/null | jq -r '.ok' 2>/dev/null || echo "")
if [ "$K61_ZERO" = "true" ] && [ "$K61_ONE" = "false" ] && [ "$K61_TWO" = "true" ]; then
  pass "K61: assert-council-budget (0 → ok | 1+max=1 → block | 1+max=2 → ok)"
else
  fail "K61: budget gate misfired (zero=$K61_ZERO one=$K61_ONE two=$K61_TWO)"
fi
rm -rf "$K61_TMP"

# K62 — arch-scan-trace 3-event emit with workflow_type enrichment.
# Mirrors the council-trace observability pattern (K55) for arch scanner.
K62_TMP=$(mktemp -d)
mkdir -p "$K62_TMP/.devt/state"
echo '{}' > "$K62_TMP/.devt/config.json"
cat > "$K62_TMP/.devt/state/workflow.yaml" <<EOF_K62
active: true
workflow_id: test-wf-K62
workflow_type: arch_health_scan
phase: scan
first_created_at: "2026-06-05T10:00:00Z"
created_at: "2026-06-05T10:00:00Z"
EOF_K62
(cd "$K62_TMP" && node "$CLI" state arch-scan-trace scan-start --scan-id=K62 >/dev/null 2>&1) || true
(cd "$K62_TMP" && node "$CLI" state arch-scan-trace scan-complete --scan-id=K62 --finding-count=12 --baseline-delta=3 >/dev/null 2>&1) || true
(cd "$K62_TMP" && node "$CLI" state arch-scan-trace triage --scan-id=K62 --classification=fix-now >/dev/null 2>&1) || true
K62_COUNT=$(awk '/"source":"arch_scan"/' "$K62_TMP/.devt/state/gate-trace.jsonl" 2>/dev/null | wc -l | tr -d ' ')
K62_TYPE=$(awk '/"event":"scan-start"/{print}' "$K62_TMP/.devt/state/gate-trace.jsonl" 2>/dev/null | jq -r '.workflow_type' 2>/dev/null || echo "")
K62_DELTA=$(awk '/"event":"scan-complete"/{print}' "$K62_TMP/.devt/state/gate-trace.jsonl" 2>/dev/null | jq -r '."baseline-delta"' 2>/dev/null || echo "")
if [ "$K62_COUNT" = "3" ] && [ "$K62_TYPE" = "arch_health_scan" ] && [ "$K62_DELTA" = "3" ]; then
  pass "K62: arch-scan-trace 3-event emit with workflow_type + metadata preservation"
else
  fail "K62: arch-scan-trace misfired (count=$K62_COUNT type=$K62_TYPE delta=$K62_DELTA)"
fi
rm -rf "$K62_TMP"

# K63 — assert-arch-scan-fresh. Three states: missing report → ok:false |
# fresh report → ok:true warn:false | stale report → ok:true warn:true.
# Advisory-only gate by default (blocks only with --block flag).
K63_TMP=$(mktemp -d)
mkdir -p "$K63_TMP/.devt/state"
echo '{}' > "$K63_TMP/.devt/config.json"
K63_MISSING=$(cd "$K63_TMP" && node "$CLI" state assert-arch-scan-fresh 2>/dev/null | jq -r '.ok' 2>/dev/null || echo "")
echo "# Arch Scan Report" > "$K63_TMP/.devt/state/arch-scan-report.md"
K63_FRESH=$(cd "$K63_TMP" && node "$CLI" state assert-arch-scan-fresh --max-age-hours=24 2>/dev/null | jq -r '.ok, .warn' 2>/dev/null | tr '\n' '|')
# Set mtime back 48 hours
touch -t 202605231000 "$K63_TMP/.devt/state/arch-scan-report.md" 2>/dev/null || true
K63_STALE=$(cd "$K63_TMP" && node "$CLI" state assert-arch-scan-fresh --max-age-hours=24 2>/dev/null | jq -r '.ok, .warn' 2>/dev/null | tr '\n' '|')
if [ "$K63_MISSING" = "false" ] && [ "$K63_FRESH" = "true|false|" ] && [ "$K63_STALE" = "true|true|" ]; then
  pass "K63: assert-arch-scan-fresh 3-state (missing→fail | fresh→ok+no-warn | stale→ok+warn)"
else
  fail "K63: arch-scan-fresh misfired (missing=$K63_MISSING fresh=$K63_FRESH stale=$K63_STALE)"
fi
rm -rf "$K63_TMP"

# K64 — assert-wired (verification-patterns Level 3). Checks symbol has at
# least N references across the codebase. Uses git ls-files + node-native
# regex match. Three states: known symbol → ok | unknown symbol → block
# | injection attempt → reject.
K64_TMP=$(mktemp -d)
mkdir -p "$K64_TMP/.devt/state" "$K64_TMP/bin/modules"
echo '{}' > "$K64_TMP/.devt/config.json"
(cd "$K64_TMP" && git init -q 2>/dev/null) || true
cat > "$K64_TMP/bin/modules/io.cjs" <<'EOF_K64'
function findProjectRoot() { return process.cwd(); }
module.exports = { findProjectRoot };
EOF_K64
cat > "$K64_TMP/bin/modules/use.cjs" <<'EOF_K64_USE'
const { findProjectRoot } = require("./io.cjs");
console.log(findProjectRoot());
EOF_K64_USE
(cd "$K64_TMP" && git add -A && git -c user.email=ci@devt.local -c user.name=ci commit -qm fixture 2>/dev/null) || true
K64_KNOWN=$(cd "$K64_TMP" && node "$CLI" state assert-wired findProjectRoot --min-references=1 2>/dev/null | jq -r '.ok' 2>/dev/null || echo "")
K64_UNKNOWN=$(cd "$K64_TMP" && node "$CLI" state assert-wired NeverDefinedSymbol 2>/dev/null | jq -r '.ok' 2>/dev/null || echo "")
K64_INJECT=$(cd "$K64_TMP" && node "$CLI" state assert-wired 'foo; rm -rf' 2>/dev/null | jq -r '.ok' 2>/dev/null || echo "")
if [ "$K64_KNOWN" = "true" ] && [ "$K64_UNKNOWN" = "false" ] && [ "$K64_INJECT" = "false" ]; then
  pass "K64: assert-wired (known symbol → pass | unknown → block | injection → reject)"
else
  fail "K64: assert-wired misfired (known=$K64_KNOWN unknown=$K64_UNKNOWN inject=$K64_INJECT)"
fi
rm -rf "$K64_TMP"

# K65 — assert-scope-complete (verification-patterns Level 5). Extracts
# requirement bullets from spec.md, checks for keyword evidence in
# impl-summary.md. Three states: requirements + matching impl → ok |
# requirements + partial impl → block + missing list | no spec → inapplicable.
K65_TMP=$(mktemp -d)
mkdir -p "$K65_TMP/.devt/state"
echo '{}' > "$K65_TMP/.devt/config.json"
cat > "$K65_TMP/.devt/state/spec.md" <<'EOF_K65_SPEC'
# Spec
- Add user authentication middleware
- Configure rate limiting with redis backend
- Implement email notification on signup
EOF_K65_SPEC
cat > "$K65_TMP/.devt/state/impl-summary.md" <<'EOF_K65_IMPL_FULL'
# Impl Summary
Authentication middleware added in src/auth.py.
Rate limiting configured using redis at src/middleware.py.
Email notification implemented in src/notifications.py.
EOF_K65_IMPL_FULL
K65_COVERED=$(cd "$K65_TMP" && node "$CLI" state assert-scope-complete 2>/dev/null | jq -r '.ok' 2>/dev/null || echo "")
cat > "$K65_TMP/.devt/state/impl-summary.md" <<'EOF_K65_IMPL_PART'
# Impl Summary
Authentication middleware added in src/auth.py.
EOF_K65_IMPL_PART
K65_PARTIAL=$(cd "$K65_TMP" && node "$CLI" state assert-scope-complete 2>/dev/null | jq -r '.ok, .missing_count' 2>/dev/null | tr '\n' '|')
if [ "$K65_COVERED" = "true" ] && [ "$K65_PARTIAL" = "false|2|" ]; then
  pass "K65: assert-scope-complete (full coverage→ok | partial→block + 2 missing)"
else
  fail "K65: assert-scope-complete misfired (covered=$K65_COVERED partial=$K65_PARTIAL)"
fi
rm -rf "$K65_TMP"

# K66 — autoskill-rej-check. Calls memory.listRejectedKeywords and scans
# proposal text for case-insensitive substring matches. Two states:
# --list-only → returns keyword count | proposal text → ok or block.
K66_TMP=$(mktemp -d)
mkdir -p "$K66_TMP/.devt/state"
echo '{}' > "$K66_TMP/.devt/config.json"
K66_LIST=$(cd "$K66_TMP" && node "$CLI" state autoskill-rej-check --list-only 2>/dev/null | jq -r '.ok' 2>/dev/null || echo "")
K66_CLEAN=$(cd "$K66_TMP" && node "$CLI" state autoskill-rej-check "Add support for new feature" 2>/dev/null | jq -r '.ok' 2>/dev/null || echo "")
K66_EMPTY=$(cd "$K66_TMP" && node "$CLI" state autoskill-rej-check 2>/dev/null | jq -r '.ok' 2>/dev/null || echo "")
if [ "$K66_LIST" = "true" ] && [ "$K66_CLEAN" = "true" ] && [ "$K66_EMPTY" = "false" ]; then
  pass "K66: autoskill-rej-check (--list-only→ok | clean text→ok | empty arg→reject)"
else
  fail "K66: autoskill-rej-check misfired (list=$K66_LIST clean=$K66_CLEAN empty=$K66_EMPTY)"
fi
rm -rf "$K66_TMP"

# K67 — assert-graphify-source-tagged. Hard Invariant #2 enforcement.
# Three states: file without source → block | file with JSON source → ok
# | file with prose source → ok.
K67_TMP=$(mktemp -d)
mkdir -p "$K67_TMP/.devt/state"
echo '{}' > "$K67_TMP/.devt/config.json"
echo "# Output with no tag" > "$K67_TMP/no-tag.md"
echo '{"source":"graphify","results":[]}' > "$K67_TMP/json-tag.json"
echo "Found things — source: grep" > "$K67_TMP/prose-tag.md"
K67_MISSING=$(cd "$K67_TMP" && node "$CLI" state assert-graphify-source-tagged no-tag.md 2>/dev/null | jq -r '.ok' 2>/dev/null || echo "")
K67_JSON=$(cd "$K67_TMP" && node "$CLI" state assert-graphify-source-tagged json-tag.json 2>/dev/null | jq -r '.ok, .source' 2>/dev/null | tr '\n' '|')
K67_PROSE=$(cd "$K67_TMP" && node "$CLI" state assert-graphify-source-tagged prose-tag.md 2>/dev/null | jq -r '.ok, .source' 2>/dev/null | tr '\n' '|')
if [ "$K67_MISSING" = "false" ] && [ "$K67_JSON" = "true|graphify|" ] && [ "$K67_PROSE" = "true|grep|" ]; then
  pass "K67: assert-graphify-source-tagged (missing→block | JSON→ok | prose→ok)"
else
  fail "K67: graphify-source-tagged misfired (missing=$K67_MISSING json=$K67_JSON prose=$K67_PROSE)"
fi
rm -rf "$K67_TMP"

# K68 — graphify-fallback-trace observability. Four triggers + none emit
# records to gate-trace.jsonl with workflow_type enrichment.
K68_TMP=$(mktemp -d)
mkdir -p "$K68_TMP/.devt/state"
echo '{}' > "$K68_TMP/.devt/config.json"
cat > "$K68_TMP/.devt/state/workflow.yaml" <<EOF_K68
active: true
workflow_id: test-K68
workflow_type: dev
phase: implement
first_created_at: "2026-06-05T10:00:00Z"
created_at: "2026-06-05T10:00:00Z"
EOF_K68
for t in empty error not_setup below_threshold; do
  (cd "$K68_TMP" && node "$CLI" state graphify-fallback-trace $t --skill=codebase-scan >/dev/null 2>&1) || true
done
K68_COUNT=$(awk '/"source":"graphify_fallback"/' "$K68_TMP/.devt/state/gate-trace.jsonl" 2>/dev/null | wc -l | tr -d ' ')
K68_TYPE=$(awk '/"trigger":"empty"/{print}' "$K68_TMP/.devt/state/gate-trace.jsonl" 2>/dev/null | jq -r '.workflow_type' 2>/dev/null || echo "")
if [ "$K68_COUNT" = "4" ] && [ "$K68_TYPE" = "dev" ]; then
  pass "K68: graphify-fallback-trace 4-trigger emit with workflow_type enrichment"
else
  fail "K68: graphify-fallback-trace misfired (count=$K68_COUNT type=$K68_TYPE)"
fi
rm -rf "$K68_TMP"

# K69 — setup --template rust. Verifies the rust template is registered in
# AVAILABLE_TEMPLATES and `setup --template rust` produces the 6 canonical
# rules files at .devt/rules/. Mirrors what other templates ship; without
# this gate a typo in setup.cjs::AVAILABLE_TEMPLATES would only surface to
# end users when they ran setup.
K69_TMP=$(mktemp -d)
(cd "$K69_TMP" && node "$CLI" setup --template rust --mode create >/dev/null 2>&1) || true
K69_FILES=0
for f in coding-standards.md architecture.md quality-gates.md golden-rules.md review-checklist.md testing-patterns.md; do
  if [ -s "$K69_TMP/.devt/rules/$f" ]; then
    K69_FILES=$((K69_FILES + 1))
  fi
done
K69_CANON=0
if [ -s "$K69_TMP/.devt/rules/canonical-entities.yaml" ]; then
  K69_CANON=1
fi
if [ "$K69_FILES" = "6" ] && [ "$K69_CANON" = "1" ]; then
  pass "K69: setup --template rust scaffolds 6 .md files + canonical-entities.yaml"
else
  fail "K69: setup --template rust missing files (md=$K69_FILES/6 canon=$K69_CANON)"
fi
rm -rf "$K69_TMP"

# K70 — template-shape consistency. Walks every template registered in
# bin/modules/setup.cjs::AVAILABLE_TEMPLATES and asserts each ships the 9
# baseline files (8 .md at top level + patterns/common-smells.md). Closes
# the structural gap that K69 (and earlier per-template gates) leave open:
# a new template can silently omit standard files. The baseline is what the
# 'blank' template ships, since blank IS the canonical empty shape.
# Templates may ship MORE than the baseline (e.g. python-fastapi's hurl-*
# files, rust's canonical-entities.yaml) — extra files are fine. The gate
# only flags missing baseline files.
TEMPLATES_ROOT="$(dirname "$CLI")/../templates"
K70_BASELINE="architecture.md coding-standards.md documentation.md git-workflow.md golden-rules.md quality-gates.md review-checklist.md testing-patterns.md patterns/common-smells.md"
# Read AVAILABLE_TEMPLATES from setup.cjs source (not via Node — keep gate
# self-contained + fail-fast if the structure changes).
K70_TEMPLATES=$(node -e "process.stdout.write(require('$(dirname "$CLI")/modules/setup.cjs').AVAILABLE_TEMPLATES.join(' '))" 2>/dev/null)
K70_MISSING_TOTAL=0
K70_MISSING_REPORT=""
for tpl in $K70_TEMPLATES; do
  for f in $K70_BASELINE; do
    if [ ! -s "$TEMPLATES_ROOT/$tpl/$f" ]; then
      K70_MISSING_TOTAL=$((K70_MISSING_TOTAL + 1))
      K70_MISSING_REPORT="$K70_MISSING_REPORT $tpl/$f"
    fi
  done
done
if [ "$K70_MISSING_TOTAL" = "0" ]; then
  pass "K70: template-shape consistency — all AVAILABLE_TEMPLATES ship the 9-file baseline"
else
  fail "K70: template-shape drift — $K70_MISSING_TOTAL missing:$K70_MISSING_REPORT"
fi

# K71 — dispatch envelope drift. After v0.76.0, every dispatch region in
# workflows/*.md must match its envelope template (.tmpl.md). The drift
# tracker lives in `dispatch.cjs compile --check`: it walks every
# BEGIN dispatch:<agent>:<wf> marker and compares the rendered body against
# the committed body. Zero drift = committed dispatches reflect their
# templates + io-contracts.yaml. Non-zero drift = a template was edited
# but the workflows weren't re-rendered (or vice versa). Closes the gap
# that v0.75.x exposed: programmer/code-reviewer rendered envelopes silently
# diverged from io-contracts.yaml's graph_impact_md declaration.
K71_OUT=$(node "$CLI" dispatch compile --check 2>&1)
K71_DRIFT=$(echo "$K71_OUT" | jq -r '.drift | length' 2>/dev/null)
if [ "$K71_DRIFT" = "0" ]; then
  pass "K71: dispatch envelope drift — zero workflows out of sync with their templates"
else
  K71_FILES=$(echo "$K71_OUT" | jq -r '.drift[] | "\(.file):\(.agent):\(.workflow_id)"' 2>/dev/null | tr '\n' ' ')
  fail "K71: $K71_DRIFT dispatch region(s) drifted — run \`node bin/devt-tools.cjs dispatch compile --write\`. Drifted: $K71_FILES"
fi

# K71b — render idempotence. `dispatch compile --check` must be a pure
# function of (templates, io-contracts.yaml, workflow source files): two
# consecutive runs must produce byte-identical output. Catches mtime/
# timestamp/random-id leaks into the substitution table that would
# silently break prompt-cache hit rates. Borrowed from headroom's
# CacheAligner concept (byte-stable prefixes → KV cache hits). Concept
# only — no headroom code dependency.
K71B_OUT2=$(node "$CLI" dispatch compile --check 2>&1)
if [ "$K71_OUT" = "$K71B_OUT2" ]; then
  pass "K71b: dispatch compile --check is idempotent (two consecutive renders byte-identical)"
else
  fail "K71b: dispatch render is NOT byte-stable across consecutive calls — substitution table likely leaks mtime/timestamp/random into output (breaks KV cache hits)"
fi

# K72 (v0.77.0 B1): lane-suggestions archetype classifier sub-classifies the
# ungrouped bucket by file-extension when files have no graph community.
# Field 2026-06-07 calibration: 24 of 42 files (57%) landed in one
# "ungrouped" mega-bucket; archetype classifier splits them into docs/tests/
# config/ungrouped so the orchestrator gets coherent fallback lanes.
# Mixed-input fixture: 1 covered file + 1 .md + 1 test path + 1 sql.
K72_TMP=$(mktemp -d)
mkdir -p "$K72_TMP/.devt" "$K72_TMP/graphify-out"
echo '{"graphify":{"enabled":true}}' > "$K72_TMP/.devt/config.json"
node -e "
const fs = require('fs');
const g = {
  directed: true, multigraph: false, graph: {built_at_commit: 'deadbeef'},
  nodes: [{id: 'a1', label: 'AuthHelper', source_file: 'src/auth.py', community: 1}],
  links: []
};
fs.writeFileSync('$K72_TMP/graphify-out/graph.json', JSON.stringify(g));
"
K72_OUT=$(cd "$K72_TMP" && node "$ROOT/bin/devt-tools.cjs" graphify lane-suggestions \
  src/auth.py docs/README.md tests/test_auth.py migrations/001.sql 2>/dev/null)
K72_ARCH=$(echo "$K72_OUT" | node -e "let s='';process.stdin.on('data',d=>s+=d);process.stdin.on('end',()=>{try{const j=JSON.parse(s);const archs=(j.groups||[]).map(g=>g.archetype).filter(Boolean).sort().join(',');console.log(archs);}catch(e){console.log('err');}})")
if [ "$K72_ARCH" = "docs,tests" ]; then
  pass "K72: lane-suggestions archetype classifier splits ungrouped by extension (docs + tests)"
else
  fail "K72: archetype classifier mismatch — expected 'docs,tests', got '$K72_ARCH'"
fi
rm -rf "$K72_TMP"

# K73 (v0.77.0 A1): dispatch render-filled inlines graph-impact.md content
# via the {graph_impact_content} placeholder. v0.76.0 shipped a Read-prompt
# wrapped in <graph_impact>; field calibration 2026-06-07 confirmed the
# data reached sub-agents only via Read, not via inlining. loadGraphImpact()
# + dispatch substitution closes the gap. Test verifies present + absent
# branches.
K73_TMP=$(mktemp -d)
cd "$K73_TMP"
node "$CLI" init workflow "K73 inlining test" >/dev/null 2>&1
# absent: rendered envelope shows the (no graph-impact.md available — ...) notice
K73_ABSENT=$(node "$CLI" dispatch render-filled programmer:dev 2>/dev/null | grep -c "no graph-impact.md available" || true)
# present: write graph-impact.md and confirm content inlines verbatim
echo "## SENTINEL_K73_MARKER" > .devt/state/graph-impact.md
K73_PRESENT=$(node "$CLI" dispatch render-filled programmer:dev 2>/dev/null | grep -c "SENTINEL_K73_MARKER" || true)
cd "$ROOT"
rm -rf "$K73_TMP"
if [ "$K73_ABSENT" -ge 1 ] && [ "$K73_PRESENT" -ge 1 ]; then
  pass "K73: dispatch render-filled inlines graph-impact.md content (absent → notice, present → verbatim)"
else
  fail "K73: graph_impact inlining broken (absent_notice=$K73_ABSENT, present_marker=$K73_PRESENT)"
fi

# K74: structural-drift validator (caveman validate.py port). checkAgentOutput's
# --structural --baseline=<path> flag compares the final artifact against the
# stub-first sentinel snapshot. Closes the gap stub/word-count detection misses:
# section deletion, code-fence mangling, lost URLs/inline-codes between baseline
# and final write. 4 fixtures: superset stub→complete ok, superset stub→dropped-
# section fail, equality mangled-code-block fail, equality identical ok.
K74_TMP=$(mktemp -d)
mkdir -p "$K74_TMP/.devt/state"
# Fixture 1: superset stub → complete (sections added, none dropped) → ok
printf "## Status\n\n(stub)\n\n## Findings\n\n(stub)\n" > "$K74_TMP/.devt/state/k74-stub.md"
printf "## Status\n\nDone with the work as planned across the full implementation scope which contains a sufficient prose count for the substance threshold to clear without flagging the artifact as a stub during the check phase.\n\n## Findings\n\n- bug A discovered during the deep review pass against the integration suite\n- bug B reproduced in the smoke harness with the expected sentinel markers\n\n## Recommendations\n\nFix bug A first then schedule bug B for the next release window.\n" > "$K74_TMP/.devt/state/k74-complete.md"
K74_T1=$(cd "$K74_TMP" && node "$CLI" state check-agent-output .devt/state/k74-complete.md --structural --baseline=.devt/state/k74-stub.md 2>/dev/null | jq -r '.structural_drift.ok' 2>/dev/null)
# Fixture 2: superset stub → dropped section (Status missing) → fail
printf "## Findings\n\n- only bug A here, the Status section dropped during the final write to test detection of section deletion against the baseline snapshot with enough words to clear stub.\n" > "$K74_TMP/.devt/state/k74-dropped.md"
K74_T2=$(cd "$K74_TMP" && node "$CLI" state check-agent-output .devt/state/k74-dropped.md --structural --baseline=.devt/state/k74-stub.md 2>/dev/null | jq -r '.structural_drift.errors[0]' 2>/dev/null)
# Fixture 3: equality mangled code block → fail
printf "## A\n\n\`\`\`js\nconst x = 1;\n\`\`\`\n\nbody text here with enough words to clear the substance threshold for the smoke gate fixture without flagging.\n" > "$K74_TMP/.devt/state/k74-orig.md"
printf "## A\n\n\`\`\`js\nconst x = 2;\n\`\`\`\n\nbody text here with enough words to clear the substance threshold for the smoke gate fixture without flagging.\n" > "$K74_TMP/.devt/state/k74-mangled.md"
K74_T3=$(cd "$K74_TMP" && node "$CLI" state check-agent-output .devt/state/k74-mangled.md --structural --baseline=.devt/state/k74-orig.md --mode=equality 2>/dev/null | jq -r '.structural_drift.ok' 2>/dev/null)
# Fixture 4: equality identical → ok
cp "$K74_TMP/.devt/state/k74-orig.md" "$K74_TMP/.devt/state/k74-identical.md"
K74_T4=$(cd "$K74_TMP" && node "$CLI" state check-agent-output .devt/state/k74-identical.md --structural --baseline=.devt/state/k74-orig.md --mode=equality 2>/dev/null | jq -r '.structural_drift.ok' 2>/dev/null)
rm -rf "$K74_TMP"
if [ "$K74_T1" = "true" ] && [ "$K74_T2" = "Section dropped: \"Status\" (level 2)" ] && [ "$K74_T3" = "false" ] && [ "$K74_T4" = "true" ]; then
  pass "K74: structural-drift validator (superset stub→complete ok, stub→dropped fail, equality mangled fail, equality identical ok)"
else
  fail "K74: structural validator mismatch — T1=$K74_T1 (want true), T2='$K74_T2' (want section-dropped), T3=$K74_T3 (want false), T4=$K74_T4 (want true)"
fi

# K76: graphify sensitive-path denylist (caveman is_sensitive_path port).
# Refuses CLI file args matching credential/key/secret patterns at the 4
# file-accepting subcommands (lane-suggestions, check-large-files,
# check-symbol-godnodes, symbols-in-files). Closes the disclosure path
# where a .env or ~/.ssh/id_rsa accidentally passed to graphify would
# flow into MCP queries. Round-trip: 3 sensitive-path fixtures must
# return exit 2 + clean path returns exit 0.
K76_TMP=$(mktemp -d)
mkdir -p "$K76_TMP/.devt" "$K76_TMP/graphify-out"
echo '{"graphify":{"enabled":true}}' > "$K76_TMP/.devt/config.json"
echo '{"directed":true,"multigraph":false,"graph":{"built_at_commit":"x"},"nodes":[],"links":[]}' > "$K76_TMP/graphify-out/graph.json"
# Fixture 1: credentials.json → refuse. Wrapped in `if` so `set -e` doesn't
# trip on the expected exit 2 from the denylist.
if (cd "$K76_TMP" && node "$CLI" graphify lane-suggestions src/auth.py credentials.json >/dev/null 2>&1); then K76_T1=0; else K76_T1=$?; fi
if (cd "$K76_TMP" && node "$CLI" graphify symbols-in-files /tmp/fake/.ssh/id_rsa >/dev/null 2>&1); then K76_T2=0; else K76_T2=$?; fi
if (cd "$K76_TMP" && node "$CLI" graphify check-large-files my-api-key.env >/dev/null 2>&1); then K76_T3=0; else K76_T3=$?; fi
if (cd "$K76_TMP" && node "$CLI" graphify lane-suggestions src/auth.py docs/README.md >/dev/null 2>&1); then K76_T4=0; else K76_T4=$?; fi
rm -rf "$K76_TMP"
if [ "$K76_T1" = "2" ] && [ "$K76_T2" = "2" ] && [ "$K76_T3" = "2" ] && [ "$K76_T4" = "0" ]; then
  pass "K76: graphify sensitive-path denylist (credentials/ssh/secret-token refused, clean path ok)"
else
  fail "K76: graphify denylist mismatch — credentials=$K76_T1 (want 2), ssh=$K76_T2 (want 2), secret=$K76_T3 (want 2), clean=$K76_T4 (want 0)"
fi

# K77: static-compress round-trip (caveman-shrink port). Compresses prose
# while preserving code blocks, URLs, paths, identifiers byte-equal;
# validates with structural-drift validator; backs up to .original.md;
# --restore returns byte-identical original. Mode 'off' default refuses;
# sensitive filename refused; empty file refused; structural drift triggers
# automatic revert (no compressed-with-drift file lands).
K77_TMP=$(mktemp -d)
mkdir -p "$K77_TMP/.devt/state"
cat > "$K77_TMP/sample.md" <<'EOF_K77'
# Test File

Please just check the docs at https://example.com/foo for the API.
Really important that you preserve the `inline_code` and /path/to/file.txt references.

## Section A
Just basic content with some hedging maybe.
EOF_K77
ORIG_BYTES=$(wc -c < "$K77_TMP/sample.md" | tr -d ' ')
# Fixture A: mode='off' explicit → refused with feature-disabled message.
# (v0.88.0 flipped DEFAULTS.static_compress.mode to 'on'; this fixture
# pins mode='off' explicitly to verify the refusal path still works for
# users who opt out.) Node intentionally exits 1 on refusal; `|| true`
# swallows it so set -o pipefail doesn't crash the smoke script.
echo '{"static_compress":{"mode":"off"}}' > "$K77_TMP/.devt/config.json"
K77_A=$(cd "$K77_TMP" && node "$CLI" static-compress sample.md 2>/dev/null | jq -r '.reason // ""' 2>/dev/null | grep -c "static_compress.mode='off'" || true)
# Fixture B: mode='on' → compresses, writes backup, code/URL/path preserved
echo '{"static_compress":{"mode":"on"}}' > "$K77_TMP/.devt/config.json"
K77_B_JSON=$(cd "$K77_TMP" && node "$CLI" static-compress sample.md 2>/dev/null)
K77_B_OK=$(echo "$K77_B_JSON" | jq -r '.ok' 2>/dev/null)
K77_B_HAS_URL=$(grep -c "https://example.com/foo" "$K77_TMP/sample.md" 2>/dev/null || true)
K77_B_HAS_PATH=$(grep -c "/path/to/file.txt" "$K77_TMP/sample.md" 2>/dev/null || true)
K77_B_HAS_CODE=$(grep -c '`inline_code`' "$K77_TMP/sample.md" 2>/dev/null || true)
K77_B_HAS_BACKUP=$(test -f "$K77_TMP/sample.original.md" && echo "yes" || echo "no")
# Fixture C: --restore returns byte-identical original
(cd "$K77_TMP" && node "$CLI" static-compress --restore sample.md >/dev/null 2>&1) || true
RESTORED_BYTES=$(wc -c < "$K77_TMP/sample.md" | tr -d ' ')
# Fixture D: sensitive filename refused
cp "$K77_TMP/sample.md" "$K77_TMP/credentials.md"
if (cd "$K77_TMP" && node "$CLI" static-compress credentials.md >/dev/null 2>&1); then K77_D=0; else K77_D=$?; fi
# Fixture E: empty file refused
: > "$K77_TMP/empty.md"
K77_E_REASON=$(cd "$K77_TMP" && node "$CLI" static-compress empty.md 2>/dev/null | jq -r '.reason // ""' 2>/dev/null | grep -c "empty" || true)
# Fixture F (drift-detected revert) removed in v0.88.0 alongside the
# headroom shellout. The drift-revert behavior is already locked by:
#   - K74 (structural-drift validator, 4 fixtures)
#   - K85 (prose-shrink correctness, 4 fixtures + 3 regression guards)
# Keeping a separate Fixture F here was redundant once the compressor
# became single-engine (regex only).
rm -rf "$K77_TMP"
if [ "$K77_A" = "1" ] && [ "$K77_B_OK" = "true" ] && [ "$K77_B_HAS_URL" -ge "1" ] && [ "$K77_B_HAS_PATH" -ge "1" ] && [ "$K77_B_HAS_CODE" -ge "1" ] && [ "$K77_B_HAS_BACKUP" = "yes" ] && [ "$RESTORED_BYTES" = "$ORIG_BYTES" ] && [ "$K77_D" = "1" ] && [ "$K77_E_REASON" = "1" ]; then
  pass "K77: static-compress 5-fixture round-trip (off-refused, compress preserves bytes + backup, restore byte-equal, sensitive refused, empty refused)"
else
  fail "K77: static-compress mismatch — A=$K77_A B_ok=$K77_B_OK B_url=$K77_B_HAS_URL B_path=$K77_B_HAS_PATH B_code=$K77_B_HAS_CODE B_backup=$K77_B_HAS_BACKUP restored=$RESTORED_BYTES/orig=$ORIG_BYTES D=$K77_D E=$K77_E_REASON"
fi

# K78: convention-enforcement — banned devt-internal version markers
# (vX.Y.Z literals) must not appear in code surfaces. Provenance belongs
# in CHANGELOG and git history. Scope: bin/modules/, hooks/, agents/,
# workflows/, templates/, guardrails/. Exempt: update.cjs:185 (the
# CHANGELOG-header parser regex), skills/ (Option A/B template text used
# for user-presentation prescriptions).
K78_HITS=$(grep -rEn '\bv[0-9]+\.[0-9]+\.[0-9]+\b' \
  "$ROOT/bin/modules/" \
  "$ROOT/hooks/" \
  "$ROOT/agents/" \
  "$ROOT/workflows/" \
  "$ROOT/templates/" \
  "$ROOT/guardrails/" \
  2>/dev/null \
  | grep -v 'update.cjs:.*Match version headers' \
  | grep -v '/templates/[^/]*/documentation\.md:' \
  || true)
if [ -z "$K78_HITS" ]; then
  pass "K78: no banned vX.Y.Z markers in code surfaces (CHANGELOG-parser regex exempt)"
else
  K78_COUNT=$(echo "$K78_HITS" | wc -l | tr -d ' ')
  fail "K78: $K78_COUNT version-marker violation(s) — must move to CHANGELOG. Hits:\n$K78_HITS"
fi

# K79: end-to-end synthetic drift recovery — closes the gap between K74
# (detector only) and the production recovery loop. Validates that a
# substantive artifact missing one or more expected_sections triggers the
# targeted-fix branch with the right drift list AND that the fix-envelope
# template exists with the {drift_errors} placeholder ready to substitute.
# Field 2026-06-09: zero structural-drift fires in 30+ days of
# production runs — synthetic fixture is the only way to validate the
# recovery path without inventing field data that doesn't exist.
K79_TMP=$(mktemp -d)
mkdir -p "$K79_TMP/.devt/state"
echo '{"validator":{"structural_mode":"warn"}}' > "$K79_TMP/.devt/config.json"
# Substantive impl-summary.md missing 2 of 5 expected_sections
# (Key Decisions + Provenance) — exercises the structural-drift branch
# rather than the stub / rate-limit / investigate branches.
cat > "$K79_TMP/.devt/state/impl-summary.md" <<'EOF_K79'
## Task

Implemented K79 synthetic drift recovery fixture. The fixture writes substantive impl-summary.md missing two of five expected_sections so structural validator returns targeted-fix instead of investigate. Word count clears 50-word substance threshold.

## Files Modified

- scripts/smoke-test.sh — added K79 block exercising recover-partial-impl

## Quality Gate Results

Smoke: retained after K79 added. Locking: 3/3 retained. K74 unchanged.
EOF_K79
K79_OUT=$(cd "$K79_TMP" && node "$CLI" state recover-partial-impl programmer 2>/dev/null)
K79_ACTION=$(echo "$K79_OUT" | jq -r '.suggested_action // ""' 2>/dev/null)
K79_MISSING=$(echo "$K79_OUT" | jq -r '.drift.missing_sections | length' 2>/dev/null)
K79_TMPL_PATH="$ROOT/templates/dispatch/envelopes/programmer-fix.tmpl.md"
if [ -f "$K79_TMPL_PATH" ]; then
  K79_TMPL_HAS_PLACEHOLDER=$(grep -c "{drift_errors}" "$K79_TMPL_PATH" 2>/dev/null || true)
else
  K79_TMPL_HAS_PLACEHOLDER=0
fi
rm -rf "$K79_TMP"
if [ "$K79_ACTION" = "targeted-fix" ] && [ "$K79_MISSING" = "2" ] && [ "$K79_TMPL_HAS_PLACEHOLDER" -ge "1" ]; then
  pass "K79: E2E synthetic drift recovery (detector fires → targeted-fix, 2 missing sections, fix template carries {drift_errors} placeholder)"
else
  fail "K79: drift recovery mismatch — action='$K79_ACTION' (want targeted-fix), missing=$K79_MISSING (want 2), tmpl_placeholder=$K79_TMPL_HAS_PLACEHOLDER (want ≥1)"
fi

# K80: claude-mem detection uses the plugin registry, not `command -v`.
# Bug: claude-mem v13+ is distributed as a Claude Code plugin (no CLI
# binary on PATH), so the prior `command -v claude-mem` check reported
# "not installed" for actually-installed users. The fix reads
# ~/.claude/plugins/installed_plugins.json::plugins and matches any key
# prefixed `claude-mem@<marketplace>`. K80 freezes the contract: detection
# returns yes when registry contains the key, no when registry is missing
# / empty / contains unrelated plugins.
K80_TMP=$(mktemp -d)
# Helper — runs the detection bash against an arbitrary registry path.
k80_detect() {
  local registry="$1"
  if [ -f "$registry" ] && jq -e '.plugins | keys | any(startswith("claude-mem@"))' "$registry" >/dev/null 2>&1; then
    echo yes
  else
    echo no
  fi
}
# Fixture 1: registry with claude-mem@thedotmack → yes
cat > "$K80_TMP/installed-yes.json" <<'EOF_K80'
{"plugins":{"claude-mem@thedotmack":{"installed_at":"2026-01-01T00:00:00Z"},"other-plugin@official":{}},"version":1}
EOF_K80
K80_T1=$(k80_detect "$K80_TMP/installed-yes.json")
# Fixture 2: registry without claude-mem → no
cat > "$K80_TMP/installed-no.json" <<'EOF_K80'
{"plugins":{"other-plugin@official":{},"unrelated@source":{}},"version":1}
EOF_K80
K80_T2=$(k80_detect "$K80_TMP/installed-no.json")
# Fixture 3: registry file missing → no (graceful default)
K80_T3=$(k80_detect "$K80_TMP/does-not-exist.json")
# Fixture 4: empty registry object → no (graceful)
echo '{}' > "$K80_TMP/installed-empty.json"
K80_T4=$(k80_detect "$K80_TMP/installed-empty.json")
# Fixture 5: marketplace fork — claude-mem@some-fork still matches
cat > "$K80_TMP/installed-fork.json" <<'EOF_K80'
{"plugins":{"claude-mem@some-fork":{}},"version":1}
EOF_K80
K80_T5=$(k80_detect "$K80_TMP/installed-fork.json")
# Fixture 6: project-init.md still uses the registry-based check (regression guard)
K80_PROJECT_INIT_HAS_FIX=$(grep -c 'CLAUDE_MEM_REGISTRY=' "$ROOT/workflows/project-init.md" 2>/dev/null || true)
K80_PROJECT_INIT_HAS_OLD=$(grep -c 'command -v claude-mem >/dev/null' "$ROOT/workflows/project-init.md" 2>/dev/null || true)
rm -rf "$K80_TMP"
if [ "$K80_T1" = "yes" ] && [ "$K80_T2" = "no" ] && [ "$K80_T3" = "no" ] && [ "$K80_T4" = "no" ] && [ "$K80_T5" = "yes" ] && [ "$K80_PROJECT_INIT_HAS_FIX" -ge "1" ] && [ "$K80_PROJECT_INIT_HAS_OLD" = "0" ]; then
  pass "K80: claude-mem detection via plugin registry (installed→yes, absent→no, missing/empty→no, fork→yes, project-init.md uses fixed check)"
else
  fail "K80: detection mismatch — T1=$K80_T1 (want yes), T2=$K80_T2 (want no), T3=$K80_T3 (want no), T4=$K80_T4 (want no), T5=$K80_T5 (want yes), project-init-fix=$K80_PROJECT_INIT_HAS_FIX (want ≥1), project-init-old=$K80_PROJECT_INIT_HAS_OLD (want 0)"
fi

# K81: static-compress --all bulk mode + adoption loop wiring.
# Validates: walker scans only project-local paths (NOT plugin's own
# guardrails/), idempotent re-runs skip via backup-existence, safety
# refusals (identical-output) categorize as skipped not errored,
# project-init.md has the prompt_static_compress_setup step, and
# health.cjs aggregates savings from static-compress.jsonl into the
# compression.savings block. Closes the adoption-loop contract between
# init-time consent → --all bulk run → health-time ROI surface.
K81_TMP=$(mktemp -d)
mkdir -p "$K81_TMP/.devt/rules"
echo '{"static_compress":{"mode":"on"}}' > "$K81_TMP/.devt/config.json"
cat > "$K81_TMP/.devt/rules/rule-a.md" <<'EOF_K81'
# Rule A

Verbose prose with multiple sentences. URL https://example.com/foo and path /var/log/test.log. Inline `code_var` and CONST_CASE_THING. We need enough prose volume for the regex compressor to find something to drop without destabilizing structure.

## Section

More prose. The compressor preserves the structural elements (headings, code, URLs, paths, identifiers) byte-equal while shrinking the connective prose.
EOF_K81
cat > "$K81_TMP/.devt/rules/rule-b.md" <<'EOF_K81'
# Rule B

A second rule file. Has `func_call()` and version 1.2.3 to test preservation. Plus URL https://docs.example.com.

## Details

Body content here. Enough volume for compressor.
EOF_K81
# Snapshot plugin guardrails mtimes BEFORE the run — they must be untouched.
K81_PLUGIN_GUARDRAILS_BEFORE=$(find "$ROOT/guardrails" -name '*.md' -exec sha256sum {} \; 2>/dev/null | sort | sha256sum | cut -d' ' -f1)
K81_RUN1=$(cd "$K81_TMP" && node "$CLI" static-compress --all 2>/dev/null)
K81_R1_OK=$(echo "$K81_RUN1" | jq -r '.ok // false')
K81_R1_TOTAL=$(echo "$K81_RUN1" | jq -r '.total_files // 0')
K81_R1_COMPRESSED=$(echo "$K81_RUN1" | jq -r '.compressed | length')
K81_R1_ERRORS=$(echo "$K81_RUN1" | jq -r '.errors | length')
# Plugin guardrails must not have been touched.
K81_PLUGIN_GUARDRAILS_AFTER=$(find "$ROOT/guardrails" -name '*.md' -exec sha256sum {} \; 2>/dev/null | sort | sha256sum | cut -d' ' -f1)
K81_PLUGIN_UNCHANGED=$([ "$K81_PLUGIN_GUARDRAILS_BEFORE" = "$K81_PLUGIN_GUARDRAILS_AFTER" ] && echo yes || echo no)
# Idempotent re-run — second invocation must skip everything compressed.
K81_RUN2=$(cd "$K81_TMP" && node "$CLI" static-compress --all 2>/dev/null)
K81_R2_COMPRESSED=$(echo "$K81_RUN2" | jq -r '.compressed | length')
K81_R2_SKIPPED=$(echo "$K81_RUN2" | jq -r '.skipped_already_done | length')
# Health savings block must aggregate the compress events.
K81_HEALTH_SAVINGS=$(cd "$K81_TMP" && node "$CLI" health 2>/dev/null | jq -r '.compression.savings.files_compressed // 0')
# Workflow step must exist (regression guard).
K81_WORKFLOW_HAS_STEP=$(grep -c 'name="prompt_static_compress_setup"' "$ROOT/workflows/project-init.md" 2>/dev/null || true)
rm -rf "$K81_TMP"
if [ "$K81_R1_OK" = "true" ] \
   && [ "$K81_R1_TOTAL" = "2" ] \
   && [ "$K81_R1_COMPRESSED" -ge "1" ] \
   && [ "$K81_R1_ERRORS" = "0" ] \
   && [ "$K81_PLUGIN_UNCHANGED" = "yes" ] \
   && [ "$K81_R2_COMPRESSED" = "0" ] \
   && [ "$K81_R2_SKIPPED" -ge "1" ] \
   && [ "$K81_HEALTH_SAVINGS" -ge "1" ] \
   && [ "$K81_WORKFLOW_HAS_STEP" -ge "1" ]; then
  pass "K81: static-compress --all bulk + adoption loop (plugin guardrails untouched, idempotent re-run, health surfaces savings, init step present)"
else
  fail "K81: bulk-compress mismatch — r1_ok=$K81_R1_OK r1_total=$K81_R1_TOTAL r1_compressed=$K81_R1_COMPRESSED r1_errors=$K81_R1_ERRORS plugin_unchanged=$K81_PLUGIN_UNCHANGED r2_compressed=$K81_R2_COMPRESSED r2_skipped=$K81_R2_SKIPPED health_savings=$K81_HEALTH_SAVINGS workflow_step=$K81_WORKFLOW_HAS_STEP"
fi

# K82: prior-output sidecar inline injection.
# Validates the Sidecar-Driven Handoff contract: when prior agents'
# JSON sidecars exist in .devt/state/, the rendered verifier envelope
# carries them in a <prior_outputs> block (eliminates Read tool round-
# trips for structured handoff data on every consuming dispatch). When
# sidecars are absent, the block degrades to empty (graceful — no error).
# Verifier excludes its own sidecar (verification.json) so a stale prior-
# phase verdict never re-injects.
K82_TMP=$(mktemp -d)
mkdir -p "$K82_TMP/.devt/state"
echo '{}' > "$K82_TMP/.devt/config.json"
echo '{"workflow_id":"dev","active":true,"workflow_type":"dev","phase":"verify","task":"k82 fixture"}' > "$K82_TMP/.devt/state/workflow.yaml"
echo '{"status":"DONE","verdict":"PASS","agent":"programmer"}' > "$K82_TMP/.devt/state/impl-summary.json"
echo '{"status":"DONE","verdict":"PASS","agent":"tester"}' > "$K82_TMP/.devt/state/test-summary.json"
echo '{"status":"VERIFIED","verdict":"satisfied","agent":"verifier"}' > "$K82_TMP/.devt/state/verification.json"
# Render with sidecars present — verifier should see programmer + tester
# (review.json absent, verification.json filtered as own-sidecar).
K82_OUT_WITH=$(cd "$K82_TMP" && node "$CLI" dispatch render-filled verifier:dev 2>/dev/null)
K82_HAS_PROGRAMMER=$(echo "$K82_OUT_WITH" | grep -c '<programmer_sidecar>' || true)
K82_HAS_TESTER=$(echo "$K82_OUT_WITH" | grep -c '<tester_sidecar>' || true)
K82_HAS_OWN=$(echo "$K82_OUT_WITH" | grep -c '<verifier_sidecar>' || true)
K82_HAS_NOTE=$(echo "$K82_OUT_WITH" | grep -c '<prior_outputs_note>' || true)
# Render without sidecars — block must degrade gracefully (no <prior_outputs>).
rm -f "$K82_TMP/.devt/state/impl-summary.json" "$K82_TMP/.devt/state/test-summary.json" "$K82_TMP/.devt/state/verification.json"
K82_OUT_EMPTY=$(cd "$K82_TMP" && node "$CLI" dispatch render-filled verifier:dev 2>/dev/null)
K82_EMPTY_NO_BLOCK=$(echo "$K82_OUT_EMPTY" | grep -c '<prior_outputs>' || true)
# Confirm template carries the placeholder (regression guard).
K82_TMPL_HAS_TOKEN=$(grep -c '{prior_outputs}' "$ROOT/templates/dispatch/envelopes/verifier.tmpl.md" 2>/dev/null || true)
rm -rf "$K82_TMP"
if [ "$K82_HAS_PROGRAMMER" -ge "1" ] \
   && [ "$K82_HAS_TESTER" -ge "1" ] \
   && [ "$K82_HAS_OWN" = "0" ] \
   && [ "$K82_HAS_NOTE" -ge "1" ] \
   && [ "$K82_EMPTY_NO_BLOCK" = "0" ] \
   && [ "$K82_TMPL_HAS_TOKEN" -ge "1" ]; then
  pass "K82: prior-output sidecar injection (present→inlined, own sidecar filtered, absent→degraded, template has token)"
else
  fail "K82: sidecar injection mismatch — programmer=$K82_HAS_PROGRAMMER tester=$K82_HAS_TESTER own_filtered=$K82_HAS_OWN note=$K82_HAS_NOTE empty_no_block=$K82_EMPTY_NO_BLOCK tmpl_has_token=$K82_TMPL_HAS_TOKEN"
fi

# K82b: sidecar consumer broadening (v0.87.0 B1).
# Validates that tester + code-reviewer envelopes ALSO inline upstream
# sidecars, not just verifier. Tester consumes programmer (impl-summary.json);
# code-reviewer in dev/quick_implement consumes programmer + tester; in
# code_review workflow it runs standalone and falls through gracefully.
# Self-filter still applies (each agent never inlines its own sidecar).
K82B_TMP=$(mktemp -d)
mkdir -p "$K82B_TMP/.devt/state"
echo '{}' > "$K82B_TMP/.devt/config.json"
echo '{"workflow_id":"dev","active":true,"workflow_type":"dev","phase":"test","task":"k82b fixture"}' > "$K82B_TMP/.devt/state/workflow.yaml"
echo '{"status":"DONE","verdict":"PASS","agent":"programmer"}' > "$K82B_TMP/.devt/state/impl-summary.json"
echo '{"status":"DONE","verdict":"PASS","agent":"tester"}' > "$K82B_TMP/.devt/state/test-summary.json"
echo '{"status":"COMPLETE","verdict":"PASS","agent":"code-reviewer"}' > "$K82B_TMP/.devt/state/review.json"
# Tester sees programmer; doesn't see own tester sidecar.
K82B_TESTER_OUT=$(cd "$K82B_TMP" && node "$CLI" dispatch render-filled tester:dev 2>/dev/null)
K82B_TESTER_HAS_PROG=$(echo "$K82B_TESTER_OUT" | grep -c '<programmer_sidecar>' || true)
K82B_TESTER_HAS_OWN=$(echo "$K82B_TESTER_OUT" | grep -c '<tester_sidecar>' || true)
# Code-reviewer in dev sees programmer + tester; doesn't see own review.
K82B_CR_OUT=$(cd "$K82B_TMP" && node "$CLI" dispatch render-filled code-reviewer:dev 2>/dev/null)
K82B_CR_HAS_PROG=$(echo "$K82B_CR_OUT" | grep -c '<programmer_sidecar>' || true)
K82B_CR_HAS_TESTER=$(echo "$K82B_CR_OUT" | grep -c '<tester_sidecar>' || true)
K82B_CR_HAS_OWN=$(echo "$K82B_CR_OUT" | grep -c '<code-reviewer_sidecar>' || true)
# Template regression guard — all 5 broadened templates carry the token.
K82B_TPL_TESTER_DEV=$(grep -c '{prior_outputs}' "$ROOT/templates/dispatch/envelopes/tester.tmpl.md" 2>/dev/null || true)
K82B_TPL_TESTER_QI=$(grep -c '{prior_outputs}' "$ROOT/templates/dispatch/envelopes/tester-quick_implement.tmpl.md" 2>/dev/null || true)
K82B_TPL_CR_DEV=$(grep -c '{prior_outputs}' "$ROOT/templates/dispatch/envelopes/code-reviewer.tmpl.md" 2>/dev/null || true)
K82B_TPL_CR_QI=$(grep -c '{prior_outputs}' "$ROOT/templates/dispatch/envelopes/code-reviewer-quick_implement.tmpl.md" 2>/dev/null || true)
K82B_TPL_CR_CR=$(grep -c '{prior_outputs}' "$ROOT/templates/dispatch/envelopes/code-reviewer-code_review.tmpl.md" 2>/dev/null || true)
rm -rf "$K82B_TMP"
if [ "$K82B_TESTER_HAS_PROG" -ge "1" ] \
   && [ "$K82B_TESTER_HAS_OWN" = "0" ] \
   && [ "$K82B_CR_HAS_PROG" -ge "1" ] \
   && [ "$K82B_CR_HAS_TESTER" -ge "1" ] \
   && [ "$K82B_CR_HAS_OWN" = "0" ] \
   && [ "$K82B_TPL_TESTER_DEV" -ge "1" ] \
   && [ "$K82B_TPL_TESTER_QI" -ge "1" ] \
   && [ "$K82B_TPL_CR_DEV" -ge "1" ] \
   && [ "$K82B_TPL_CR_QI" -ge "1" ] \
   && [ "$K82B_TPL_CR_CR" -ge "1" ]; then
  pass "K82b: sidecar consumer broadening (tester sees programmer; code-reviewer sees programmer+tester; both filter own sidecar; 5 broadened templates carry the token)"
else
  fail "K82b: broadened sidecar consumer mismatch — tester_prog=$K82B_TESTER_HAS_PROG tester_own=$K82B_TESTER_HAS_OWN cr_prog=$K82B_CR_HAS_PROG cr_tester=$K82B_CR_HAS_TESTER cr_own=$K82B_CR_HAS_OWN tpl=[$K82B_TPL_TESTER_DEV,$K82B_TPL_TESTER_QI,$K82B_TPL_CR_DEV,$K82B_TPL_CR_QI,$K82B_TPL_CR_CR]"
fi

# K83: provenance citation protocol injection (v0.87.0 B2).
# Validates conditional protocol block — present only when graph-impact.md
# exists (graphify ran). In graphify-skip flows the block is absent (would
