   && [ "$K83_TPL_VERIFIER" -ge "1" ] \
   && [ "$K83_TPL_CR_CR" -ge "1" ]; then
  pass "K83: provenance citation protocol (graphify present→protocol inlined with via-call syntax, graphify absent→empty, 2 templates carry token)"
else
  fail "K83: protocol injection mismatch — verifier_protocol=$K83_VP_HAS_PROTOCOL verifier_via_call=$K83_VP_HAS_VIA_CALL cr_protocol=$K83_CR_PRESENT skip_no_protocol=$K83_VA_NO_PROTOCOL tpl_verifier=$K83_TPL_VERIFIER tpl_cr=$K83_TPL_CR_CR"
fi

# K84: plugin maintainer-mode pre-compress CLI surface (v0.87.0 B3).
# Validates the new `--plugin-build` flag wires correctly. Focus is on
# CLI contract + safety stack — NOT yield (yield depends on prose-shrink
# bugs that future fixes will improve without code changes here).
# Asserts: (a) clean-tree check fires (refuses when guardrails dirty);
# (b) --allow-dirty override works; (c) walker scopes to plugin tree;
# (d) structural validator refuses bad compressions (most plugin files
# trip validator because heading lines start with "The"); (e) result
# shape is consistent with compressAll for telemetry continuity.
# Snapshot any uncommitted maintainer edits in guardrails/ + skills/ BEFORE
# this test runs. K84 uses --allow-dirty (compresses on top of whatever's
# there) and then resets via git checkout. Without preservation, a smoke
# run wipes the maintainer's in-progress skill/guardrails edits along with
# the compression artifacts. We capture the diff, let the test run + reset,
# then re-apply the diff to restore the working tree. Untracked files are
# unaffected by `git diff` and `git checkout`, so they survive without
# intervention.
K84_PRESERVED_PATCH=$(mktemp)
git -C "$ROOT" diff -- guardrails skills > "$K84_PRESERVED_PATCH" 2>/dev/null || true

K84_OUT=$(node "$CLI" static-compress --plugin-build --allow-dirty 2>/dev/null)
K84_OK=$(echo "$K84_OUT" | jq -r '.ok // false')
K84_TOTAL=$(echo "$K84_OUT" | jq -r '.total_files // 0')
K84_HAS_PLUGIN_ROOT=$(echo "$K84_OUT" | jq -r '.plugin_root | length > 0')
K84_HAS_BREAKDOWN=$(echo "$K84_OUT" | jq -r '.engine_breakdown | type == "object"')
# Walker must find guardrails files (5+ guardrails .md files exist)
K84_HAS_GUARDRAILS_CANDIDATE=$(test "$K84_TOTAL" -ge "5" && echo yes || echo no)
# Errors array exists (structural drift expected on heading-starts-with-article files)
K84_HAS_ERRORS_FIELD=$(echo "$K84_OUT" | jq -r '.errors | type == "array"')
# Reset compression artifacts so the smoke run stays side-effect-free
# against a clean tree.
git -C "$ROOT" checkout guardrails skills 2>/dev/null || true

# Restore the maintainer's pre-K84 uncommitted state (if any). Empty patch
# is a no-op via the -s check. Apply failure warns but does not fail the
# test — manual recovery via the saved patch path stays available.
if [ -s "$K84_PRESERVED_PATCH" ]; then
  git -C "$ROOT" apply --whitespace=nowarn "$K84_PRESERVED_PATCH" 2>/dev/null \
    || echo "  WARN: K84 could not restore prior uncommitted changes in guardrails/skills (patch at $K84_PRESERVED_PATCH); check git status" >&2
fi
rm -f "$K84_PRESERVED_PATCH"
# CLI surface guard — usage string carries new flag
K84_USAGE_HAS_FLAG=$(node "$CLI" static-compress 2>&1 | grep -c -- '--plugin-build' || true)
if [ "$K84_OK" = "true" ] \
   && [ "$K84_HAS_PLUGIN_ROOT" = "true" ] \
   && [ "$K84_HAS_BREAKDOWN" = "true" ] \
   && [ "$K84_HAS_GUARDRAILS_CANDIDATE" = "yes" ] \
   && [ "$K84_HAS_ERRORS_FIELD" = "true" ] \
   && [ "$K84_USAGE_HAS_FLAG" -ge "1" ]; then
  pass "K84: plugin-build CLI surface (walker finds ${K84_TOTAL} files, result shape consistent, structural validator gates writes, usage advertises flag)"
else
  fail "K84: plugin-build mismatch — ok=$K84_OK plugin_root=$K84_HAS_PLUGIN_ROOT breakdown=$K84_HAS_BREAKDOWN candidates=$K84_HAS_GUARDRAILS_CANDIDATE (total=$K84_TOTAL) errors_field=$K84_HAS_ERRORS_FIELD usage=$K84_USAGE_HAS_FLAG"
fi

# K85: prose-shrink correctness — locks 3 root-cause fixes that lifted
# plugin-build yield from 5/23 to 23/23 (22% → 100%):
#   (1) ARTICLES /i removed — heading "## The Iron Law" no longer mangled
#       (under /i, the lookahead [a-z] matched uppercase too, stripping
#       "The " from headings).
#   (2) Heading-line whole-line protection in PROTECTED_PATTERNS — keeps
#       in-heading lowercase articles like "## Step 1: keep the scope"
#       byte-equal (article stripping mid-heading was changing titles).
#   (3) Whitespace-collapse anchored to non-whitespace — preserves leading
#       indentation on list continuation lines AND indented code fences
#       within list items (3-space CommonMark loose-list pattern).
# Also asserts ARTICLES still compresses lowercase prose (no regression
# on the intended compression target) AND article stripping correctly
# avoids title-cased sentence starts.
K85_TMP=$(mktemp -d)
cat > "$K85_TMP/case1.md" <<'EOF_K85'
## The Iron Law
## The Process
EOF_K85
cat > "$K85_TMP/case2.md" <<'EOF_K85'
## Step 1: keep the scope fresh
## Why this is not the default path
EOF_K85
cat > "$K85_TMP/case3.md" <<'EOF_K85'
1. First item with continuation:

   ```bash
   indented_code_block
   ```

   More continuation prose.
EOF_K85
cat > "$K85_TMP/case4.md" <<'EOF_K85'
see the cat. we have an example. check the docs.
EOF_K85
# Fixture 5 (v0.88.2): inline triple-backticks in prose must NOT pair
# with a real code fence's opening. A field project's
# quality-gates.md had this exact pattern: blockquote example
# `tagged ``` ```bash parallel ``` are run` followed by a real
# `bash parallel` fence. The earlier unanchored regex paired the
# inline closing with the real fence opening, leaving the real block
# UNPROTECTED — then `\s+([,.;:!?])` collapsed `ruff check .` →
# `ruff check.` inside what should have been protected code.
cat > "$K85_TMP/case5.md" <<'EOF_K85'
> About `parallel`: gates tagged ``` ```bash parallel ``` are run concurrently.

## Gate

```bash parallel
uv run ruff check .
```

End.
EOF_K85
K85_PROBE="const { compress } = require('$ROOT/bin/modules/prose-shrink.cjs'); const fs = require('fs');"
# Fixture 1: heading articles preserved
K85_C1=$(node -e "$K85_PROBE const r = compress(fs.readFileSync('$K85_TMP/case1.md','utf8')); process.stdout.write(r.compressed.includes('## The Iron Law') && r.compressed.includes('## The Process') ? 'pass' : 'fail');")
# Fixture 2: in-heading lowercase articles preserved (heading protection)
K85_C2=$(node -e "$K85_PROBE const r = compress(fs.readFileSync('$K85_TMP/case2.md','utf8')); process.stdout.write(r.compressed.includes('## Step 1: keep the scope fresh') && r.compressed.includes('## Why this is not the default path') ? 'pass' : 'fail');")
# Fixture 3: 3-space indented code fences preserved (interior-only collapse)
K85_C3=$(node -e "$K85_PROBE const r = compress(fs.readFileSync('$K85_TMP/case3.md','utf8')); process.stdout.write(r.compressed.includes('   \`\`\`bash') && r.compressed.includes('   indented_code_block') ? 'pass' : 'fail');")
# Fixture 4: lowercase article compression STILL works (no regression)
K85_C4=$(node -e "$K85_PROBE const r = compress(fs.readFileSync('$K85_TMP/case4.md','utf8')); const c = r.compressed; process.stdout.write(!c.includes(' the cat') && !c.includes(' an example') ? 'pass' : 'fail');")
# Fixture 5: inline triple-backticks in prose don't break real fence
# protection — `ruff check .` must survive byte-equal inside the block.
K85_C5=$(node -e "$K85_PROBE const r = compress(fs.readFileSync('$K85_TMP/case5.md','utf8')); const c = r.compressed; process.stdout.write(c.includes('ruff check .') && !c.includes('ruff check.') ? 'pass' : 'fail');")
# Regression guards (literal-string greps — substring presence, not full
# regex match, to avoid escaping pitfalls).
# 1. ARTICLES regex no longer ends with /gi
K85_NO_I_FLAG=$(grep -cF 'const ARTICLES = /\b(?:a|an|the)[ \t]+(?=[a-z])/g' "$ROOT/bin/modules/prose-shrink.cjs" 2>/dev/null || true)
# 2. Heading line pattern present in PROTECTED_PATTERNS
K85_HAS_HEADING_PATTERN=$(grep -cF '/^#{1,6}[ \t]+.*$/gm' "$ROOT/bin/modules/prose-shrink.cjs" 2>/dev/null || true)
# 3. Whitespace collapse uses \S anchor
K85_HAS_SAFE_COLLAPSE=$(grep -cF '(\S)[ \t]{2,}' "$ROOT/bin/modules/prose-shrink.cjs" 2>/dev/null || true)
rm -rf "$K85_TMP"
if [ "$K85_C1" = "pass" ] \
   && [ "$K85_C2" = "pass" ] \
   && [ "$K85_C3" = "pass" ] \
   && [ "$K85_C4" = "pass" ] \
   && [ "$K85_C5" = "pass" ] \
   && [ "$K85_NO_I_FLAG" -ge "1" ] \
   && [ "$K85_HAS_HEADING_PATTERN" -ge "1" ] \
   && [ "$K85_HAS_SAFE_COLLAPSE" -ge "1" ]; then
  pass "K85: prose-shrink correctness (heading articles preserved, in-heading lowercase preserved, indented code fences preserved, lowercase prose still compressed, inline triple-backticks don't break real fence protection, 3 regression guards)"
else
  fail "K85: prose-shrink correctness mismatch — heading=$K85_C1 in_heading=$K85_C2 indented_fence=$K85_C3 lowercase=$K85_C4 inline_fences=$K85_C5 no_i_flag=$K85_NO_I_FLAG heading_pattern=$K85_HAS_HEADING_PATTERN safe_collapse=$K85_HAS_SAFE_COLLAPSE"
fi

# K86: dispatch decompose CLI surface (v0.89.0 measurement tool).
# Pure read-only — render envelope, classify each XML block as static
# or dynamic, return JSON with summary + per-block detail. Validates:
# (a) JSON shape (.summary, .blocks); (b) static_pct + dynamic_pct +
# wrapper_pct ≈ 1.0; (c) governing_rules detected as static when present
# in the rendered envelope; (d) the new exports (cmdDecompose) are wired.
K86_TMP=$(mktemp -d)
mkdir -p "$K86_TMP/.devt/state"
echo '{}' > "$K86_TMP/.devt/config.json"
echo '{"workflow_id":"dev","active":true,"workflow_type":"dev","phase":"verify","task":"k86 fixture"}' > "$K86_TMP/.devt/state/workflow.yaml"
K86_OUT=$(cd "$K86_TMP" && node "$CLI" dispatch decompose verifier:dev 2>/dev/null)
K86_HAS_SUMMARY=$(echo "$K86_OUT" | jq -r '.summary | type == "object"' 2>/dev/null)
K86_HAS_BLOCKS=$(echo "$K86_OUT" | jq -r '.blocks | type == "array"' 2>/dev/null)
K86_TOTAL=$(echo "$K86_OUT" | jq -r '.total_bytes' 2>/dev/null)
K86_PCT_SUM=$(echo "$K86_OUT" | jq -r '(.summary.static_pct + .summary.dynamic_pct + .summary.wrapper_pct)' 2>/dev/null)
K86_AGENT=$(echo "$K86_OUT" | jq -r '.agent' 2>/dev/null)
K86_HAS_GOV_RULES=$(echo "$K86_OUT" | jq -r '[.blocks[] | select(.tag == "governing_rules" and .kind == "static")] | length > 0' 2>/dev/null)
# wrapper_bytes MUST be non-negative (field audit B1 fix): nested tags
# like <review_checklist> inside <governing_rules> were being double-counted
# in the prior implementation, producing negative wrapper_bytes. New logic
# attributes inner-tag bytes only to their outermost ancestor.
K86_WRAPPER_NONNEG=$(echo "$K86_OUT" | jq -r '.summary.wrapper_bytes >= 0' 2>/dev/null)
# Every block exposes a nested_in field (null when the tag is outermost).
K86_BLOCKS_HAVE_NESTED_IN=$(echo "$K86_OUT" | jq -r '[.blocks[] | has("nested_in")] | all' 2>/dev/null)
# Export guard — cmdDecompose available externally
K86_EXPORT_OK=$(node -e "console.log(typeof require('$ROOT/bin/modules/dispatch.cjs').cmdDecompose === 'function')")
rm -rf "$K86_TMP"
# pct_sum should round to ~1.0 (allow tiny float jitter via 0.99-1.01 window)
PCT_OK=$(awk "BEGIN { v=$K86_PCT_SUM; if (v >= 0.99 && v <= 1.01) print 1; else print 0 }")
if [ "$K86_HAS_SUMMARY" = "true" ] \
   && [ "$K86_HAS_BLOCKS" = "true" ] \
   && [ "$K86_TOTAL" -gt "0" ] \
   && [ "$PCT_OK" = "1" ] \
   && [ "$K86_AGENT" = "verifier" ] \
   && [ "$K86_HAS_GOV_RULES" = "true" ] \
   && [ "$K86_WRAPPER_NONNEG" = "true" ] \
   && [ "$K86_BLOCKS_HAVE_NESTED_IN" = "true" ] \
   && [ "$K86_EXPORT_OK" = "true" ]; then
  pass "K86: dispatch decompose CLI surface (JSON shape, pct sums to 1, governing_rules classified static, wrapper non-negative, nested_in field present, cmdDecompose exported)"
else
  fail "K86: decompose mismatch — summary=$K86_HAS_SUMMARY blocks=$K86_HAS_BLOCKS total=$K86_TOTAL pct_sum=$K86_PCT_SUM agent=$K86_AGENT has_gov_rules=$K86_HAS_GOV_RULES wrapper_nonneg=$K86_WRAPPER_NONNEG nested_in=$K86_BLOCKS_HAVE_NESTED_IN export=$K86_EXPORT_OK"
fi

# K86b: dispatch decompose handles multi-occurrence tags via per-byte
# coverage tracking. Field finding: when CLAUDE.md prose mentions
# literal tag names (e.g. "<task>" or "<governing_rules>" appearing in
# documentation inside the governing_rules block), the prior summation-
# based algorithm counted each occurrence as a sibling outermost range,
# producing static_bytes + dynamic_bytes > total_bytes and wrapper_bytes
# < 0. The fix paints per-byte coverage from outermost ranges only —
# mathematically eliminates the double-count class. K86b runs against
# the verifier:dev envelope rendered FROM devt's own repo (which has
# the multi-mention pathology in CLAUDE.md) and asserts:
# (a) wrapper_bytes >= 0
# (b) static + dynamic + wrapper === total_bytes (no float jitter)
# (c) multiple blocks with the same tag-name CAN appear in blocks[]
#     (no merge-by-tag-name)
K86B_OUT=$(node "$CLI" dispatch decompose verifier:dev 2>/dev/null)
K86B_WRAPPER=$(echo "$K86B_OUT" | jq -r '.summary.wrapper_bytes' 2>/dev/null)
K86B_STATIC=$(echo "$K86B_OUT" | jq -r '.summary.static_bytes' 2>/dev/null)
K86B_DYNAMIC=$(echo "$K86B_OUT" | jq -r '.summary.dynamic_bytes' 2>/dev/null)
K86B_TOTAL=$(echo "$K86B_OUT" | jq -r '.total_bytes' 2>/dev/null)
K86B_SUM=$((K86B_STATIC + K86B_DYNAMIC + K86B_WRAPPER))
K86B_TASK_OCCURRENCES=$(echo "$K86B_OUT" | jq -r '[.blocks[] | select(.tag == "task")] | length' 2>/dev/null)
if [ "$K86B_WRAPPER" -ge "0" ] && [ "$K86B_SUM" = "$K86B_TOTAL" ] && [ "$K86B_TASK_OCCURRENCES" -ge "1" ]; then
  pass "K86b: byte-coverage tracking (wrapper non-negative, static+dynamic+wrapper === total, multi-occurrence tags listed individually)"
else
  fail "K86b: byte-coverage mismatch — wrapper=$K86B_WRAPPER (want ≥0) sum=$K86B_SUM total=$K86B_TOTAL task_occurrences=$K86B_TASK_OCCURRENCES (want ≥1)"
fi

# K87: static-compress always persists log entry (field audit B2).
# Prior implementation only called _logEntry on the success return path
# — refusal paths (mode=off, backup exists, sensitive path, drift,
# empty input, identical output, etc.) left no audit trail. Field
# 2026-06-10: 14 files compressed but .devt/state/static-compress.jsonl
# was absent because subsequent re-runs all took refusal paths.
# Fix: route every return through _logAndReturn which calls _logEntry
# exactly once per invocation. K87 verifies 3 distinct return paths
# (mode=off refusal, compress success, backup-exists refusal) all log.
K87_TMP=$(mktemp -d)
mkdir -p "$K87_TMP/.devt/rules"
# Fixture 1: mode='off' refusal
echo '{"static_compress":{"mode":"off"}}' > "$K87_TMP/.devt/config.json"
echo '# Sample' > "$K87_TMP/.devt/rules/x.md"
(cd "$K87_TMP" && node "$CLI" static-compress .devt/rules/x.md >/dev/null 2>&1) || true
# Fixture 2: compress success
echo '{"static_compress":{"mode":"on"}}' > "$K87_TMP/.devt/config.json"
cat > "$K87_TMP/.devt/rules/y.md" <<'EOF_K87'
# Compress Test
This is a realistic markdown body. Articles and filler words should be removed. The compressor needs enough text to find tokens it can drop without affecting structure.
## Section
More body text. Includes URL https://example.com and `inline_code` and CONST_VALUE.
EOF_K87
(cd "$K87_TMP" && node "$CLI" static-compress .devt/rules/y.md >/dev/null 2>&1) || true
# Fixture 3: backup-exists refusal
(cd "$K87_TMP" && node "$CLI" static-compress .devt/rules/y.md >/dev/null 2>&1) || true
K87_LOG_LINES=$(wc -l < "$K87_TMP/.devt/state/static-compress.jsonl" 2>/dev/null | tr -d ' ' || echo 0)
K87_HAS_REFUSAL=$(grep -c '"reason"' "$K87_TMP/.devt/state/static-compress.jsonl" 2>/dev/null || true)
rm -rf "$K87_TMP"
if [ "$K87_LOG_LINES" = "3" ] && [ "$K87_HAS_REFUSAL" -ge "2" ]; then
  pass "K87: static-compress audit trail (3 distinct return paths all logged: mode=off refusal, success, backup-exists refusal)"
else
  fail "K87: log persistence mismatch — log_lines=$K87_LOG_LINES (want 3) reason_count=$K87_HAS_REFUSAL (want ≥2)"
fi

# K88: workflow_id stability across re-init within active workflow
# (field audit B4). Prior init.cjs unconditionally stripped
# created_at + workflow_id from workflow.yaml on every init * call,
# forcing updateState to re-stamp both → workflow_id rotated on every
# devt command. Field observed 42 IDs in one conceptual workflow's
# history. Fix: when prior workflow.yaml has active=true, preserve
# stamps. When active=false (or absent), strip as before.
# K88 verifies both branches.
K88_TMP=$(mktemp -d)
mkdir -p "$K88_TMP/.devt/state"
echo '{}' > "$K88_TMP/.devt/config.json"
# Branch A: active=true + same workflow_type → workflow_id preserved
cat > "$K88_TMP/.devt/state/workflow.yaml" <<'EOF_K88'
active: true
workflow_id: k88-preserved-uuid
created_at: "2026-06-01T00:00:00Z"
workflow_type: dev
task: "k88 fixture"
EOF_K88
(cd "$K88_TMP" && node "$CLI" init workflow "k88 re-init" >/dev/null 2>&1) || true
K88_PRESERVED_ID=$(grep "^workflow_id:" "$K88_TMP/.devt/state/workflow.yaml" | head -1 | awk '{print $2}')
# Branch B: active=false → workflow_id rotated (new UUID)
cat > "$K88_TMP/.devt/state/workflow.yaml" <<'EOF_K88'
active: false
workflow_id: k88-old-closed-uuid
created_at: "2026-06-01T00:00:00Z"
workflow_type: dev
task: "k88 closed fixture"
EOF_K88
(cd "$K88_TMP" && node "$CLI" init workflow "k88 fresh workflow" >/dev/null 2>&1) || true
K88_ROTATED_ID=$(grep "^workflow_id:" "$K88_TMP/.devt/state/workflow.yaml" | head -1 | awk '{print $2}')
rm -rf "$K88_TMP"
if [ "$K88_PRESERVED_ID" = "k88-preserved-uuid" ] && [ "$K88_ROTATED_ID" != "k88-old-closed-uuid" ] && [ "$K88_ROTATED_ID" != "k88-preserved-uuid" ] && [ -n "$K88_ROTATED_ID" ]; then
  pass "K88: workflow_id stability (active=true preserves prior ID, active=false rotates to fresh UUID)"
else
  fail "K88: workflow_id rotation mismatch — preserved_id='$K88_PRESERVED_ID' (want 'k88-preserved-uuid'), rotated_id='$K88_ROTATED_ID' (want fresh UUID)"
fi

# K89: graphify symbols-in-files envelope shape (field audit G2).
# Prior implementation returned a bare array []. Field could not
# distinguish "graph stale, re-index needed" from "no symbols in diff"
# from "input was empty". New shape returns
# { symbols, reason, graph_lag_commits, total_matches } so orchestrators
# have actionable signal. K89 verifies (a) no-input path returns envelope
# with reason "no input files"; (b) workflows/code-review.md consumer was
# updated to '.symbols[]?.symbol' (not bare '.[].symbol').
K89_NO_INPUT_REASON=$(node -e "const m = require('$ROOT/bin/modules/graphify.cjs'); const r = m.symbolsInFiles([]); process.stdout.write(r.reason || '');" 2>/dev/null || true)
K89_HAS_ENVELOPE=$(node -e "const m = require('$ROOT/bin/modules/graphify.cjs'); const r = m.symbolsInFiles([]); process.stdout.write(typeof r === 'object' && 'symbols' in r && 'reason' in r && 'graph_lag_commits' in r && 'total_matches' in r ? 'true' : 'false');" 2>/dev/null || true)
# Consumer was migrated from inline workflow bash to state.cjs
# computeGraphifyImpactPlan (cal #37 #3) — assert the consumer is updated
# in the new location where graphify.symbolsInFiles is called.
K89_CONSUMER_UPDATED=$(grep -cE 'graphifyMod\.symbolsInFiles' "$ROOT/bin/modules/state.cjs" 2>/dev/null || true)
if [ "$K89_NO_INPUT_REASON" = "no input files" ] && [ "$K89_HAS_ENVELOPE" = "true" ] && [ "$K89_CONSUMER_UPDATED" -ge "1" ]; then
  pass "K89: symbols-in-files envelope shape (reason/graph_lag_commits/total_matches keys present; consumer in state.cjs::computeGraphifyImpactPlan uses .symbols[])"
else
  fail "K89: envelope mismatch — no_input_reason='$K89_NO_INPUT_REASON' envelope=$K89_HAS_ENVELOPE consumer_updated=$K89_CONSUMER_UPDATED"
fi

# K90: lane-suggestions skew detection (field audit G6).
# When the largest community group dominates the covered scope (>40%),
# the partition is too skewed to parallelize meaningfully — one lane
# would do most of the work. Field observed a 230-file giant + 3
# noise buckets in code-review-parallel and had to discard the result.
# Fix: laneSuggestions returns mode=fallback (instead of mode=partial)
# when skew_ratio > 0.40. K90 builds a synthetic 102/5/3 fixture →
# 93% skew → expects fallback with skew_ratio populated.
K90_NODE_PROBE="
const path = require('path');
const fs = require('fs');
const tmp = require('os').tmpdir() + '/k90-fix-' + process.pid;
fs.rmSync(tmp, { recursive: true, force: true });
fs.mkdirSync(path.join(tmp, 'graphify-out'), { recursive: true });
fs.mkdirSync(path.join(tmp, '.devt/state'), { recursive: true });
fs.writeFileSync(path.join(tmp, '.devt/config.json'), '{\"graphify\":{\"enabled\":true}}');
const nodes = [];
const links = [];
const files = [];
for (let i = 0; i < 100; i++) { nodes.push({id:'a'+i,label:'A'+i,source_file:'src/big/x'+i+'.py',community:1}); files.push('src/big/x'+i+'.py'); }
for (let i = 0; i < 5; i++) { nodes.push({id:'b'+i,label:'B'+i,source_file:'src/mid/y'+i+'.py',community:2}); files.push('src/mid/y'+i+'.py'); }
for (let i = 0; i < 3; i++) { nodes.push({id:'c'+i,label:'C'+i,source_file:'src/sm/z'+i+'.py',community:3}); files.push('src/sm/z'+i+'.py'); }
files.push('docs/readme.md','test/uncov.py');
fs.writeFileSync(path.join(tmp, 'graphify-out/graph.json'), JSON.stringify({directed:true, multigraph:false, graph:{}, nodes, links}));
process.chdir(tmp);
const g = require('$ROOT/bin/modules/graphify.cjs');
const r = g.laneSuggestions(files, { targetLanes: 3 });
process.stdout.write(JSON.stringify({mode: r.mode, has_skew_ratio: typeof r.skew_ratio === 'number', skew_above_threshold: (r.skew_ratio || 0) > 0.40}));
fs.rmSync(tmp, { recursive: true, force: true });
"
K90_OUT=$(node -e "$K90_NODE_PROBE" 2>/dev/null || echo '{}')
K90_MODE=$(echo "$K90_OUT" | node -e "let s='';process.stdin.on('data',d=>s+=d);process.stdin.on('end',()=>{try{console.log(JSON.parse(s).mode||'')}catch(e){console.log('')}})")
K90_HAS_SKEW=$(echo "$K90_OUT" | node -e "let s='';process.stdin.on('data',d=>s+=d);process.stdin.on('end',()=>{try{console.log(JSON.parse(s).has_skew_ratio===true)}catch(e){console.log('false')}})")
K90_ABOVE=$(echo "$K90_OUT" | node -e "let s='';process.stdin.on('data',d=>s+=d);process.stdin.on('end',()=>{try{console.log(JSON.parse(s).skew_above_threshold===true)}catch(e){console.log('false')}})")
if [ "$K90_MODE" = "fallback" ] && [ "$K90_HAS_SKEW" = "true" ] && [ "$K90_ABOVE" = "true" ]; then
  pass "K90: lane-suggestions skew detection (102/5/3 fixture → mode=fallback with skew_ratio above 40% threshold)"
else
  fail "K90: skew detection mismatch — mode='$K90_MODE' has_skew=$K90_HAS_SKEW above_threshold=$K90_ABOVE"
fi

# K91: graphify --allow=<pattern> whitelist for sensitive-path filter
# (field audit G7). Field reported false-positive class:
# `.env.example` / `.env.sample` are committed templates that match the
# sensitive denylist but contain no real credentials. Fix: --allow=<substring>
# CLI flag bypasses the denylist for known-safe paths. K91 verifies:
# (a) without --allow, .env.example is refused (exit 2);
# (b) with --allow=.env.example, the call succeeds.
K91_TMP=$(mktemp -d)
mkdir -p "$K91_TMP/.devt/state" "$K91_TMP/graphify-out" "$K91_TMP/configs"
echo '{"graphify":{"enabled":true}}' > "$K91_TMP/.devt/config.json"
printf '{"directed":true,"multigraph":false,"graph":{},"nodes":[{"id":"x","label":"X","source_file":"configs/.env.example"}],"links":[]}' > "$K91_TMP/graphify-out/graph.json"
touch "$K91_TMP/configs/.env.example"
# Without --allow: refused (exit 2). Run in a subshell + `|| true` so set -e
# doesn't kill the smoke when the expected refusal returns non-zero.
if (cd "$K91_TMP" && node "$CLI" graphify symbols-in-files configs/.env.example >/dev/null 2>&1); then
  K91_REFUSED_EXIT=0
else
  K91_REFUSED_EXIT=$?
fi
# With --allow: succeeds
K91_ALLOWED_OUT=$(cd "$K91_TMP" && node "$CLI" graphify symbols-in-files configs/.env.example --allow=.env.example 2>/dev/null)
K91_ALLOWED_REASON=$(echo "$K91_ALLOWED_OUT" | node -e "let s='';process.stdin.on('data',d=>s+=d);process.stdin.on('end',()=>{try{console.log(JSON.parse(s).reason||'')}catch(e){console.log('')}})")
rm -rf "$K91_TMP"
if [ "$K91_REFUSED_EXIT" = "2" ] && [ "$K91_ALLOWED_REASON" = "ok" ]; then
  pass "K91: sensitive-path --allow whitelist (.env.example refused without flag, allowed with --allow=.env.example)"
else
  fail "K91: --allow mismatch — refused_exit=$K91_REFUSED_EXIT (want 2), allowed_reason='$K91_ALLOWED_REASON' (want 'ok')"
fi

# K91b: --allow uses basename-anchored match, NOT full-path substring.
# Code-review hardening: prior implementation matched substring anywhere
# in the path, so `--allow=.ssh/` would bypass `nested/.ssh/id_rsa`.
# Fix: match against path.basename(f) only. K91b verifies the attack
# pattern is correctly refused even with the (path-traversal-shaped)
# allow flag present.
K91B_TMP=$(mktemp -d)
mkdir -p "$K91B_TMP/.devt/state" "$K91B_TMP/graphify-out" "$K91B_TMP/nested/.ssh"
echo '{"graphify":{"enabled":true}}' > "$K91B_TMP/.devt/config.json"
printf '{"directed":true,"multigraph":false,"graph":{},"nodes":[{"id":"y","label":"Y","source_file":"nested/.ssh/id_rsa"}],"links":[]}' > "$K91B_TMP/graphify-out/graph.json"
touch "$K91B_TMP/nested/.ssh/id_rsa"
# With --allow=.ssh/ (path-substring-shaped) — should STILL refuse.
if (cd "$K91B_TMP" && node "$CLI" graphify symbols-in-files nested/.ssh/id_rsa --allow=.ssh/ >/dev/null 2>&1); then
  K91B_ATTACK_EXIT=0
else
  K91B_ATTACK_EXIT=$?
fi
rm -rf "$K91B_TMP"
if [ "$K91B_ATTACK_EXIT" = "2" ]; then
  pass "K91b: --allow is basename-anchored (path-substring-shaped pattern like --allow=.ssh/ does NOT bypass nested/.ssh/id_rsa)"
else
  fail "K91b: --allow attack surface — path-substring pattern bypassed sensitive-path filter (exit=$K91B_ATTACK_EXIT, want 2)"
fi

# K92: dispatch-hygiene-guard is content-aware (v0.91.0).
# Prior gate flagged ALL Task() calls to devt:* agents that lacked the
# canonical <scope_trust>/<scope_hint>/<memory_signal> trio — even when
# the orchestrator hand-injected a richer envelope shape (e.g. <context>
# + <original_review> for iter-2 verifier revisions). Field I1
# reported the false-positive class blocked legitimate workflow teardown.
# Fix: expanded signal set to include any of <context>, <graph_impact>,
# <original_review>, <lane_scope>, <god_node_warnings>, <prior_outputs>,
# <provenance_protocol>. K92 verifies:
# (a) hand-injected <context> envelope passes (no deny)
# (b) docs-writer with no envelope passes (ENVELOPE_NOT_REQUIRED)
# (c) bare prose with no envelope STILL denies (real failure mode caught)
K92_PROBE_HAND_INJECTED='{"tool_name":"Agent","tool_input":{"subagent_type":"devt:code-reviewer","prompt":"<context> <workflow_type>code_review_parallel</workflow_type> <mode>synthesis_revision</mode> <original_review>.devt/state/review.md</original_review> </context> Do the work."}}'
K92_PROBE_DOCS_WRITER='{"tool_name":"Agent","tool_input":{"subagent_type":"devt:docs-writer","prompt":"You are the docs-writer for Batch A. Update changelog."}}'
K92_PROBE_BARE='{"tool_name":"Agent","tool_input":{"subagent_type":"devt:code-reviewer","prompt":"You are reviewing Lane A. Just do it."}}'
K92_HAND_RESULT=$(echo "$K92_PROBE_HAND_INJECTED" | node "$ROOT/hooks/run-hook.js" dispatch-hygiene-guard.sh 2>/dev/null)
K92_DOCS_RESULT=$(echo "$K92_PROBE_DOCS_WRITER" | node "$ROOT/hooks/run-hook.js" dispatch-hygiene-guard.sh 2>/dev/null)
K92_BARE_RESULT=$(echo "$K92_PROBE_BARE" | node "$ROOT/hooks/run-hook.js" dispatch-hygiene-guard.sh 2>/dev/null)
# Hand-injected and docs-writer should produce NO deny output (empty stdout).
K92_HAND_PASS=$([ -z "$K92_HAND_RESULT" ] && echo yes || echo no)
K92_DOCS_PASS=$([ -z "$K92_DOCS_RESULT" ] && echo yes || echo no)
# Bare prose should produce a deny decision.
K92_BARE_DENIES=$(echo "$K92_BARE_RESULT" | grep -c '"decision":"deny"' || true)
if [ "$K92_HAND_PASS" = "yes" ] && [ "$K92_DOCS_PASS" = "yes" ] && [ "$K92_BARE_DENIES" -ge "1" ]; then
  pass "K92: dispatch-hygiene content-aware (hand-injected <context> envelope passes, ENVELOPE_NOT_REQUIRED docs-writer passes, bare prose still denies)"
else
  fail "K92: hygiene gate mismatch — hand_injected_pass=$K92_HAND_PASS docs_writer_pass=$K92_DOCS_PASS bare_denies=$K92_BARE_DENIES"
fi

# K93: hook-cost-estimate CLI surface + classification correctness.
# Validates the per-hook migration ROI estimator: reads a synthetic
# hook-trace JSONL (generated with dynamic timestamps so the smoke is
# resilient to clock drift), runs the CLI, and asserts the recommendation
# logic correctly classifies hooks by their event role and fire rate.
# Uses devt's real hooks/ tree for brittleness scoring (module resolves
# hooksDir via __dirname, not cwd) — so dispatch-hygiene-guard.sh's 10
# JS-regex literals drive the "migrate" recommendation when fires <= 200.
K93_TMP=$(mktemp -d)
mkdir -p "$K93_TMP/.devt/state/hook-trace"
K93_TS=$(date -u +"%Y-%m-%dT%H:%M:%SZ")
# Synthetic trace: dispatch-hygiene-guard at 50 fires (low → migrate eligible
# given the real hook's brittleness=10); bash-guard at 1000 fires (high →
# stay even if brittleness were high, since the fires cap kicks in);
# session-start at 5 fires (lifecycle event → always stay regardless).
{
  for _ in $(seq 1 50); do echo "{\"ts\":\"$K93_TS\",\"script\":\"dispatch-hygiene-guard.sh\",\"stdin_bytes\":300,\"exit\":0}"; done
  for _ in $(seq 1 1000); do echo "{\"ts\":\"$K93_TS\",\"script\":\"bash-guard.sh\",\"stdin_bytes\":700,\"exit\":0}"; done
  for _ in $(seq 1 5); do echo "{\"ts\":\"$K93_TS\",\"script\":\"session-start.sh\",\"stdin_bytes\":160,\"exit\":0}"; done
} > "$K93_TMP/.devt/state/hook-trace/run-hook.jsonl"
K93_OUT=$(cd "$K93_TMP" && node "$CLI" hook-cost-estimate --window=7d 2>/dev/null)
K93_OK=$(echo "$K93_OUT" | jq -r '.ok // false')
K93_HAS_SUMMARY=$(echo "$K93_OUT" | jq -r '.summary | type == "object"')
K93_HAS_HOOKS_ARRAY=$(echo "$K93_OUT" | jq -r '.hooks | type == "array"')
K93_TOTAL_HOOKS=$(echo "$K93_OUT" | jq -r '.hooks | length')
# Classification asserts — these are the contract that the algorithm
# protects. Changing them requires updating the recommendation thresholds.
K93_DHG_REC=$(echo "$K93_OUT" | jq -r '.hooks[] | select(.hook == "dispatch-hygiene-guard.sh") | .recommend')
K93_BASH_REC=$(echo "$K93_OUT" | jq -r '.hooks[] | select(.hook == "bash-guard.sh") | .recommend')
K93_SESS_REC=$(echo "$K93_OUT" | jq -r '.hooks[] | select(.hook == "session-start.sh") | .recommend')
# Invalid window must surface as ok=false. The CLI exits 1 in that case
# so pipefail would trip the smoke under set -e — wrap in `|| true` to
# capture the JSON output without aborting the test (K91 pattern).
K93_INVALID_OK=$(cd "$K93_TMP" && (node "$CLI" hook-cost-estimate --window=invalid 2>/dev/null || true) | jq -r '.ok // false')
# 24h window flag wires through.
K93_24H_DAYS=$(cd "$K93_TMP" && node "$CLI" hook-cost-estimate --window=24h 2>/dev/null | jq -r '.window_days')
rm -rf "$K93_TMP"
if [ "$K93_OK" = "true" ] \
   && [ "$K93_HAS_SUMMARY" = "true" ] \
   && [ "$K93_HAS_HOOKS_ARRAY" = "true" ] \
   && [ "$K93_TOTAL_HOOKS" = "3" ] \
   && [ "$K93_DHG_REC" = "migrate" ] \
   && [ "$K93_BASH_REC" = "stay" ] \
   && [ "$K93_SESS_REC" = "stay" ] \
   && [ "$K93_INVALID_OK" = "false" ] \
   && [ "$K93_24H_DAYS" = "1" ]; then
  pass "K93: hook-cost-estimate (well-formed JSON, dispatch-hygiene→migrate, bash-guard→stay, session-start→stay, --window flag wires, invalid window errors)"
else
  fail "K93: hook-cost-estimate mismatch — ok=$K93_OK summary=$K93_HAS_SUMMARY hooks=$K93_HAS_HOOKS_ARRAY total=$K93_TOTAL_HOOKS dhg=$K93_DHG_REC bash=$K93_BASH_REC sess=$K93_SESS_REC invalid_ok=$K93_INVALID_OK 24h_days=$K93_24H_DAYS"
fi

# K94: command-surface stratification contract.
# Validates the post-Phase-3 visible-vs-hidden split.
# Visible (16): do, workflow, specify, plan, research, implement, debug,
# review, ship, status, next, setup, memory, help, note, thread (promoted
# to visible — a session-handoff command must be user-discoverable).
# Hidden via `user-invocable: false` (3 specialized): preflight, autoskill,
# council. These stayed direct-callable because their narrow use cases
# don't fold cleanly into a family-head parameter form.
# Phase 3 deleted the 18 fold-able commands (clarify, fast, docs, retro,
# pause, cancel-workflow, defer, init, update, uninstall, health,
# arch-health, quality, forensics, session-report, weekly-report, tokens,
# mcp-stats) and rerouted all their callers to the family-head + param
# form (covered by K97).
# Hidden specialized commands stay typed-callable — the frontmatter only
# affects the `/`-menu autocomplete.
K94_VISIBLE="do workflow specify plan research implement debug review ship status next setup memory help note thread"
K94_HIDDEN="preflight autoskill council"
K94_VISIBLE_OK=yes
for cmd in $K94_VISIBLE; do
  if [ ! -f "$ROOT/commands/$cmd.md" ]; then K94_VISIBLE_OK=no; break; fi
  if grep -q "^user-invocable: false" "$ROOT/commands/$cmd.md"; then K94_VISIBLE_OK=no; break; fi
done
K94_HIDDEN_OK=yes
for cmd in $K94_HIDDEN; do
  if [ ! -f "$ROOT/commands/$cmd.md" ]; then K94_HIDDEN_OK=no; break; fi
  if ! grep -q "^user-invocable: false" "$ROOT/commands/$cmd.md"; then K94_HIDDEN_OK=no; break; fi
done
# Count check: every commands/*.md should be in exactly one bucket.
K94_TOTAL_CMDS=$(find "$ROOT/commands" -maxdepth 1 -name '*.md' | wc -l | tr -d ' ')
K94_EXPECTED=$(echo "$K94_VISIBLE $K94_HIDDEN" | wc -w | tr -d ' ')
K94_TOTALS_MATCH=$([ "$K94_TOTAL_CMDS" = "$K94_EXPECTED" ] && echo yes || echo no)
if [ "$K94_VISIBLE_OK" = "yes" ] && [ "$K94_HIDDEN_OK" = "yes" ] && [ "$K94_TOTALS_MATCH" = "yes" ]; then
  pass "K94: command-surface stratification (15 visible, 4 specialized hidden via user-invocable:false, totals match disk inventory)"
else
  fail "K94: stratification drift — visible_ok=$K94_VISIBLE_OK hidden_ok=$K94_HIDDEN_OK totals_match=$K94_TOTALS_MATCH (disk=$K94_TOTAL_CMDS expected=$K94_EXPECTED)"
fi

# K95: Phase-2 parameter routing contract.
# Validates that family-head commands (workflow, review, debug, status,
# note, setup) declare routing tables that delegate to the right
# workflows/ file. Drift this guards against: a command's --mode/--focus/
# --report flag silently pointing at a missing or renamed workflow file.
# Each pairing is encoded as "command|flag|workflow_path" on one line.
K95_PAIRS=(
  "workflow|--mode=specify|workflows/specify.md"
  "workflow|--mode=plan|workflows/create-plan.md"
  "workflow|--mode=research|workflows/research-task.md"
  "workflow|--mode=implement|workflows/quick-implement.md"
  "workflow|--mode=clarify|workflows/clarify-task.md"
  "workflow|--mode=fast|workflows/fast.md"
  "workflow|--mode=docs|workflows/docs-extraction.md"
  "workflow|--pause|workflows/pause-work.md"
  "workflow|--retro|workflows/lesson-extraction.md"
  "review|--focus=arch|workflows/arch-health-scan.md"
  "review|--focus=quality|workflows/quality-gates.md"
  "debug|--mode=forensics|workflows/forensics.md"
  "status|--report=session|workflows/session-report.md"
  "status|--report=weekly|workflows/weekly-report.md"
  "status|--stats=tokens|workflows/tokens.md"
  "status|--stats=mcp|workflows/mcp-stats.md"
  "status|--stats=hooks|hook-cost-estimate"
  "status|--health|workflows/health.md"
  "note|--defer|workflows/defer.md"
  "setup|--init|workflows/project-init.md"
  "setup|--update|workflows/update.md"
  "setup|--uninstall|workflows/uninstall.md"
  "setup|--health|workflows/health.md"
)
K95_OK=yes
K95_FAIL_PAIR=""
for pair in "${K95_PAIRS[@]}"; do
  cmd="${pair%%|*}"
  rest="${pair#*|}"
  flag="${rest%%|*}"
  workflow="${rest#*|}"
  file="$ROOT/commands/$cmd.md"
  if grep -q -F -- "$flag" "$file" 2>/dev/null && grep -q -F -- "$workflow" "$file" 2>/dev/null; then
    continue
  fi
  K95_OK=no
  K95_FAIL_PAIR="$K95_FAIL_PAIR $cmd[$flag→$workflow]"
done
if [ "$K95_OK" = "yes" ]; then
  pass "K95: parameter routing contract (6 family heads, ${#K95_PAIRS[@]} (flag → workflow) pairings all resolve)"
else
  fail "K95: routing drift —$K95_FAIL_PAIR"
fi

# K96: workflow file existence — verify every K95-referenced workflow
# actually exists on disk. K95 checks that the command body MENTIONS the
# workflow file; K96 checks the file is not dangling. Catches: someone
# renames workflows/forensics.md → workflows/post-mortem.md and forgets
# to update commands/debug.md's routing table.
K96_OK=yes
K96_MISSING=""
for pair in "${K95_PAIRS[@]}"; do
  workflow="${pair##*|}"
  # Skip non-file routes (e.g., "hook-cost-estimate" CLI reference)
  case "$workflow" in
    workflows/*) ;;
    *) continue ;;
  esac
  if [ ! -f "$ROOT/$workflow" ]; then
    K96_OK=no
    K96_MISSING="$K96_MISSING $workflow"
  fi
done
if [ "$K96_OK" = "yes" ]; then
  pass "K96: workflow file existence (every K95 routing target exists on disk)"
else
  fail "K96: dangling routes —$K96_MISSING"
fi

# K97: stale-reference scan in contract files.
# Every /devt:<name> reference in commands/, workflows/, agents/, skills/
# must resolve to a file at commands/<name>.md. Catches typos, missing
# files after a rename, and references to commands deleted without
# updating callers. Scope is the contract layer ONLY — README and docs
# may use meta-syntactic placeholders like /devt:<command-name> which
# are documentation literals, not real references.
K97_EXISTS=$(ls "$ROOT"/commands/*.md 2>/dev/null | sed -E 's|^.*/commands/||; s|\.md$||' | sort -u)
# Exclude commands/help.md from the scan — the help body intentionally
# documents the Phase-3 renames (e.g., "/devt:init → /devt:setup --init")
# as a guide for users with muscle memory; those refs to deleted commands
# are pedagogical and would otherwise be false positives.
K97_REFS=$( (find "$ROOT/commands" "$ROOT/workflows" "$ROOT/agents" "$ROOT/skills" -name '*.md' -not -path "*/commands/help.md" 2>/dev/null | xargs grep -hoE '/devt:[a-z][a-z0-9-]*' 2>/dev/null || true) | sed 's|^/devt:||' | sort -u )
# Subcommand-only patterns (/devt:memory promote, /devt:note --defer, etc.) — strip the subcommand,
# but our regex already stops at non-alphanumerics so the base name is captured.
# Allowlist: known non-command refs that appear in docs/protocol descriptions.
K97_ALLOWLIST="review-parallel command-name"
K97_STALE=""
for ref in $K97_REFS; do
  if echo "$K97_EXISTS" | grep -qx "$ref"; then continue; fi
  skip=no
  for w in $K97_ALLOWLIST; do
    if [ "$ref" = "$w" ]; then skip=yes; break; fi
  done
  [ "$skip" = "yes" ] && continue
  K97_STALE="$K97_STALE $ref"
done
if [ -z "$K97_STALE" ]; then
  pass "K97: stale-reference scan (every /devt:<name> in contract files resolves to commands/<name>.md)"
else
  fail "K97: stale refs —$K97_STALE"
fi

# K98: do.md ↔ devt-coordinator.md routing table parity.
# The two routing tables are documented as mirrors. K98 enforces both
# row count parity AND row-by-row "Route to" column parity. Catches the
# class where someone updates one router but forgets the other (the
# drift note already warns about this). Uses temp files instead of
# process substitution to play nice with `set -euo pipefail`.
K98_DO_TMP=$(mktemp)
K98_DC_TMP=$(mktemp)
awk '/^\| If the prompt/{seen=1; next} seen && /^\|/ && $0 !~ /^\|[ ]*---/{
  n=split($0, a, "|"); if(n>=3){ gsub(/^[ \t`]+|[ \t`]+$/, "", a[3]); if(length(a[3]) > 0) print a[3] }
}' "$ROOT/workflows/do.md" | sort > "$K98_DO_TMP"
awk '/^\| If the prompt/{seen=1; next} seen && /^\|/ && $0 !~ /^\|[ ]*---/{
  n=split($0, a, "|"); if(n>=3){ gsub(/^[ \t`]+|[ \t`]+$/, "", a[3]); if(length(a[3]) > 0) print a[3] }
}' "$ROOT/agents/devt-coordinator.md" | sort > "$K98_DC_TMP"
K98_DO_COUNT=$(wc -l < "$K98_DO_TMP" | tr -d ' ')
K98_DC_COUNT=$(wc -l < "$K98_DC_TMP" | tr -d ' ')
K98_DIFF=$(diff "$K98_DO_TMP" "$K98_DC_TMP" 2>/dev/null | head -10 || true)
rm -f "$K98_DO_TMP" "$K98_DC_TMP"
if [ "$K98_DO_COUNT" = "$K98_DC_COUNT" ] && [ -z "$K98_DIFF" ]; then
  pass "K98: router parity ($K98_DO_COUNT routes match between workflows/do.md and agents/devt-coordinator.md)"
else
  fail "K98: router drift — do.md=$K98_DO_COUNT routes, devt-coordinator.md=$K98_DC_COUNT routes; diff lines: $K98_DIFF"
fi

# K99: workflow orphan detection.
# Every workflows/*.md file should be reachable from SOMEWHERE: either as
# a command @-ref / explicit Read, or as an internal cross-workflow route,
# or as a subcommand-routed workflow (e.g., workflows/memory-promote.md is
# invoked via /devt:memory promote, not a direct @-ref).
# Allowlist: workflows that are intentionally subcommand-routed or
# internal-only (no command points at them directly).
K99_ALLOWLIST="code-review-parallel memory-init memory-promote memory-reject"
K99_ORPHANS=$(node -e '
const fs = require("fs");
const path = require("path");
const root = process.argv[1];
const wfs = fs.readdirSync(path.join(root, "workflows"))
  .filter(f => f.endsWith(".md"))
  .map(f => "workflows/" + f);
const referenced = new Set();
for (const dir of ["commands", "workflows", "agents", "skills"]) {
  const dirPath = path.join(root, dir);
  if (!fs.existsSync(dirPath)) continue;
  function walk(d) {
    for (const e of fs.readdirSync(d, { withFileTypes: true })) {
      const full = path.join(d, e.name);
      if (e.isDirectory()) walk(full);
      else if (e.isFile() && e.name.endsWith(".md")) {
        const body = fs.readFileSync(full, "utf8");
        const matches = body.match(/workflows\/[a-z][a-z0-9.-]*\.md/g) || [];
        matches.forEach(m => referenced.add(m));
      }
    }
  }
  walk(dirPath);
}
const allowlist = process.argv[2].split(" ").filter(Boolean);
const orphans = wfs.filter(w => {
  if (referenced.has(w)) return false;
  const base = w.replace(/^workflows\//, "").replace(/\.md$/, "");
  return !allowlist.includes(base);
});
process.stdout.write(orphans.join(" "));
' "$ROOT" "$K99_ALLOWLIST")
if [ -z "$K99_ORPHANS" ]; then
  TOTAL_WFS=$(ls "$ROOT"/workflows/*.md 2>/dev/null | wc -l | tr -d ' ')
  pass "K99: workflow orphan check ($TOTAL_WFS workflows reachable; allowlist for subcommand routes: $K99_ALLOWLIST)"
else
  fail "K99: orphan workflows — $K99_ORPHANS"
fi

# K100: runtime stale-reference scan in hooks/, bin/, templates/.
# Every /devt:<name> reference in runtime files (.sh, .cjs, .js, .py, .md
# under hooks/+bin/+templates/) must resolve to an existing commands/<name>.md.
# K97 covers contract files (commands/workflows/agents/skills); K100 closes
# the runtime layer where hooks emit user-facing prompts, bin modules emit
# error messages, and templates ship to user projects on /devt:setup --init.
# Drift class: a hook or CLI error message references a deleted command,
# leaving users with stale "Run /devt:<deleted>" advice that fails.
K100_EXISTS=$(ls "$ROOT"/commands/*.md 2>/dev/null | sed -E 's|^.*/commands/||; s|\.md$||' | sort -u)
K100_REFS=$( (find "$ROOT/hooks" "$ROOT/bin" "$ROOT/templates" -type f \( -name '*.sh' -o -name '*.cjs' -o -name '*.js' -o -name '*.py' -o -name '*.md' \) 2>/dev/null | xargs grep -hoE '/devt:[a-z][a-z0-9-]*' 2>/dev/null || true) | sed 's|^/devt:||' | sort -u )
K100_ALLOWLIST="review-parallel command-name"
K100_STALE=""
for ref in $K100_REFS; do
  if echo "$K100_EXISTS" | grep -qx "$ref"; then continue; fi
  skip=no
  for w in $K100_ALLOWLIST; do
    if [ "$ref" = "$w" ]; then skip=yes; break; fi
  done
  [ "$skip" = "yes" ] && continue
  K100_STALE="$K100_STALE $ref"
done
if [ -z "$K100_STALE" ]; then
  pass "K100: runtime stale-reference scan (every /devt:<name> in hooks/+bin/+templates/ resolves to commands/<name>.md)"
else
  fail "K100: runtime stale refs —$K100_STALE"
fi

# K101: CLAUDE.md size budget.
# CLAUDE.md is loaded into every session AND every sub-agent dispatch
# (it's ~94% of the governing_rules block per measurement). Phase 6
# slimmed it from 35,699 bytes to 25,048 by moving the verbose CLI
# reference to docs/INTERNALS.md::Development CLI Reference. K101 enforces
# a 28,000-byte cap to prevent regrowth — that's the Phase 6 result + ~12%
# headroom for natural maintenance. Drift class: large reference blocks
# accumulating in CLAUDE.md instead of docs/INTERNALS.md.
K101_BUDGET=28000
K101_SIZE=$(wc -c < "$ROOT/CLAUDE.md" | tr -d ' ')
if [ "$K101_SIZE" -le "$K101_BUDGET" ]; then
  pass "K101: CLAUDE.md size budget (${K101_SIZE} bytes ≤ ${K101_BUDGET} cap; move reference material to docs/INTERNALS.md if growing)"
else
  fail "K101: CLAUDE.md exceeds size budget — ${K101_SIZE} bytes > ${K101_BUDGET} cap. Move reference material to docs/INTERNALS.md per CC best-practices (every byte costs per-session AND per-dispatch token budget)."
fi

# K102: inline_guardrails size budget.
# init.cjs::INLINE_GUARDRAILS injects golden-rules.md + engineering-principles.md
# + generative-debt-checklist.md into <guardrails_inline> on every
# programmer/code-reviewer dispatch. Phase 10 trimmed golden-rules.md by
# moving "Common violation" examples to docs/GUARDRAILS-REFERENCE.md
# (23,646 bytes total). K102 enforces a 27,000-byte cap (Phase 10 result
# + ~14% headroom for natural rule maintenance). Drift class: detailed
# pedagogy accumulating in guardrails/ instead of docs/GUARDRAILS-REFERENCE.md.
K102_BUDGET=27000
K102_TOTAL=0
for g in golden-rules.md engineering-principles.md generative-debt-checklist.md; do
  if [ -f "$ROOT/guardrails/$g" ]; then
    K102_TOTAL=$((K102_TOTAL + $(wc -c < "$ROOT/guardrails/$g" | tr -d ' ')))
  fi
done
if [ "$K102_TOTAL" -le "$K102_BUDGET" ]; then
  pass "K102: inline_guardrails size budget (${K102_TOTAL} bytes ≤ ${K102_BUDGET} cap; move violation examples to docs/GUARDRAILS-REFERENCE.md if growing)"
else
  fail "K102: inline_guardrails exceed budget — ${K102_TOTAL} bytes > ${K102_BUDGET} cap. Move pedagogy / examples to docs/GUARDRAILS-REFERENCE.md per Phase 10 pattern."
fi

# K103: workflow_type registry 4-way parity.
# Four surfaces independently declare workflow_type values:
#   S1 — state.cjs::VALID_WORKFLOW_TYPES (the canonical registry)
#   S2 — workflows/next.md routing table (resume command per type)
#   S3 — workflows/status.md routing table (resume guidance per type)
#   S4 — workflow bodies that actually set workflow_type via `state update`
# Drift between them ships UX bugs: status.md routing drift went undetected
# for weeks until a manual audit caught 4 missing rows
# (dev/debug/retro/arch_health_scan). Drift class: silent registry/router divergence.
K103_VALID=$(awk '/VALID_WORKFLOW_TYPES = new Set/,/\]\);/' "$ROOT/bin/modules/state.cjs" \
  | grep -oE '"[a-z_]+"' | sed 's/"//g' | sort -u)
K103_NEXT=$(awk '/^\| `workflow_type` \|/{flag=1; next} flag && /^\|/' "$ROOT/workflows/next.md" \
  | grep -oE '`[a-z_]+`' | sed 's/`//g' | sort -u)
K103_STATUS=$(grep -oE "workflow_type=[a-z_]+" "$ROOT/workflows/status.md" \
  | sed 's/workflow_type=//' | sort -u)
K103_BODY=$(grep -hE 'state update.*workflow_type=' "$ROOT/workflows/"*.md 2>/dev/null \
  | grep -oE 'workflow_type=[a-z_]+' | sed 's/workflow_type=//' | sort -u)
K103_ERRORS=""
# Empty extractions usually mean the regex broke (file format changed).
[ -z "$K103_VALID" ]  && K103_ERRORS="$K103_ERRORS extraction_empty:S1_VALID;"
[ -z "$K103_NEXT" ]   && K103_ERRORS="$K103_ERRORS extraction_empty:S2_NEXT;"
[ -z "$K103_STATUS" ] && K103_ERRORS="$K103_ERRORS extraction_empty:S3_STATUS;"
[ -z "$K103_BODY" ]   && K103_ERRORS="$K103_ERRORS extraction_empty:S4_BODY;"
# `|| true` defuses set -e + pipefail when comm produces empty output (clean
# state). `grep -v '^$'` exits 1 on no matches; under pipefail that kills the
# whole script before the gate can report its verdict.
# Check A: every VALID type must have a next.md routing entry
K103_MISS_NEXT=$(comm -23 <(echo "$K103_VALID") <(echo "$K103_NEXT") | grep -v '^$' | tr '\n' ',' | sed 's/,$//' || true)
[ -n "$K103_MISS_NEXT" ] && K103_ERRORS="$K103_ERRORS missing_in_next.md=[$K103_MISS_NEXT];"
# Check B: every VALID type must have a status.md routing entry
K103_MISS_STATUS=$(comm -23 <(echo "$K103_VALID") <(echo "$K103_STATUS") | grep -v '^$' | tr '\n' ',' | sed 's/,$//' || true)
[ -n "$K103_MISS_STATUS" ] && K103_ERRORS="$K103_ERRORS missing_in_status.md=[$K103_MISS_STATUS];"
# Check C: no workflow body sets an invalid (unregistered) workflow_type
K103_INVALID_BODY=$(comm -23 <(echo "$K103_BODY") <(echo "$K103_VALID") | grep -v '^$' | tr '\n' ',' | sed 's/,$//' || true)
[ -n "$K103_INVALID_BODY" ] && K103_ERRORS="$K103_ERRORS bodies_set_invalid_types=[$K103_INVALID_BODY];"
if [ -z "$K103_ERRORS" ]; then
  pass "K103: workflow_type registry 4-way parity (state.cjs::VALID ↔ next.md ↔ status.md ↔ bodies)"
else
  fail "K103: workflow_type drift —$K103_ERRORS Add missing routing rows to next.md/status.md, or update state.cjs::VALID_WORKFLOW_TYPES."
fi

# K104: dispatch warnings CLI surface (raw_dispatch telemetry analytics).
# Hooks write .devt/state/dispatch-warnings.jsonl on raw_dispatch incidents
# (workflow envelope absent on Task(devt:* …)). K104 validates the analytics
# CLI handles: (a) default summary shape; (b) --raw + --limit truncation;
# (c) --by-source aggregation; (d) graceful missing-file response; (e) export.
K104_TMP=$(mktemp -d)
mkdir -p "$K104_TMP/.devt/state"
# Fixture: 3 entries spanning 2 sources + 2 agents
cat > "$K104_TMP/.devt/state/dispatch-warnings.jsonl" <<'WARNFIX'
{"ts":"2026-06-01T10:00:00.000Z","source":"raw_dispatch","agent":"devt:code-reviewer","prompt_bytes":18,"prompt_preview":"first"}
{"ts":"2026-06-01T11:00:00.000Z","source":"raw_dispatch","agent":"devt:programmer","prompt_bytes":20,"prompt_preview":"second"}
{"ts":"2026-06-01T12:00:00.000Z","source":"task_output_bytes","agent":"devt:code-reviewer","prompt_bytes":99,"prompt_preview":"third"}
WARNFIX
K104_DEFAULT=$(cd "$K104_TMP" && node "$CLI" dispatch warnings 2>/dev/null)
K104_TOTAL=$(echo "$K104_DEFAULT" | jq -r '.total' 2>/dev/null)
K104_HAS_SPAN=$(echo "$K104_DEFAULT" | jq -r '.span | type == "object"' 2>/dev/null)
K104_HAS_BY_SOURCE=$(echo "$K104_DEFAULT" | jq -r '.by_source | type == "object"' 2>/dev/null)
K104_HAS_TOP_AGENTS=$(echo "$K104_DEFAULT" | jq -r '.top_agents | type == "object"' 2>/dev/null)
K104_HAS_RECENT=$(echo "$K104_DEFAULT" | jq -r '.recent | type == "array"' 2>/dev/null)
K104_RAW=$(cd "$K104_TMP" && node "$CLI" dispatch warnings --raw --limit=2 2>/dev/null)
K104_RAW_LEN=$(echo "$K104_RAW" | jq -r '.entries | length' 2>/dev/null)
K104_BY_SRC=$(cd "$K104_TMP" && node "$CLI" dispatch warnings --by-source 2>/dev/null)
K104_BY_SRC_RAW=$(echo "$K104_BY_SRC" | jq -r '.counts.raw_dispatch' 2>/dev/null)
K104_BY_SRC_TOB=$(echo "$K104_BY_SRC" | jq -r '.counts.task_output_bytes' 2>/dev/null)
# Empty-file fixture for graceful-missing test
K104_EMPTY=$(mktemp -d)
K104_MISSING=$(cd "$K104_EMPTY" && node "$CLI" dispatch warnings 2>/dev/null)
K104_MISS_EXISTS=$(echo "$K104_MISSING" | jq -r '.exists' 2>/dev/null)
K104_EXPORT_OK=$(node -e "console.log(typeof require('$ROOT/bin/modules/dispatch.cjs').cmdWarnings === 'function')")
# Input validation: invalid --since / --limit reject with exit 2 + error on
# stderr. Prior behavior: --since=garbage silently filtered everything out
# (string comparison treats "garbage" > "2026-..."); --limit=-3 returned an
# empty-array slice — both wrong-without-error UX failures.
# `set +eo pipefail` inside each subshell disables BOTH errexit and pipefail
# locally — set +e alone wasn't enough because pipefail on `node | grep` still
# propagates node's exit 2 to the pipeline's exit, the subshell exits 2, and
# the parent's set -e kills the script before reaching subsequent gates.
K104_BAD_SINCE_EXIT=$(set +eo pipefail; cd "$K104_TMP"; node "$CLI" dispatch warnings --since=garbage >/dev/null 2>&1; echo $?)
K104_BAD_SINCE_HAS_ERR=$(set +eo pipefail; cd "$K104_TMP"; node "$CLI" dispatch warnings --since=garbage 2>&1 1>/dev/null | grep -c "invalid --since")
K104_BAD_LIMIT_EXIT=$(set +eo pipefail; cd "$K104_TMP"; node "$CLI" dispatch warnings --raw --limit=-3 >/dev/null 2>&1; echo $?)
K104_BAD_LIMIT_HAS_ERR=$(set +eo pipefail; cd "$K104_TMP"; node "$CLI" dispatch warnings --raw --limit=-3 2>&1 1>/dev/null | grep -c "invalid --limit")
K104_BAD_LIMIT_ZERO_EXIT=$(set +eo pipefail; cd "$K104_TMP"; node "$CLI" dispatch warnings --raw --limit=0 >/dev/null 2>&1; echo $?)
rm -rf "$K104_TMP" "$K104_EMPTY"
if [ "$K104_TOTAL" = "3" ] \
   && [ "$K104_HAS_SPAN" = "true" ] \
   && [ "$K104_HAS_BY_SOURCE" = "true" ] \
   && [ "$K104_HAS_TOP_AGENTS" = "true" ] \
   && [ "$K104_HAS_RECENT" = "true" ] \
   && [ "$K104_RAW_LEN" = "2" ] \
   && [ "$K104_BY_SRC_RAW" = "2" ] \
   && [ "$K104_BY_SRC_TOB" = "1" ] \
   && [ "$K104_MISS_EXISTS" = "false" ] \
   && [ "$K104_EXPORT_OK" = "true" ] \
   && [ "$K104_BAD_SINCE_EXIT" = "2" ] \
   && [ "$K104_BAD_SINCE_HAS_ERR" = "1" ] \
   && [ "$K104_BAD_LIMIT_EXIT" = "2" ] \
   && [ "$K104_BAD_LIMIT_HAS_ERR" = "1" ] \
   && [ "$K104_BAD_LIMIT_ZERO_EXIT" = "2" ]; then
  pass "K104: dispatch warnings CLI surface (happy-path JSON shapes + input validation rejects invalid --since/--limit with exit 2 + stderr message)"
else
  fail "K104: warnings mismatch — total=$K104_TOTAL span=$K104_HAS_SPAN by_source=$K104_HAS_BY_SOURCE top_agents=$K104_HAS_TOP_AGENTS recent=$K104_HAS_RECENT raw_len=$K104_RAW_LEN by_src_raw=$K104_BY_SRC_RAW by_src_tob=$K104_BY_SRC_TOB miss_exists=$K104_MISS_EXISTS export=$K104_EXPORT_OK bad_since_exit=$K104_BAD_SINCE_EXIT bad_since_err=$K104_BAD_SINCE_HAS_ERR bad_limit_exit=$K104_BAD_LIMIT_EXIT bad_limit_err=$K104_BAD_LIMIT_HAS_ERR bad_limit_zero=$K104_BAD_LIMIT_ZERO_EXIT"
fi

# K105: skill description size budget.
# Skill frontmatter `description` is the model's routing-trigger signal —
# included in the Skill tool's catalog prompt every session. CC docs
# advise keeping descriptions short and trigger-focused. Current true max
# (architecture-health-scanner) is 777 bytes; K105 enforces a 950-byte
# cap (~22% headroom over current max). Drift class: skill descriptions
# growing into README territory and burning per-session prompt budget
# across all 17 skills.
#
# YAML-aware extraction (node, not awk) — handles BOTH styles:
#   description: Foo bar baz...        ← inline scalar
#   description: >-                    ← block scalar (folded/literal)
#     Indented body...
# Prior awk-based extractor skipped the inline content (after `next`) and
# counted trailing frontmatter fields instead, undercounting inline-style
# descriptions by ~500–700 bytes — surfaced on Jun 14 audit.
K105_BUDGET=950
K105_OVERFLOW=""
for K105_SF in "$ROOT"/skills/*/SKILL.md; do
  [ -f "$K105_SF" ] || continue
  K105_NAME=$(basename "$(dirname "$K105_SF")")
  K105_BYTES=$(node -e '
const text = require("fs").readFileSync(process.argv[1], "utf8");
const m = text.match(/^---\n([\s\S]*?)\n---/);
if (!m) { console.log(0); process.exit(0); }
const lines = m[1].split("\n");
let desc = "";
let mode = null;
for (const line of lines) {
  if (mode === null) {
    if (/^description:\s*[|>][-+]?\s*$/.test(line)) { mode = "block"; continue; }
    const inlineMatch = line.match(/^description:\s*(.*)/);
    if (inlineMatch) { desc += inlineMatch[1]; mode = "inline"; continue; }
  } else if (mode === "block") {
    if (/^[a-zA-Z_-]+:/.test(line) && !line.startsWith(" ")) break;
    if (line.startsWith(" ") || line === "") desc += line.replace(/^  /, "") + " ";
  } else if (mode === "inline") {
    if (/^[a-zA-Z_-]+:/.test(line) && !line.startsWith(" ")) break;
    desc += " " + line.trim();
  }
}
console.log(desc.trim().length);
' "$K105_SF")
  if [ "$K105_BYTES" -gt "$K105_BUDGET" ]; then
    K105_OVERFLOW="$K105_OVERFLOW $K105_NAME=${K105_BYTES}b;"
  fi
done
if [ -z "$K105_OVERFLOW" ]; then
  pass "K105: skill description size budget (every SKILL.md description ≤ ${K105_BUDGET} bytes; descriptions are model-routing triggers, not READMEs)"
else
  fail "K105: skill descriptions exceed budget —$K105_OVERFLOW Trim to ≤${K105_BUDGET}b — descriptions go into the Skill tool's per-session catalog and burn prompt budget."
fi

# K106: telemetry CLI input validation (mcp-stats, token-report).
# Prior silent-wrong-result bugs in these telemetry surfaces (companions
# to the dispatch warnings fix in K104):
#   mcp-stats --since=garbage     → exit 0, filter silently no-op'd (NaN > 0 = false)
#   token-report --since=garbage  → same silent no-op pattern
#   token-report --sessions=garbage → exit 0, returned 0 sessions (slice(0, "garbage") → 0)
#   token-report --sessions=-5    → exit 0, returned slice(0, -5) (removed last 5)
# All four now reject with exit 2 + stderr error message. K106 locks the
# rejection contract so future regressions get caught in CI.
# `set +eo pipefail` inside each subshell — required because the expected
# non-zero exits from the CLIs would otherwise propagate through the parent
# script's set -e (same trap K104's input-validation tests had to defuse).
K106_MS_SINCE_EXIT=$(set +eo pipefail; cd "$ROOT"; node "$CLI" mcp-stats --since=garbage >/dev/null 2>&1; echo $?)
K106_MS_SINCE_HAS_ERR=$(set +eo pipefail; cd "$ROOT"; node "$CLI" mcp-stats --since=garbage 2>&1 1>/dev/null | grep -c "invalid --since")
K106_TR_SINCE_EXIT=$(set +eo pipefail; cd "$ROOT"; node "$CLI" token-report --since=garbage >/dev/null 2>&1; echo $?)
K106_TR_SINCE_HAS_ERR=$(set +eo pipefail; cd "$ROOT"; node "$CLI" token-report --since=garbage 2>&1 1>/dev/null | grep -c "invalid --since")
K106_TR_SESS_BAD_EXIT=$(set +eo pipefail; cd "$ROOT"; node "$CLI" token-report --sessions=garbage >/dev/null 2>&1; echo $?)
K106_TR_SESS_BAD_HAS_ERR=$(set +eo pipefail; cd "$ROOT"; node "$CLI" token-report --sessions=garbage 2>&1 1>/dev/null | grep -c "invalid --sessions")
K106_TR_SESS_NEG_EXIT=$(set +eo pipefail; cd "$ROOT"; node "$CLI" token-report --sessions=-5 >/dev/null 2>&1; echo $?)
K106_TR_SESS_ZERO_EXIT=$(set +eo pipefail; cd "$ROOT"; node "$CLI" token-report --sessions=0 >/dev/null 2>&1; echo $?)
if [ "$K106_MS_SINCE_EXIT" = "2" ] \
   && [ "$K106_MS_SINCE_HAS_ERR" = "1" ] \
   && [ "$K106_TR_SINCE_EXIT" = "2" ] \
   && [ "$K106_TR_SINCE_HAS_ERR" = "1" ] \
   && [ "$K106_TR_SESS_BAD_EXIT" = "2" ] \
   && [ "$K106_TR_SESS_BAD_HAS_ERR" = "1" ] \
   && [ "$K106_TR_SESS_NEG_EXIT" = "2" ] \
   && [ "$K106_TR_SESS_ZERO_EXIT" = "2" ]; then
  pass "K106: telemetry CLI input validation (mcp-stats --since, token-report --since/--sessions all reject invalid input with exit 2 + stderr message)"
else
  fail "K106: telemetry CLI validation mismatch — ms_since_exit=$K106_MS_SINCE_EXIT ms_since_err=$K106_MS_SINCE_HAS_ERR tr_since_exit=$K106_TR_SINCE_EXIT tr_since_err=$K106_TR_SINCE_HAS_ERR tr_sess_bad_exit=$K106_TR_SESS_BAD_EXIT tr_sess_bad_err=$K106_TR_SESS_BAD_HAS_ERR tr_sess_neg_exit=$K106_TR_SESS_NEG_EXIT tr_sess_zero_exit=$K106_TR_SESS_ZERO_EXIT"
fi

# K107: cliff detector proportional-response gate (cal #21 F26).
# A field project's F21 falsification test accidentally exposed this: a 112-byte
# probe prompt with a 39-byte reply tripped lowOutput and produced a false
# SendMessage-resume hint. Real cliff hits happen when an agent processes a
# substantial input (envelope blocks alone are >= ~1KB) but returns a stub.
# F26 added a 1000-byte prompt-size gate to lowOutput. K107 locks both halves
# of the contract: trivial prompt → no advisory; substantial prompt → advisory.
K107_TMP=$(mktemp -d)
mkdir -p "$K107_TMP/.devt/state"
# Case 1: trivial prompt (50 bytes) + small reply (10 bytes) → no advisory
K107_TRIVIAL=$(cd "$K107_TMP" && echo '{"tool_name":"Task","tool_input":{"subagent_type":"devt:programmer","prompt":"do a quick thing"},"tool_response":"done"}' | bash "$ROOT/hooks/task-truncation-detector.sh" 2>&1 || true)
# Case 2: substantial prompt (1024 bytes) + small reply (5 bytes) → advisory + record
K107_BIG_PROMPT=$(node -e "process.stdout.write('A'.repeat(1024))")
rm -f "$K107_TMP/.devt/state/dispatch-warnings.jsonl"
K107_SUBSTANTIVE=$(cd "$K107_TMP" && printf '%s' "{\"tool_name\":\"Task\",\"tool_input\":{\"subagent_type\":\"devt:programmer\",\"prompt\":\"$K107_BIG_PROMPT\"},\"tool_response\":\"ok\"}" | bash "$ROOT/hooks/task-truncation-detector.sh" 2>&1 || true)
K107_TRIVIAL_QUIET=no
K107_SUBSTANTIVE_LOUD=no
K107_RECORD_WRITTEN=no
[ -z "$K107_TRIVIAL" ] && K107_TRIVIAL_QUIET=yes
echo "$K107_SUBSTANTIVE" | grep -q "SendMessage-resume\|below LOW threshold" && K107_SUBSTANTIVE_LOUD=yes
[ -s "$K107_TMP/.devt/state/dispatch-warnings.jsonl" ] && tail -1 "$K107_TMP/.devt/state/dispatch-warnings.jsonl" | grep -q '"low_output":true' && K107_RECORD_WRITTEN=yes
rm -rf "$K107_TMP"
if [ "$K107_TRIVIAL_QUIET" = "yes" ] && [ "$K107_SUBSTANTIVE_LOUD" = "yes" ] && [ "$K107_RECORD_WRITTEN" = "yes" ]; then
  pass "K107: cliff detector proportional-response gate (trivial prompt → silent; substantive prompt → advisory + lowOutput record)"
else
  fail "K107: proportional-response gate broken — trivial_quiet=$K107_TRIVIAL_QUIET substantive_loud=$K107_SUBSTANTIVE_LOUD record_written=$K107_RECORD_WRITTEN"
fi

# K108: state check-inherited-edits surfaces uncommitted source files (cal #21 A4).
# A field project's W12 retry inherited a `str | None` type from a prior dead dispatch
# and self-corrected to `AuthScope`. The orchestrator had no programmatic signal that
# files had been modified. detectInheritedSourceEdits surfaces uncommitted git
# state filtered by workflow start mtime so re-dispatching is an informed choice.
# K108 validates the function's response shape against fixtures with three states:
#   (a) clean git repo no workflow active → ok=true, recommendation=clean
#   (b) clean git repo + dirty file mtime>workflow_start → recommendation=review
#   (c) non-git directory → ok=false with clear reason
K108_TMP=$(mktemp -d)
mkdir -p "$K108_TMP/.devt/state"
# Case A: no git → ok=false
K108_NOGIT=$(cd "$K108_TMP" && node "$CLI" state check-inherited-edits 2>/dev/null)
K108_NOGIT_OK=$(echo "$K108_NOGIT" | node -e "let s='';process.stdin.on('data',c=>s+=c);process.stdin.on('end',()=>{try{const o=JSON.parse(s);console.log(o.ok===false?'yes':'no');}catch{console.log('parse-err');}})")
# Case B: git init + workflow.yaml + uncommitted file modified after start → review
(cd "$K108_TMP" && git init -q && git config user.email "a@b.c" && git config user.name "test" && echo "baseline" > tracked.txt && git add tracked.txt && git commit -q -m "baseline" 2>/dev/null) >/dev/null 2>&1
# workflow.yaml with first_created_at set to 1 hour ago
K108_OLD_TS=$(node -e "console.log(new Date(Date.now() - 3600000).toISOString())")
printf 'first_created_at: "%s"\nworkflow_id: "k108-test"\nactive: true\n' "$K108_OLD_TS" > "$K108_TMP/.devt/state/workflow.yaml"
# Modify the tracked file now (mtime > workflow start)
echo "edit" >> "$K108_TMP/tracked.txt"
K108_DIRTY=$(cd "$K108_TMP" && node "$CLI" state check-inherited-edits 2>/dev/null)
K108_DIRTY_REC=$(echo "$K108_DIRTY" | node -e "let s='';process.stdin.on('data',c=>s+=c);process.stdin.on('end',()=>{try{const o=JSON.parse(s);console.log(o.recommendation||'none');}catch{console.log('parse-err');}})")
K108_DIRTY_COUNT=$(echo "$K108_DIRTY" | node -e "let s='';process.stdin.on('data',c=>s+=c);process.stdin.on('end',()=>{try{const o=JSON.parse(s);console.log(o.count_after_workflow_start||0);}catch{console.log('parse-err');}})")
K108_DIRTY_HAS_GUIDANCE=$(echo "$K108_DIRTY" | node -e "let s='';process.stdin.on('data',c=>s+=c);process.stdin.on('end',()=>{try{const o=JSON.parse(s);console.log(typeof o.guidance==='string' && o.guidance.length>10?'yes':'no');}catch{console.log('parse-err');}})")
rm -rf "$K108_TMP"
if [ "$K108_NOGIT_OK" = "yes" ] \
   && [ "$K108_DIRTY_REC" = "review" ] \
   && [ "$K108_DIRTY_COUNT" = "1" ] \
   && [ "$K108_DIRTY_HAS_GUIDANCE" = "yes" ]; then
  pass "K108: state check-inherited-edits (no-git → ok=false; dirty post-workflow-start → recommendation=review + count_after_workflow_start=1 + guidance present)"
else
  fail "K108: check-inherited-edits broken — nogit_ok=$K108_NOGIT_OK dirty_rec=$K108_DIRTY_REC dirty_count=$K108_DIRTY_COUNT dirty_guidance=$K108_DIRTY_HAS_GUIDANCE"
fi

# K109: PostToolUse raw_dispatch return-time hint (cal #21 A2b).
# When dispatch-warnings.jsonl contains raw_dispatch entries within the last
# hour, task-truncation-detector.sh emits a one-line hint in additionalContext
# regardless of whether the current dispatch tripped a cliff. Operator-confirmed
# UX preference from F24 — catch the signal in the act-on-it window.
K109_TMP=$(mktemp -d)
mkdir -p "$K109_TMP/.devt/state"
# Case A: no recent raw_dispatch entries → no hint, no advisory
K109_QUIET=$(cd "$K109_TMP" && echo '{"tool_name":"Task","tool_input":{"subagent_type":"devt:programmer","prompt":"tiny"},"tool_response":"ok"}' | bash "$ROOT/hooks/task-truncation-detector.sh" 2>&1 || true)
# Case B: seed a fresh raw_dispatch entry → hint emits
K109_NOW=$(node -e "console.log(new Date().toISOString())")
echo "{\"ts\":\"$K109_NOW\",\"source\":\"raw_dispatch\",\"agent\":\"devt:code-reviewer\",\"prompt_bytes\":18,\"prompt_preview\":\"k109 seed\"}" > "$K109_TMP/.devt/state/dispatch-warnings.jsonl"
K109_LOUD=$(cd "$K109_TMP" && echo '{"tool_name":"Task","tool_input":{"subagent_type":"devt:programmer","prompt":"tiny"},"tool_response":"ok"}' | bash "$ROOT/hooks/task-truncation-detector.sh" 2>&1 || true)
# Case C: seed an OLD raw_dispatch (2 hours ago) → hint should NOT fire
K109_OLD_TS=$(node -e "console.log(new Date(Date.now() - 7200*1000).toISOString())")
echo "{\"ts\":\"$K109_OLD_TS\",\"source\":\"raw_dispatch\",\"agent\":\"devt:code-reviewer\",\"prompt_bytes\":18,\"prompt_preview\":\"k109 old\"}" > "$K109_TMP/.devt/state/dispatch-warnings.jsonl"
K109_AGED=$(cd "$K109_TMP" && echo '{"tool_name":"Task","tool_input":{"subagent_type":"devt:programmer","prompt":"tiny"},"tool_response":"ok"}' | bash "$ROOT/hooks/task-truncation-detector.sh" 2>&1 || true)
K109_QUIET_OK=$([ -z "$K109_QUIET" ] && echo "yes" || echo "no")
K109_LOUD_OK=$(echo "$K109_LOUD" | /usr/bin/grep -c "raw_dispatch incident" 2>/dev/null || echo 0)
K109_AGED_OK=$([ -z "$K109_AGED" ] && echo "yes" || echo "no")
rm -rf "$K109_TMP"
if [ "$K109_QUIET_OK" = "yes" ] && [ "$K109_LOUD_OK" = "1" ] && [ "$K109_AGED_OK" = "yes" ]; then
  pass "K109: PostToolUse raw_dispatch return-time hint (no recent entries → silent; fresh entry → hint emits; aged entry → silent)"
else
  fail "K109: A2b hint emitter broken — quiet=$K109_QUIET_OK loud_match_count=$K109_LOUD_OK aged_silent=$K109_AGED_OK"
fi

# K110: memory CLI input validation (cal #21 methodology continuation).
# Same silent-wrong-result UX bug class as K106 caught for mcp-stats and
# token-report. memory query/links accepted --limit=garbage|-5|0 and
# --depth=garbage silently — NaN propagated through to the FTS5 query or
# graph traversal producing 0 results or unexpected behavior. K110 locks
# the rejection contract for both subcommands so future input drift in
# the memory CLI surface is caught in CI.
K110_Q_BAD_EXIT=$(set +eo pipefail; node "$CLI" memory query "test" --limit=garbage >/dev/null 2>&1; echo $?)
K110_Q_BAD_HAS_ERR=$(set +eo pipefail; node "$CLI" memory query "test" --limit=garbage 2>&1 1>/dev/null | grep -c "invalid --limit")
K110_Q_NEG_EXIT=$(set +eo pipefail; node "$CLI" memory query "test" --limit=-5 >/dev/null 2>&1; echo $?)
K110_Q_ZERO_EXIT=$(set +eo pipefail; node "$CLI" memory query "test" --limit=0 >/dev/null 2>&1; echo $?)
K110_L_BAD_EXIT=$(set +eo pipefail; node "$CLI" memory links CON-001 --depth=garbage >/dev/null 2>&1; echo $?)
K110_L_BAD_HAS_ERR=$(set +eo pipefail; node "$CLI" memory links CON-001 --depth=garbage 2>&1 1>/dev/null | grep -c "invalid --depth")
K110_L_NEG_EXIT=$(set +eo pipefail; node "$CLI" memory links CON-001 --depth=-2 >/dev/null 2>&1; echo $?)
if [ "$K110_Q_BAD_EXIT" = "2" ] \
   && [ "$K110_Q_BAD_HAS_ERR" = "1" ] \
   && [ "$K110_Q_NEG_EXIT" = "2" ] \
   && [ "$K110_Q_ZERO_EXIT" = "2" ] \
   && [ "$K110_L_BAD_EXIT" = "2" ] \
   && [ "$K110_L_BAD_HAS_ERR" = "1" ] \
   && [ "$K110_L_NEG_EXIT" = "2" ]; then
  pass "K110: memory CLI input validation (memory query --limit + memory links --depth all reject invalid input with exit 2 + stderr message)"
else
  fail "K110: memory CLI validation mismatch — q_bad_exit=$K110_Q_BAD_EXIT q_bad_err=$K110_Q_BAD_HAS_ERR q_neg=$K110_Q_NEG_EXIT q_zero=$K110_Q_ZERO_EXIT l_bad_exit=$K110_L_BAD_EXIT l_bad_err=$K110_L_BAD_HAS_ERR l_neg=$K110_L_NEG_EXIT"
fi

# K111: graphify + preflight CLI input validation (ζ audit continuation).
# Same silent-wrong-result UX bug class. Four flags fixed:
#   preflight generate --budget    → silently kept default on invalid input
#   graphify neighbors --depth     → NaN propagated through getNeighbors
#   graphify neighbors --max-bytes → silent-default-on-invalid
#   graphify symbols-in-files --limit → silent-default-on-invalid
# All now reject with exit 2 + stderr error. K111 locks the rejection
# contract across all 4 flags.
K111_PF_BUDGET_EXIT=$(set +eo pipefail; node "$CLI" preflight generate "test" --budget=garbage >/dev/null 2>&1; echo $?)
K111_PF_BUDGET_HAS_ERR=$(set +eo pipefail; node "$CLI" preflight generate "test" --budget=garbage 2>&1 1>/dev/null | grep -c "invalid --budget")
K111_GN_DEPTH_EXIT=$(set +eo pipefail; node "$CLI" graphify neighbors nonexistent --depth=garbage >/dev/null 2>&1; echo $?)
K111_GN_DEPTH_HAS_ERR=$(set +eo pipefail; node "$CLI" graphify neighbors nonexistent --depth=garbage 2>&1 1>/dev/null | grep -c "invalid --depth")
K111_GN_MB_EXIT=$(set +eo pipefail; node "$CLI" graphify neighbors nonexistent --max-bytes=garbage >/dev/null 2>&1; echo $?)
K111_GN_MB_HAS_ERR=$(set +eo pipefail; node "$CLI" graphify neighbors nonexistent --max-bytes=garbage 2>&1 1>/dev/null | grep -c "invalid --max-bytes")
K111_GS_LIM_EXIT=$(set +eo pipefail; node "$CLI" graphify symbols-in-files "$ROOT/bin/devt-tools.cjs" --limit=garbage >/dev/null 2>&1; echo $?)
K111_GS_LIM_HAS_ERR=$(set +eo pipefail; node "$CLI" graphify symbols-in-files "$ROOT/bin/devt-tools.cjs" --limit=garbage 2>&1 1>/dev/null | grep -c "invalid --limit")
K111_GN_NEG_DEPTH_EXIT=$(set +eo pipefail; node "$CLI" graphify neighbors nonexistent --depth=-5 >/dev/null 2>&1; echo $?)
K111_PF_NEG_BUDGET_EXIT=$(set +eo pipefail; node "$CLI" preflight generate "test" --budget=-1 >/dev/null 2>&1; echo $?)
if [ "$K111_PF_BUDGET_EXIT" = "2" ] \
   && [ "$K111_PF_BUDGET_HAS_ERR" = "1" ] \
   && [ "$K111_GN_DEPTH_EXIT" = "2" ] \
   && [ "$K111_GN_DEPTH_HAS_ERR" = "1" ] \
   && [ "$K111_GN_MB_EXIT" = "2" ] \
   && [ "$K111_GN_MB_HAS_ERR" = "1" ] \
   && [ "$K111_GS_LIM_EXIT" = "2" ] \
   && [ "$K111_GS_LIM_HAS_ERR" = "1" ] \
   && [ "$K111_GN_NEG_DEPTH_EXIT" = "2" ] \
   && [ "$K111_PF_NEG_BUDGET_EXIT" = "2" ]; then
  pass "K111: graphify + preflight CLI input validation (preflight --budget, graphify --depth/--max-bytes/--limit all reject invalid input with exit 2 + stderr message)"
else
  fail "K111: graphify+preflight validation mismatch — pf_bud=$K111_PF_BUDGET_EXIT pf_bud_err=$K111_PF_BUDGET_HAS_ERR gn_depth=$K111_GN_DEPTH_EXIT gn_depth_err=$K111_GN_DEPTH_HAS_ERR gn_mb=$K111_GN_MB_EXIT gn_mb_err=$K111_GN_MB_HAS_ERR gs_lim=$K111_GS_LIM_EXIT gs_lim_err=$K111_GS_LIM_HAS_ERR gn_neg=$K111_GN_NEG_DEPTH_EXIT pf_neg=$K111_PF_NEG_BUDGET_EXIT"
fi

# K112: G1 — UserPromptSubmit session signal push (cal #21 round 5 V6).
# A field project's V6 honest answer revealed A2/A2b/A4 infrastructure works but
# discovery surfaces are too passive for an LLM operator — operators forget
# the CLIs exist when head-down in a workflow. G1 extends the
# workflow-context-injector hook to push session-scoped telemetry counts
# into UserPromptSubmit additionalContext when signals exist; stays silent
# when clean. K112 validates both halves of the contract.
K112_TMP=$(mktemp -d)
mkdir -p "$K112_TMP/.devt/state"
K112_OLD_TS=$(node -e "console.log(new Date(Date.now() - 3600000).toISOString())")
K112_NOW_TS=$(node -e "console.log(new Date().toISOString())")
# Active workflow.yaml — first_created_at set 1h ago. Note: K112 does NOT
# initialize a git repo (the hook's inherited-edit probe fails open on git
# errors, so we only validate the dispatch-warnings half here). K108
# already validates state check-inherited-edits against a real git fixture.
printf 'active: true\nworkflow_id: k112-test\nworkflow_type: dev\nphase: implement\ntier: STANDARD\niteration: 1\ntask: "k112 fixture"\nfirst_created_at: "%s"\n' "$K112_OLD_TS" > "$K112_TMP/.devt/state/workflow.yaml"
# Case A: quiet (no dispatch warnings) → workflow line only
K112_QUIET=$(set +eo pipefail; cd "$K112_TMP" && echo '{}' | bash "$ROOT/hooks/workflow-context-injector.sh" 2>/dev/null) || K112_QUIET=""
K112_QUIET_HAS_WF=$(set +eo pipefail; echo "$K112_QUIET" | /usr/bin/grep -c '\[devt\] STANDARD' 2>/dev/null) || K112_QUIET_HAS_WF=0
K112_QUIET_HAS_SIGNAL=$(set +eo pipefail; echo "$K112_QUIET" | /usr/bin/grep -c 'session signal' 2>/dev/null) || K112_QUIET_HAS_SIGNAL=0
# Case B: loud (seed recent raw_dispatch) → workflow + session signal lines
echo "{\"ts\":\"$K112_NOW_TS\",\"source\":\"raw_dispatch\",\"agent\":\"devt:code-reviewer\",\"prompt_bytes\":18,\"prompt_preview\":\"k112 seed\"}" > "$K112_TMP/.devt/state/dispatch-warnings.jsonl"
K112_LOUD=$(set +eo pipefail; cd "$K112_TMP" && echo '{}' | bash "$ROOT/hooks/workflow-context-injector.sh" 2>/dev/null) || K112_LOUD=""
K112_LOUD_HAS_WF=$(set +eo pipefail; echo "$K112_LOUD" | /usr/bin/grep -c '\[devt\] STANDARD' 2>/dev/null) || K112_LOUD_HAS_WF=0
K112_LOUD_HAS_SIGNAL=$(set +eo pipefail; echo "$K112_LOUD" | /usr/bin/grep -c 'session signal' 2>/dev/null) || K112_LOUD_HAS_SIGNAL=0
K112_LOUD_HAS_RAW=$(set +eo pipefail; echo "$K112_LOUD" | /usr/bin/grep -c 'raw_dispatch' 2>/dev/null) || K112_LOUD_HAS_RAW=0
rm -rf "$K112_TMP"
if [ "$K112_QUIET_HAS_WF" = "1" ] \
   && [ "$K112_QUIET_HAS_SIGNAL" = "0" ] \
   && [ "$K112_LOUD_HAS_WF" = "1" ] \
   && [ "$K112_LOUD_HAS_SIGNAL" = "1" ] \
   && [ "$K112_LOUD_HAS_RAW" = "1" ]; then
  pass "K112: UserPromptSubmit session signal push (quiet workflow → workflow line only; recent raw_dispatch → both workflow + session signal lines including raw_dispatch count)"
else
  fail "K112: G1 hook mismatch — quiet_wf=$K112_QUIET_HAS_WF quiet_sig=$K112_QUIET_HAS_SIGNAL loud_wf=$K112_LOUD_HAS_WF loud_sig=$K112_LOUD_HAS_SIGNAL loud_raw=$K112_LOUD_HAS_RAW"
fi

# K113: G3 — verifier rubric mandates Dispatch warnings acknowledgment section.
