K115_OK=$(set +eo pipefail; echo "$K115_RESULT" | node -e "let s='';process.stdin.on('data',c=>s+=c);process.stdin.on('end',()=>{try{const o=JSON.parse(s);console.log(o.ok===false?'no':'yes');}catch{console.log('parse-err');}})") || K115_OK="parse-err"
K115_MISSING=$(set +eo pipefail; echo "$K115_RESULT" | node -e "let s='';process.stdin.on('data',c=>s+=c);process.stdin.on('end',()=>{try{const o=JSON.parse(s);console.log(o.missing_axes_count||0);}catch{console.log('parse-err');}})") || K115_MISSING="parse-err"
# Happy path: criteria_total matches rubric axis count (7)
printf '{"verdict":"satisfied","status":"VERIFIED","criteria_total":7,"criteria_met":7}\n' > "$K115_TMP/.devt/state/verification.json"
K115_MATCH_RESULT=$(set +eo pipefail; cd "$K115_TMP" && node "$CLI" state assert-verifier-graded-all-axes 2>/dev/null) || K115_MATCH_RESULT=""
K115_MATCH_OK=$(set +eo pipefail; echo "$K115_MATCH_RESULT" | node -e "let s='';process.stdin.on('data',c=>s+=c);process.stdin.on('end',()=>{try{const o=JSON.parse(s);console.log(o.ok===true?'yes':'no');}catch{console.log('parse-err');}})") || K115_MATCH_OK="parse-err"
# Also verify dev workflow_type returns gate-does-not-apply (no axis taxonomy)
printf 'active: true\nworkflow_id: k115-dev\nworkflow_type: dev\nphase: verify\ntier: STANDARD\niteration: 1\ntask: "k115 dev fixture"\nfirst_created_at: "%s"\ncreated_at: "%s"\n' "$K115_OLD_TS" "$K115_OLD_TS" > "$K115_TMP/.devt/state/workflow.yaml"
K115_DEV_RESULT=$(set +eo pipefail; cd "$K115_TMP" && node "$CLI" state assert-verifier-graded-all-axes 2>/dev/null) || K115_DEV_RESULT=""
K115_DEV_OK=$(set +eo pipefail; echo "$K115_DEV_RESULT" | node -e "let s='';process.stdin.on('data',c=>s+=c);process.stdin.on('end',()=>{try{const o=JSON.parse(s);console.log(o.ok===true && /does not use axis taxonomy/.test(o.reason||'')?'yes':'no');}catch{console.log('parse-err');}})") || K115_DEV_OK="parse-err"
rm -rf "$K115_TMP"
if [ "$K115_OK" = "no" ] && [ "$K115_MISSING" = "1" ] && [ "$K115_MATCH_OK" = "yes" ] && [ "$K115_DEV_OK" = "yes" ]; then
  pass "K115: assert-verifier-graded-all-axes catches verifier stopping short (criteria_total=6 vs rubric=7 → ok=false, missing=1); passes on match (criteria_total=7); skips dev workflow (no axis taxonomy)"
else
  fail "K115: walk-all-axes broken — miss_ok_no=$K115_OK miss_count=$K115_MISSING match_ok_yes=$K115_MATCH_OK dev_skip_yes=$K115_DEV_OK"
fi

# K116 (M3): pipefail+grep-c trap auto-detector (CON-003 codification).
# Under `set -euo pipefail`, command substitutions ending in `grep -c` exit
# non-zero when grep finds 0 matches, which kills the substitution silently
# and breaks subsequent smoke gates. Caught 5× during v0.93→v0.94 cycle.
# Scans smoke-test.sh for $(... grep -c ...) patterns lacking the defuser.
# Implemented in node so the gate itself doesn't fall into its own trap.
K116_VIOLATIONS=$(node -e "
  const fs = require('fs');
  const lines = fs.readFileSync('$0', 'utf8').split('\n');
  const violations = [];
  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    // Skip comments and string-literal references to grep -c
    if (/^\s*#/.test(line)) continue;
    if (/^\s*\/\//.test(line)) continue;
    // Skip lines where \$ is escaped (\\\$ in source — literal text, not substitution)
    if (/\\\\\\\$\\(/.test(line)) continue;
    // Skip lines that don't contain a substitution with grep -c
    if (!/\\\$\\(.*grep -c/.test(line)) continue;
    // Defuser anywhere in line: set +e[o] pipefail
    if (/set \+e?o? pipefail/.test(line)) continue;
    // Defuser anywhere in line (after grep -c): '|| true' / '|| echo' / '|| \w+='
    const afterGrepC = line.substring(line.indexOf('grep -c'));
    if (/\\|\\|\\s*(true\\b|echo\\b|\\w+=)/.test(afterGrepC)) continue;
    violations.push((i + 1) + ':' + line.trim().substring(0, 80));
  }
  if (violations.length > 0) {
    console.log('VIOLATIONS:' + violations.length);
    violations.slice(0, 3).forEach(v => console.log('  L' + v));
  } else {
    console.log('CLEAN');
  }
" 2>/dev/null)
if echo "$K116_VIOLATIONS" | /usr/bin/grep -q "^CLEAN$"; then
  pass "K116: pipefail+grep-c trap auto-detector (CON-003) — no undefused \$(... grep -c ...) substitutions"
else
  fail "K116: undefused grep-c substitutions found: $K116_VIOLATIONS"
fi

# K117 (M1): K-gate count auto-validator. Catches the off-by-one drift class
# observed 3× during v0.93→v0.94 (15→16, 17→21, 21→22). Counts actual K-gate
# definitions and verifies README + CLAUDE.md "N-deep" claim + "Kn-Km" range
# upper bound match. Node-based so the gate doesn't trip CON-003.
K117_CHECK=$(node -e "
  const fs = require('fs');
  const smoke = fs.readFileSync('$0', 'utf8');
  const readme = fs.readFileSync('$ROOT/README.md', 'utf8');
  const claude = fs.readFileSync('$ROOT/CLAUDE.md', 'utf8');
  // Count K94+ gate definitions in smoke (K94-K99 + any 3-digit K100+).
  // Accepts `# K94:` and `# K94 (anything):` so gate authors can add hints
  // without breaking the count.
  const gateMatches = smoke.match(/^# K(9[4-9]|[1-9][0-9][0-9])[a-z]?(\s+\(.*?\))?:/gm) || [];
  const actual = gateMatches.length;
  // Highest K number
  const nums = gateMatches.map(m => parseInt(m.match(/K(\d+)/)[1], 10));
  const top = Math.max.apply(null, nums);
  // Parse README + CLAUDE.md claims
  const readmeDeep = (readme.match(/(\d+)-deep/) || [0,'0'])[1];
  const readmeRange = (readme.match(/K94[-–]K(\d+)/) || [0,'0'])[1];
  const claudeDeep = (claude.match(/(\d+)-deep/) || [0,'0'])[1];
  const claudeRange = (claude.match(/K94[-–]K(\d+)/) || [0,'0'])[1];
  const failures = [];
  if (parseInt(readmeDeep,10) !== actual) failures.push('README \"' + readmeDeep + '-deep\" != actual ' + actual);
  if (parseInt(readmeRange,10) !== top) failures.push('README \"K94-K' + readmeRange + '\" != actual top K' + top);
  if (parseInt(claudeDeep,10) !== actual) failures.push('CLAUDE \"' + claudeDeep + '-deep\" != actual ' + actual);
  if (parseInt(claudeRange,10) !== top) failures.push('CLAUDE \"K94-K' + claudeRange + '\" != actual top K' + top);
  console.log(failures.length === 0 ? 'OK:actual=' + actual + ':top=K' + top : 'FAIL:' + failures.join('; '));
" 2>/dev/null)
if echo "$K117_CHECK" | /usr/bin/grep -q "^OK:"; then
  pass "K117: K-gate count auto-validator (smoke gate count matches README + CLAUDE.md \"N-deep\" + \"K94-K[top]\" claims; CON-001 applied to docs)"
else
  fail "K117: doc count drift — $K117_CHECK"
fi

# K118 (M2): CHANGELOG [Unreleased] coverage for code surface commits.
# Catches the failure mode where bin/ hooks/ workflows/ .claude-plugin/
# changed since the last tag but [Unreleased] is empty (or has only the
# anchor heading). Pre-commit version of the existing CHANGELOG-coverage
# gate; this one validates intent BEFORE the [version] rename.
K118_CHECK=$(node -e "
  const fs = require('fs');
  const { execSync } = require('child_process');
  let lastTag;
  try { lastTag = execSync('git describe --tags --abbrev=0 2>/dev/null', {encoding:'utf8'}).trim(); }
  catch { console.log('SKIP:no-tags'); process.exit(0); }
  if (!lastTag) { console.log('SKIP:no-tag-resolved'); process.exit(0); }
  // Count code-surface commits since last tag
  let codeCommits;
  try {
    const out = execSync('git log --pretty=format:%H ' + lastTag + '..HEAD -- bin/ hooks/ workflows/ .claude-plugin/ 2>/dev/null', {encoding:'utf8'});
    codeCommits = out.split('\n').filter(Boolean).length;
  } catch { codeCommits = 0; }
  // Read [Unreleased] OR the version section immediately above the previous
  // tag — both are valid resting places for content covering code commits
  // since the last tag. Gate accepts whichever is non-empty.
  const changelog = fs.readFileSync('$ROOT/CHANGELOG.md', 'utf8');
  const unreleasedMatch = changelog.match(/^## \[Unreleased\]\s*\n([\s\S]*?)(?=^## \[)/m);
  const unreleasedBody = unreleasedMatch ? unreleasedMatch[1].trim() : '';
  // Find sections between [Unreleased] and [lastTag] — those describe
  // changes post-lastTag (e.g., a freshly-renamed [next-version]).
  const tagWithoutV = lastTag.replace(/^v/, '');
  const postTagSections = changelog.match(new RegExp('## \\\\[Unreleased\\\\][\\\\s\\\\S]*?(?=## \\\\[' + tagWithoutV.replace(/\\./g, '\\\\.') + '\\\\])', 'm'));
  const postTagBody = postTagSections ? postTagSections[0].replace(/^## \\\\[Unreleased\\\\]\\\\s*\\\\n/m, '').trim() : '';
  const hasCoverage = unreleasedBody.length > 0 || postTagBody.length > 50; // > 50 to skip just-version-headers
  if (codeCommits > 0 && !hasCoverage) {
    console.log('FAIL:' + codeCommits + '-code-commit(s)-since-' + lastTag + '-but-no-Unreleased-or-post-tag-content');
  } else if (codeCommits === 0 && !hasCoverage) {
    console.log('OK:no-code-commits-empty-fine');
  } else {
    console.log('OK:' + codeCommits + '-code-commits-coverage-' + (unreleasedBody.length || postTagBody.length) + '-bytes');
  }
" 2>/dev/null)
if echo "$K118_CHECK" | /usr/bin/grep -qE "^(OK|SKIP):"; then
  pass "K118: CHANGELOG [Unreleased] coverage (code-surface commits since last tag → [Unreleased] non-empty)"
else
  fail "K118: $K118_CHECK"
fi

# K119 (M4): compiled-region EDIT-SOURCE marker presence. Each
# <!-- BEGIN dispatch:agent:workflow_id --> in workflows/*.md MUST be
# immediately followed by an <!-- EDIT-SOURCE: templates/dispatch/... -->
# marker. Field signal: during v0.94.0 doc-sync I edited workflows/code-review.md
# inside a compiled region twice before realizing it was managed by dispatch
# compile --write. The marker eliminates this class of architectural-coupling
# confusion. Updates to dispatch.cjs::cmdCompile to emit the marker are part
# of the same commit.
K119_CHECK=$(node -e "
  const fs = require('fs');
  const path = require('path');
  const dir = '$ROOT/workflows';
  const violations = [];
  for (const f of fs.readdirSync(dir)) {
    if (!f.endsWith('.md')) continue;
    const content = fs.readFileSync(path.join(dir, f), 'utf8');
    const lines = content.split('\n');
    for (let i = 0; i < lines.length; i++) {
      const beginMatch = lines[i].match(/^<!-- BEGIN dispatch:([\w-]+):([\w-]+) -->/);
      if (!beginMatch) continue;
      const next = lines[i + 1] || '';
      if (!next.match(/^<!-- EDIT-SOURCE: templates\/dispatch\/(envelopes|blocks)\//)) {
        violations.push(f + ':L' + (i + 1) + ':' + beginMatch[1] + ':' + beginMatch[2]);
      }
    }
  }
  console.log(violations.length === 0 ? 'CLEAN' : 'VIOLATIONS:' + violations.length + ':' + violations.slice(0, 3).join(','));
" 2>/dev/null)
if echo "$K119_CHECK" | /usr/bin/grep -q "^CLEAN$"; then
  pass "K119: compiled-region EDIT-SOURCE markers present (every <!-- BEGIN dispatch:... --> in workflows/*.md is followed by <!-- EDIT-SOURCE: templates/... -->)"
else
  fail "K119: missing EDIT-SOURCE markers — $K119_CHECK"
fi

# K120 (cal #23 8E): workflow_id_history trim respects archive_runs cap.
# Field session evidence: history grew to 234 entries while archive_runs=5
# because the self-healing logic appended ids but never bounded. K120 verifies
# the trim runs on state update and bounds the history to archive_runs+1
# (the +1 preserves the original_workflow_id anchor for cross-rotation trace
# attribution). Fixture: write a workflow.yaml with 50-entry history, call
# state update, expect length ≤ 6 (archive_runs default 5 + 1 anchor).
K120_TMP=$(mktemp -d)
mkdir -p "$K120_TMP/.devt/state"
# Build a 10-entry history with the serialization format the YAML parser
# round-trips correctly (JSON-stringified array inside double-quoted string,
# with backslash-escaped inner quotes — matches serializeSimpleYaml output).
K120_HIST_VAL=$(node -e "console.log(JSON.stringify(JSON.stringify(Array.from({length: 10}, (_, i) => 'k120-id-' + String(i).padStart(2, '0')))));")
printf 'active: true\nworkflow_id: "k120-id-09"\noriginal_workflow_id: "k120-id-00"\nworkflow_type: dev\nphase: implement\ntier: STANDARD\nfirst_created_at: "2026-06-01T00:00:00.000Z"\ncreated_at: "2026-06-01T00:00:00.000Z"\nworkflow_id_history: %s\n' "$K120_HIST_VAL" > "$K120_TMP/.devt/state/workflow.yaml"
# Defensive parse: state read returns history as array OR JSON-string depending on path
K120_BEFORE=$(set +eo pipefail; cd "$K120_TMP" && node "$CLI" state read 2>/dev/null | node -e "let s='';process.stdin.on('data',c=>s+=c);process.stdin.on('end',()=>{try{const o=JSON.parse(s);const h=Array.isArray(o.workflow_id_history)?o.workflow_id_history:JSON.parse(o.workflow_id_history);console.log(h.length);}catch{console.log('parse-err');}})") || K120_BEFORE=0
(cd "$K120_TMP" && node "$CLI" state update phase=verify >/dev/null 2>&1) || true
K120_AFTER=$(set +eo pipefail; cd "$K120_TMP" && node "$CLI" state read 2>/dev/null | node -e "let s='';process.stdin.on('data',c=>s+=c);process.stdin.on('end',()=>{try{const o=JSON.parse(s);const h=Array.isArray(o.workflow_id_history)?o.workflow_id_history:JSON.parse(o.workflow_id_history);console.log(h.length);}catch{console.log('parse-err');}})") || K120_AFTER=0
K120_ANCHOR_PRESERVED=$(set +eo pipefail; cd "$K120_TMP" && node "$CLI" state read 2>/dev/null | node -e "let s='';process.stdin.on('data',c=>s+=c);process.stdin.on('end',()=>{try{const o=JSON.parse(s);const h=Array.isArray(o.workflow_id_history)?o.workflow_id_history:JSON.parse(o.workflow_id_history);console.log(h[0]==='k120-id-00'?'yes':'no');}catch{console.log('parse-err');}})") || K120_ANCHOR_PRESERVED="parse-err"
rm -rf "$K120_TMP"
if [ "$K120_BEFORE" = "10" ] && [ "$K120_AFTER" = "6" ] && [ "$K120_ANCHOR_PRESERVED" = "yes" ]; then
  pass "K120: workflow_id_history trim respects archive_runs cap (10 → 6 entries, original_workflow_id anchor preserved at index 0)"
else
  fail "K120: trim broken — before=$K120_BEFORE after=$K120_AFTER anchor_preserved=$K120_ANCHOR_PRESERVED"
fi

# K121: state update phase=X status=DONE fires phase-gates from
# _phase-gates.yaml; --skip-gates opts out. Field-observed: workflows
# overwhelmingly call `state update phase=X` rather than `state advance-phase`,
# so gating only the advance-phase path leaves the registry effectively dead
# for the majority of phase transitions. K121 locks the unified contract:
# default-block on gate failure, opt-out via --skip-gates, state unchanged
# on refusal.
K121_TMP=$(mktemp -d)
mkdir -p "$K121_TMP/.devt/state"
# Active code_review_parallel workflow at context_init (gates for .complete
# include assert-no-raw-dispatches + assert-claim-checks + assert-verifier-ran
# — all will fail in this empty fixture so the gate is guaranteed to block).
(cd "$K121_TMP" && node "$CLI" state update active=true workflow_type=code_review_parallel phase=context_init status=DONE --skip-gates >/dev/null 2>&1) || true
# Test 1: state update phase=complete status=DONE should refuse (exit non-zero).
K121_REFUSED="no"
if ! (cd "$K121_TMP" && node "$CLI" state update phase=complete status=DONE active=false >/dev/null 2>&1); then
  K121_REFUSED="yes"
fi
# Test 2: state must remain at IN_PROGRESS / context_init / active=true after refusal.
K121_STATE_AFTER_REFUSAL=$(set +eo pipefail; cd "$K121_TMP" && node "$CLI" state read 2>/dev/null | node -e "let s='';process.stdin.on('data',c=>s+=c);process.stdin.on('end',()=>{try{const o=JSON.parse(s);console.log(o.phase+'/'+o.active);}catch{console.log('parse-err');}})") || K121_STATE_AFTER_REFUSAL="parse-err"
# Test 3: state update phase=complete --skip-gates should succeed.
K121_SKIPPED="no"
if (cd "$K121_TMP" && node "$CLI" state update phase=complete status=DONE active=false --skip-gates >/dev/null 2>&1); then
  K121_SKIPPED="yes"
fi
K121_STATE_AFTER_SKIP=$(set +eo pipefail; cd "$K121_TMP" && node "$CLI" state read 2>/dev/null | node -e "let s='';process.stdin.on('data',c=>s+=c);process.stdin.on('end',()=>{try{const o=JSON.parse(s);console.log(o.phase+'/'+o.active);}catch{console.log('parse-err');}})") || K121_STATE_AFTER_SKIP="parse-err"
rm -rf "$K121_TMP"
if [ "$K121_REFUSED" = "yes" ] && [ "$K121_STATE_AFTER_REFUSAL" = "context_init/true" ] && [ "$K121_SKIPPED" = "yes" ] && [ "$K121_STATE_AFTER_SKIP" = "complete/false" ]; then
  pass "K121: state update phase=complete status=DONE fires phase-gates (default-block); --skip-gates opts out; state preserved on refusal"
else
  fail "K121: phase-gate-on-state-update contract broken — refused=$K121_REFUSED after_refusal=$K121_STATE_AFTER_REFUSAL skipped=$K121_SKIPPED after_skip=$K121_STATE_AFTER_SKIP"
fi

# K122: _phase-gates.yaml gates every INTERMEDIATE phase with
# assert-no-raw-dispatches-this-session (not just terminal). Field-observed:
# raw_dispatches can accumulate across dispatch_lanes → substance_check_lanes
# → redispatch_lanes → consolidate before terminal `complete` enforces.
# Combined with the kill-threshold (config: dispatch_hygiene_kill_threshold,
# default 3), the bypass pattern now trips at the threshold count on
# whatever intermediate phase boundary the orchestrator hits next. K122
# locks that contract.
K122_TMP=$(mktemp -d)
mkdir -p "$K122_TMP/.devt/state"
# Active dev workflow at phase=scan (intermediate phase, has a gate per the
# new YAML entry). Seed 3 raw_dispatch records to trip kill-threshold (=3).
(cd "$K122_TMP" && node "$CLI" state update active=true workflow_type=dev phase=scan status=DONE --skip-gates >/dev/null 2>&1) || true
cat > "$K122_TMP/.devt/state/dispatch-warnings.jsonl" <<'EOF'
{"ts":"2099-01-01T00:00:00Z","source":"raw_dispatch","agent":"devt:programmer"}
{"ts":"2099-01-01T00:00:01Z","source":"raw_dispatch","agent":"devt:tester"}
{"ts":"2099-01-01T00:00:02Z","source":"raw_dispatch","agent":"devt:code-reviewer"}
EOF
# Test 1: state update phase=plan (intermediate) should refuse due to kill-threshold.
K122_REFUSED="no"
if ! (cd "$K122_TMP" && node "$CLI" state update phase=plan status=DONE >/dev/null 2>&1); then
  K122_REFUSED="yes"
fi
# Test 2: state must remain at phase=scan after refusal.
K122_STATE_AFTER_REFUSAL=$(set +eo pipefail; cd "$K122_TMP" && node "$CLI" state read 2>/dev/null | node -e "let s='';process.stdin.on('data',c=>s+=c);process.stdin.on('end',()=>{try{const o=JSON.parse(s);console.log(o.phase);}catch{console.log('parse-err');}})") || K122_STATE_AFTER_REFUSAL="parse-err"
# Test 3: --skip-gates should bypass intermediate-phase gate.
K122_SKIPPED="no"
if (cd "$K122_TMP" && node "$CLI" state update phase=plan status=DONE --skip-gates >/dev/null 2>&1); then
  K122_SKIPPED="yes"
fi
K122_STATE_AFTER_SKIP=$(set +eo pipefail; cd "$K122_TMP" && node "$CLI" state read 2>/dev/null | node -e "let s='';process.stdin.on('data',c=>s+=c);process.stdin.on('end',()=>{try{const o=JSON.parse(s);console.log(o.phase);}catch{console.log('parse-err');}})") || K122_STATE_AFTER_SKIP="parse-err"
rm -rf "$K122_TMP"
if [ "$K122_REFUSED" = "yes" ] && [ "$K122_STATE_AFTER_REFUSAL" = "scan" ] && [ "$K122_SKIPPED" = "yes" ] && [ "$K122_STATE_AFTER_SKIP" = "plan" ]; then
  pass "K122: intermediate-phase gates fire on state update phase=<intermediate> status=DONE (kill-threshold trips at 3 raw_dispatches; state preserved on refusal; --skip-gates opts out)"
else
  fail "K122: intermediate-phase gate contract broken — refused=$K122_REFUSED after_refusal=$K122_STATE_AFTER_REFUSAL skipped=$K122_SKIPPED after_skip=$K122_STATE_AFTER_SKIP"
fi

# K123: cliff-counter at workflow-context-injector.sh must read r.signal
# field — only count records with signal in (near_cliff, low_output,
# mid_task). Counting every task_output_bytes record regardless of signal
# produces cry-wolf — field-observed at ~247-of-254 false alarms in a
# single session — and trains operators to ignore the banner. K123
# validates by reading the bash hook's node-eval logic, dropping a fake
# JSONL fixture, and asserting cliff count matches signal-aware semantics.
K123_HOOK=$(cat "$ROOT/hooks/workflow-context-injector.sh")
# Assert the corrected predicate is present (defensive — catches regressions
# that revert the signal-aware check without breaking the runtime path).
if echo "$K123_HOOK" | grep -q "r.source === 'task_output_bytes' && r.signal && r.signal !== 'healthy'"; then
  K123_PREDICATE="present"
else
  K123_PREDICATE="missing"
fi
# Functional test: run the JSONL filter logic in isolation against a 5-record
# fixture (3 healthy, 1 null, 1 near_cliff). Expected cliff count = 1.
K123_FUNCTIONAL=$(node -e "
  const records = [
    {ts: '2099-01-01T00:00:00Z', source: 'task_output_bytes', signal: 'healthy'},
    {ts: '2099-01-01T00:00:01Z', source: 'task_output_bytes', signal: 'healthy'},
    {ts: '2099-01-01T00:00:02Z', source: 'task_output_bytes', signal: null},
    {ts: '2099-01-01T00:00:03Z', source: 'task_output_bytes', signal: 'healthy'},
    {ts: '2099-01-01T00:00:04Z', source: 'task_output_bytes', signal: 'near_cliff'},
  ];
  let cliff = 0;
  for (const r of records) {
    if (r.source === 'task_output_bytes' && r.signal && r.signal !== 'healthy') cliff++;
  }
  console.log(cliff);
" 2>/dev/null)
if [ "$K123_PREDICATE" = "present" ] && [ "$K123_FUNCTIONAL" = "1" ]; then
  pass "K123: workflow-context-injector cliff-counter reads r.signal (only counts actionable signals; healthy/null filtered as noise)"
else
  fail "K123: signal-aware cliff-counter contract broken — predicate=$K123_PREDICATE functional_cliff_count=$K123_FUNCTIONAL (expected present/1)"
fi

# K124: blast_radius MCP schema maxItems=256 (raised from a prior 32-cap).
# Prior cap was an arbitrary JSONSchema literal with no underlying transport
# constraint; the CLI wrapper handles unlimited input. Field-observed: a
# 32-cap silently dropped ~65% of topic symbols on PRs with wider domain
# surfaces. K124 locks the raised value and prevents accidental shrink.
K124_MAX_ITEMS=$(grep -oE 'maxItems:\s*[0-9]+' "$ROOT/bin/devt-graphify-mcp.cjs" | grep -oE '[0-9]+' | head -1)
# Functional test: parse the schema literal and confirm a 100-symbol input
# would pass validation (the 32-cap would have failed).
K124_VALIDATES=$(node -e "
  const fs = require('fs');
  const src = fs.readFileSync('$ROOT/bin/devt-graphify-mcp.cjs', 'utf8');
  const m = src.match(/maxItems:\s*(\d+),\s*description:\s*\"Subject symbols/);
  const cap = m ? parseInt(m[1], 10) : 0;
  // A 100-symbol input would pass iff cap >= 100.
  console.log(cap >= 100 ? 'pass' : 'fail');
" 2>/dev/null)
if [ "$K124_MAX_ITEMS" = "256" ] && [ "$K124_VALIDATES" = "pass" ]; then
  pass "K124: blast_radius MCP schema maxItems=256 (100-symbol input validates; prevents the silent symbol-drop pattern field-observed at 32-cap)"
else
  fail "K124: MCP cap contract broken — maxItems=$K124_MAX_ITEMS validates_100=$K124_VALIDATES (expected 256/pass)"
fi

# K125: pre-flight-guard silent auto-write for ungoverned edits when memory
# layer exists but no governing doc matches the path. Field signal: project
# with memory governance set up + edit on a path no ADR/CON/FLOW covers
# nagged the operator to manually write "PREFLIGHT ... :: ungoverned" (~50
# noise events per session). Auto-write silently instead. Projects WITHOUT
# memory layer keep existing warn behavior (the nudge to set up governance
# is load-bearing for those — covered by adjacent assertions above).
K125_TMP=$(mktemp -d)
mkdir -p "$K125_TMP/.devt/state"
# Initialize memory layer (init + index) — empty memory, no docs match anything
(cd "$K125_TMP" && node "$ROOT/bin/devt-tools.cjs" memory init >/dev/null 2>&1)
(cd "$K125_TMP" && node "$ROOT/bin/devt-tools.cjs" memory index >/dev/null 2>&1)
echo '{"memory":{"preflight_mode":"warn"}}' > "$K125_TMP/.devt/config.json"
echo 'active: true' > "$K125_TMP/.devt/state/workflow.yaml"
touch "$K125_TMP/test.py"
if [ -f "$K125_TMP/.devt/memory/index.db" ]; then
  K125_OUT=$(cd "$K125_TMP" && echo '{"tool_name":"Edit","tool_input":{"file_path":"'"$K125_TMP"'/test.py"}}' | CLAUDE_PLUGIN_ROOT="$ROOT" bash "$ROOT/hooks/pre-flight-guard.sh" 2>&1)
  K125_SCRATCH=$(cat "$K125_TMP/.devt/state/scratchpad.md" 2>/dev/null || echo "")
  if [ -z "$K125_OUT" ] && echo "$K125_SCRATCH" | /usr/bin/grep -q ":: ungoverned"; then
    pass "K125: pre-flight-guard silent auto-write when memory exists + no doc matches (no prompt-channel warning + scratchpad ungoverned line appended)"
  else
    fail "K125: ungoverned auto-write broken (out=${K125_OUT:0:200} scratch=$K125_SCRATCH)"
  fi
else
  fail "K125: memory init failed — index.db not created in fixture"
fi
rm -rf "$K125_TMP"

# K126: dispatch-hygiene-guard surfaces envelope-unavailable reason.
# Two silent-failure paths were field-observed: CLAUDE_PLUGIN_ROOT unset (the
# require() never ran) AND no active workflow (cmdRenderFilled threw). Both
# now surface a specific reason in the advisory so the operator knows WHY the
# envelope wasn't attached. Locks both reason paths.
K126_TMP=$(mktemp -d)
mkdir -p "$K126_TMP/.devt/state"
echo '{"dispatch_hygiene_mode":"warn"}' > "$K126_TMP/.devt/config.json"
# Path A: no active workflow → reason mentions "no active devt workflow"
K126_INPUT='{"tool_name":"Task","tool_input":{"subagent_type":"devt:code-reviewer","prompt":"Review file X. No envelope."}}'
K126_OUT_A=$(cd "$K126_TMP" && echo "$K126_INPUT" | CLAUDE_PLUGIN_ROOT="$ROOT" bash "$ROOT/hooks/dispatch-hygiene-guard.sh" 2>&1)
# Path B: no CLAUDE_PLUGIN_ROOT → reason mentions "plugin root not resolvable"
K126_OUT_B=$(cd "$K126_TMP" && echo "$K126_INPUT" | env -u CLAUDE_PLUGIN_ROOT bash "$ROOT/hooks/dispatch-hygiene-guard.sh" 2>&1)
rm -rf "$K126_TMP"
if echo "$K126_OUT_A" | /usr/bin/grep -q "no active devt workflow" && echo "$K126_OUT_B" | /usr/bin/grep -q "plugin root not resolvable"; then
  pass "K126: dispatch-hygiene-guard surfaces envelope-unavailable reasons (no-workflow + no-plugin-root both explicit)"
else
  fail "K126: envelope-reason surfacing broken — workflow-path=${K126_OUT_A:0:80} plugin-path=${K126_OUT_B:0:80}"
fi

# K127: workflow-context-injector dual-window session-signal counter.
# Field signal: long-running workflows (first_created_at days/weeks old)
# accumulated dispatch-warnings.jsonl entries that the cumulative counter
# treated as current — producing banner-blindness ("74 raw_dispatch" stale).
# Dual-window: count last-1h primarily; silent when last-1h=0 even if
# cumulative > 0. Adds cumulative tail "; total this workflow (Xd): N raw"
# only when workflow age > 24h AND counts differ.
K127_TMP=$(mktemp -d)
mkdir -p "$K127_TMP/.devt/state"
cat > "$K127_TMP/.devt/state/workflow.yaml" <<EOF
active: true
workflow_id: k127-test
workflow_type: dev
tier: STANDARD
phase: implement
status: IN_PROGRESS
iteration: 1
task: "k127 test"
first_created_at: "2026-06-10T08:00:00.000Z"
created_at: "2026-06-17T08:00:00.000Z"
EOF
# Case A: only old records → silent (no session signal line)
cat > "$K127_TMP/.devt/state/dispatch-warnings.jsonl" <<EOF
{"ts":"2026-06-11T08:00:00.000Z","source":"raw_dispatch","agent":"devt:tester"}
{"ts":"2026-06-12T08:00:00.000Z","source":"raw_dispatch","agent":"devt:tester"}
EOF
K127_OUT_A=$(cd "$K127_TMP" && echo '{"hook_event_name":"UserPromptSubmit","prompt":"test"}' | bash "$ROOT/hooks/workflow-context-injector.sh" 2>&1)
# Case B: 1 old + 1 recent → signal fires, recent count = 1
RECENT_TS=$(date -u -v-15M +%Y-%m-%dT%H:%M:%S.000Z 2>/dev/null || date -u -d '15 minutes ago' +%Y-%m-%dT%H:%M:%S.000Z)
cat > "$K127_TMP/.devt/state/dispatch-warnings.jsonl" <<EOF
{"ts":"2026-06-11T08:00:00.000Z","source":"raw_dispatch","agent":"devt:tester"}
{"ts":"$RECENT_TS","source":"raw_dispatch","agent":"devt:code-reviewer"}
EOF
K127_OUT_B=$(cd "$K127_TMP" && echo '{"hook_event_name":"UserPromptSubmit","prompt":"test"}' | bash "$ROOT/hooks/workflow-context-injector.sh" 2>&1)
rm -rf "$K127_TMP"
K127_A_SILENT=$(echo "$K127_OUT_A" | /usr/bin/grep -c "session signal" || true)
K127_B_FIRES=$(echo "$K127_OUT_B" | /usr/bin/grep -c "1 raw_dispatch.*last 1h" || true)
K127_B_TOTAL=$(echo "$K127_OUT_B" | /usr/bin/grep -c "total this workflow" || true)
K127_B_BYSRC=$(echo "$K127_OUT_B" | /usr/bin/grep -c "devt:code-reviewer=1" || true)
if [ "$K127_A_SILENT" = "0" ] && [ "$K127_B_FIRES" = "1" ] && [ "$K127_B_TOTAL" = "1" ] && [ "$K127_B_BYSRC" = "1" ]; then
  pass "K127: workflow-context-injector dual-window counter (silent on stale-only; recent count + workflow-age tail + by-source inline when recent activity)"
else
