fi

# K133: workflow-context-injector emits staleness warning when workflow > 24h old.
# Field signal: a 3-day workflow accumulated 39 raw_dispatches across many
# sessions and tripped the kill-threshold. Counter semantics are correct
# (workflow-scoped per created_at) — issue is the operator's mental model is
# per-session while counter's is per-workflow-window. Bridge with actionable
# warning when workflow age > 24h. No auto-reset (operator decides).
# Separate tmpdirs per case — the hook's mtime-keyed state cache hashes on
# $(pwd); if both tests reused the same path, the cache populated by the
# first test could be reused (within mtime resolution) for the second.
K133_STALE_TMP=$(mktemp -d)
mkdir -p "$K133_STALE_TMP/.devt/state"
cat > "$K133_STALE_TMP/.devt/state/workflow.yaml" <<EOF
active: true
workflow_id: k133-stale
workflow_type: dev
tier: STANDARD
phase: implement
iteration: 1
status: IN_PROGRESS
task: "stale-test"
first_created_at: "$(date -u -v-3d +%Y-%m-%dT%H:%M:%S.000Z 2>/dev/null || date -u -d '3 days ago' +%Y-%m-%dT%H:%M:%S.000Z)"
created_at: "$(date -u -v-3d +%Y-%m-%dT%H:%M:%S.000Z 2>/dev/null || date -u -d '3 days ago' +%Y-%m-%dT%H:%M:%S.000Z)"
EOF
K133_STALE=$(cd "$K133_STALE_TMP" && echo '{"hook_event_name":"UserPromptSubmit","prompt":"test"}' | bash "$ROOT/hooks/workflow-context-injector.sh" 2>&1)
rm -rf "$K133_STALE_TMP"

K133_FRESH_TMP=$(mktemp -d)
mkdir -p "$K133_FRESH_TMP/.devt/state"
cat > "$K133_FRESH_TMP/.devt/state/workflow.yaml" <<EOF
active: true
workflow_id: k133-fresh
workflow_type: dev
tier: STANDARD
phase: implement
iteration: 1
status: IN_PROGRESS
task: "fresh-test"
first_created_at: "$(date -u -v-1H +%Y-%m-%dT%H:%M:%S.000Z 2>/dev/null || date -u -d '1 hour ago' +%Y-%m-%dT%H:%M:%S.000Z)"
created_at: "$(date -u -v-1H +%Y-%m-%dT%H:%M:%S.000Z 2>/dev/null || date -u -d '1 hour ago' +%Y-%m-%dT%H:%M:%S.000Z)"
EOF
K133_FRESH=$(cd "$K133_FRESH_TMP" && echo '{"hook_event_name":"UserPromptSubmit","prompt":"test"}' | bash "$ROOT/hooks/workflow-context-injector.sh" 2>&1)
rm -rf "$K133_FRESH_TMP"
K133_STALE_WARN=$(echo "$K133_STALE" | /usr/bin/grep -c "workflow open.*d.*long-running" || true)
K133_FRESH_QUIET=$(echo "$K133_FRESH" | /usr/bin/grep -c "workflow open.*d.*long-running" || true)
if [ "${K133_STALE_WARN:-0}" -ge 1 ] && [ "${K133_FRESH_QUIET:-0}" = "0" ]; then
  pass "K133: workflow-staleness warning fires on >24h workflow + silent on <24h workflow"
else
  fail "K133: staleness warning broken — stale_fires=$K133_STALE_WARN fresh_silent=$K133_FRESH_QUIET"
fi

# K134: preflight laneG project-context enrichment surfaces project-shape docs.
# Field signal: a Bitbucket project's CON-002 ("Bitbucket projects permanently
# lose pr_scoped tier") never surfaced in memory_signal for a task whose scope
# string had zero keyword overlap with the doc. laneG queries memory by
# project-context tokens (.devt/config.json::git.provider) and unions into
# the governing pool so project-shape docs surface regardless of task vocabulary.
K134_TMP=$(mktemp -d)
mkdir -p "$K134_TMP/.devt/state"
echo '{"git":{"provider":"bitbucket"}}' > "$K134_TMP/.devt/config.json"
# Initialize memory + seed a Bitbucket-scoped doc
(cd "$K134_TMP" && node "$ROOT/bin/devt-tools.cjs" memory init >/dev/null 2>&1)
mkdir -p "$K134_TMP/.devt/memory/concepts"
# Use CON-999 (numeric ID required to pass concept-id pattern validation)
cat > "$K134_TMP/.devt/memory/concepts/CON-999-bitbucket-test.md" <<EOF
---
id: CON-999
title: "K134 test — Bitbucket-only constraint"
doc_type: concept
domain: "tooling"
status: candidate
confidence: explicit
summary: "Bitbucket projects on devt cannot use feature X (a doc whose only project-context anchor is the word 'bitbucket')."
affects_paths: [".devt/**"]
created_at: "2026-06-18T00:00:00Z"
created_by: curator
schema_version: 1
---
Body content here.
EOF
(cd "$K134_TMP" && node "$ROOT/bin/devt-tools.cjs" memory index >/dev/null 2>&1)
# Query that has ZERO overlap with the doc — only the project context (bitbucket) should surface it
K134_RESULT=$(cd "$K134_TMP" && node -e "
  const pf = require('$ROOT/bin/modules/preflight.cjs');
  const r = pf.generate('unrelated task with no bitbucket keyword', { depth: 1 });
  console.log(JSON.stringify({lane_g: r.counts.lane_g, governing: r.counts.governing}));
" 2>/dev/null)
rm -rf "$K134_TMP"
K134_LANE_G=$(echo "$K134_RESULT" | node -e "let s=''; process.stdin.on('data',d=>s+=d); process.stdin.on('end',()=>{try{console.log(JSON.parse(s).lane_g)}catch{console.log(0)}});" 2>/dev/null)
if [ "${K134_LANE_G:-0}" -ge 1 ]; then
  pass "K134: preflight laneG project-context enrichment surfaces docs via .devt/config.json::git.provider token"
else
  fail "K134: laneG broken — project-context token (bitbucket) didn't surface a directly-matching doc: $K134_RESULT"
fi

# K135: docs/GRAPHIFY.md positions symbol_anchored as canonical primary for non-GitHub.
# Field calibration: field (Bitbucket project) read pr_scoped as "the flagship"
# and symbol_anchored as a fallback. The framing was already honest in workflow code
# but absent from user-facing docs/GRAPHIFY.md. This gate locks the positioning.
if /usr/bin/grep -qE "symbol_anchored.*(canonical primary|primary tier).*non-GitHub" "$ROOT/docs/GRAPHIFY.md" 2>/dev/null; then
  pass "K135: docs/GRAPHIFY.md positions symbol_anchored as canonical primary for non-GitHub"
else
  fail "K135: docs/GRAPHIFY.md missing tier-semantics positioning string"
fi

# K136: identify_scope diff resolution captures ALL branch commits (not just
# HEAD~1). Field calibration: a multi-commit feature branch was silently
# diffed at HEAD~1 (single commit) instead of merge-base (whole branch).
# The pattern now lives in `state changed-files` (collectChangedFiles union:
# merge-base triple-dot + working tree + untracked), which identify_scope
# consumes — so the behavioral assertion runs the CLI on a 3-commit fixture
# and requires every commit's files plus an uncommitted one.
K136_TMP=$(mktemp -d)
(
  cd "$K136_TMP"
  git init -q -b main 2>/dev/null || { git init -q && git checkout -q -b main; }
  git config user.email "k136@test"
  git config user.name "K136 Test"
  echo "base" > base.txt && git add base.txt && git -c commit.gpgsign=false commit -q -m "base"
  git checkout -q -b feature
  echo "c1" > c1.txt && git add c1.txt && git -c commit.gpgsign=false commit -q -m "c1"
  echo "c2" > c2.txt && git add c2.txt && git -c commit.gpgsign=false commit -q -m "c2"
  echo "c3" > c3.txt && git add c3.txt && git -c commit.gpgsign=false commit -q -m "c3"
  echo "wt" > wt.txt
) >/dev/null 2>&1
K136_UNION=$(cd "$K136_TMP" && node "$CLI" state changed-files --base=main 2>/dev/null | node -e '
let s=""; process.stdin.on("data",d=>s+=d); process.stdin.on("end",()=>{
  try { console.log(JSON.parse(s).files.sort().join(",")); } catch(e) { console.log("parse-error"); }
});' 2>/dev/null || echo "cli-error")
K136_HEAD1_DIFF=$(cd "$K136_TMP" && git diff --name-only HEAD~1 2>/dev/null | sort | tr '\n' ',' | sed 's/,$//')
rm -rf "$K136_TMP"
# union must capture c1+c2+c3 (all branch commits) AND wt.txt (untracked);
# HEAD~1 only captures c3 — the silent under-scope this gate exists to block
if [ "$K136_UNION" = "c1.txt,c2.txt,c3.txt,wt.txt" ] && [ "$K136_HEAD1_DIFF" = "c3.txt" ]; then
  if /usr/bin/grep -q 'state changed-files' "$ROOT/workflows/code-review.md"; then
    pass "K136: identify_scope diff resolution — changed-files union captures all branch commits + working tree (not just HEAD~1)"
  else
    fail "K136: code-review.md identify_scope no longer consumes 'state changed-files'"
  fi
else
  fail "K136: diff-base behavior unexpected — union=$K136_UNION head1=$K136_HEAD1_DIFF"
fi

# K137: state reset-soft clears per-workflow accumulators while preserving
# session anchors. Field calibration: field receipt #4 — operator ran
# /devt:review on stale workflow with 51 raw_dispatch entries from prior 20-day
# workflow chain. KILL gate fired on first state.update call, blocking the
# entire review. Reset-soft is the surgical escape hatch.
K137_TMP=$(mktemp -d)
mkdir -p "$K137_TMP/.devt/state"
cat > "$K137_TMP/.devt/state/workflow.yaml" <<EOF
active: true
workflow_id: k137-prev-id
original_workflow_id: k137-original-id
workflow_type: dev
task: "prior task"
tier: COMPLEX
phase: implement
status: IN_PROGRESS
verify_iteration: 3
redispatch_count: 5
first_created_at: "2026-06-01T00:00:00.000Z"
created_at: "2026-06-01T00:00:00.000Z"
EOF
echo '{"ts":"2026-06-01","source":"raw_dispatch"}' > "$K137_TMP/.devt/state/dispatch-warnings.jsonl"
K137_RESULT=$(cd "$K137_TMP" && node "$ROOT/bin/devt-tools.cjs" state reset-soft 2>/dev/null)
K137_NEW_ID=$(echo "$K137_RESULT" | node -e "let s=''; process.stdin.on('data',d=>s+=d); process.stdin.on('end',()=>{try{const o=JSON.parse(s); console.log(o.new_workflow_id&&o.new_workflow_id!=='k137-prev-id'?'1':'0')}catch{console.log('0')}});" 2>/dev/null)
K137_HISTORY=$(cd "$K137_TMP" && /usr/bin/grep -c "k137-prev-id" .devt/state/workflow.yaml 2>/dev/null || true)
K137_ANCHOR=$(cd "$K137_TMP" && /usr/bin/grep -c "k137-original-id" .devt/state/workflow.yaml 2>/dev/null || true)
K137_ROTATED=$(ls "$K137_TMP/.devt/state/" 2>/dev/null | /usr/bin/grep -c "dispatch-warnings.archive" || true)
K137_TASK_CLEARED=$(/usr/bin/grep -c "^task:" "$K137_TMP/.devt/state/workflow.yaml" 2>/dev/null || true)
rm -rf "$K137_TMP"
if [ "${K137_NEW_ID:-0}" = "1" ] && [ "${K137_HISTORY:-0}" -ge 1 ] && [ "${K137_ANCHOR:-0}" -ge 1 ] && [ "${K137_ROTATED:-0}" -ge 1 ] && [ "${K137_TASK_CLEARED:-0}" = "0" ]; then
  pass "K137: state reset-soft clears accumulators (task), generates new workflow_id, preserves history+original_workflow_id, rotates dispatch-warnings.jsonl"
else
  fail "K137: reset-soft broken — new_id=$K137_NEW_ID history=$K137_HISTORY anchor=$K137_ANCHOR rotated=$K137_ROTATED task_cleared=$K137_TASK_CLEARED"
fi

# K138: state staleness-check enforces AND semantics — task changed AND age
# > 1h. Task-mismatch-but-fresh = not stale (typo retry). Task-match-stale =
# not stale (legitimate resume). Both required = stale.
K138_TMP=$(mktemp -d)
mkdir -p "$K138_TMP/.devt/state"
# Case 1: task changed AND age > 1h → stale=true
cat > "$K138_TMP/.devt/state/workflow.yaml" <<EOF
task: "old task"
created_at: "2026-06-01T00:00:00.000Z"
EOF
K138_BOTH=$(cd "$K138_TMP" && node "$ROOT/bin/devt-tools.cjs" state staleness-check --task="new task" 2>/dev/null | node -e "let s=''; process.stdin.on('data',d=>s+=d); process.stdin.on('end',()=>{try{console.log(JSON.parse(s).stale===true?'1':'0')}catch{console.log('0')}});" 2>/dev/null)
# Case 2: task changed AND age < 1h → stale=false (typo retry guard)
cat > "$K138_TMP/.devt/state/workflow.yaml" <<EOF
task: "old task"
created_at: "$(date -u +%Y-%m-%dT%H:%M:%S.000Z)"
EOF
K138_FRESH_MISMATCH=$(cd "$K138_TMP" && node "$ROOT/bin/devt-tools.cjs" state staleness-check --task="new task" 2>/dev/null | node -e "let s=''; process.stdin.on('data',d=>s+=d); process.stdin.on('end',()=>{try{console.log(JSON.parse(s).stale===true?'1':'0')}catch{console.log('0')}});" 2>/dev/null)
# Case 3: task match AND age > 1h → stale=false (legitimate resume guard)
cat > "$K138_TMP/.devt/state/workflow.yaml" <<EOF
task: "same task"
created_at: "2026-06-01T00:00:00.000Z"
EOF
K138_STALE_MATCH=$(cd "$K138_TMP" && node "$ROOT/bin/devt-tools.cjs" state staleness-check --task="same task" 2>/dev/null | node -e "let s=''; process.stdin.on('data',d=>s+=d); process.stdin.on('end',()=>{try{console.log(JSON.parse(s).stale===true?'1':'0')}catch{console.log('0')}});" 2>/dev/null)
rm -rf "$K138_TMP"
if [ "${K138_BOTH:-0}" = "1" ] && [ "${K138_FRESH_MISMATCH:-1}" = "0" ] && [ "${K138_STALE_MATCH:-1}" = "0" ]; then
  pass "K138: state staleness-check enforces AND semantics (task-changed+age>1h stale; typo-retry and legitimate-resume both NOT stale)"
else
  fail "K138: staleness-check broken — both=$K138_BOTH fresh_mismatch=$K138_FRESH_MISMATCH stale_match=$K138_STALE_MATCH"
fi

# K139: dispatch render-lanes emits <correlation_id>cid_ tag per envelope.
# Field calibration: field receipt #4 — operator followed register-lanes
# + render-lanes canonical path, but dispatch-hygiene-guard.sh still flagged
# all 6 dispatches as raw_dispatch because matcher only recognized literal
# envelope tags. correlation_id is the short tag operators can preserve when
