# K140: dispatch-hygiene-guard.sh matcher recognizes correlation_id-only
# envelope (operator customized other content but preserved the short tag).
# Two cases: (a) prompt with only <correlation_id>cid_*</correlation_id> →
# silenced; (b) prompt with neither correlation_id nor other envelope tags →
# flagged as raw_dispatch.
K140_TMP=$(mktemp -d)
mkdir -p "$K140_TMP/.devt/state"
# Note: hook needs CLAUDE_PLUGIN_ROOT to load envelope helpers; set explicitly.
export CLAUDE_PLUGIN_ROOT="$ROOT"
# Case (a): correlation_id present → exit_silently (no raw_dispatch write).
PRIOR_WARNINGS_A=0
if [ -f "$K140_TMP/.devt/state/dispatch-warnings.jsonl" ]; then
  PRIOR_WARNINGS_A=$(wc -l < "$K140_TMP/.devt/state/dispatch-warnings.jsonl" 2>/dev/null || echo 0)
fi
(cd "$K140_TMP" && echo '{"tool_name":"Task","tool_input":{"subagent_type":"devt:code-reviewer","prompt":"## Task\n\nCustom prose\n\n<correlation_id>cid_test1234_L1</correlation_id>\n\nMore prose"}}' | bash "$ROOT/hooks/dispatch-hygiene-guard.sh" >/dev/null 2>&1)
NEW_WARNINGS_A=0
if [ -f "$K140_TMP/.devt/state/dispatch-warnings.jsonl" ]; then
  NEW_WARNINGS_A=$(wc -l < "$K140_TMP/.devt/state/dispatch-warnings.jsonl" 2>/dev/null || echo 0)
fi
# Case (b): no envelope tags + no correlation_id → raw_dispatch write.
K140_TMP2=$(mktemp -d)
mkdir -p "$K140_TMP2/.devt/state"
(cd "$K140_TMP2" && echo '{"tool_name":"Task","tool_input":{"subagent_type":"devt:code-reviewer","prompt":"## Task\n\nJust prose, no envelope tags at all"}}' | bash "$ROOT/hooks/dispatch-hygiene-guard.sh" >/dev/null 2>&1)
NEW_WARNINGS_B=0
if [ -f "$K140_TMP2/.devt/state/dispatch-warnings.jsonl" ]; then
  NEW_WARNINGS_B=$(wc -l < "$K140_TMP2/.devt/state/dispatch-warnings.jsonl" 2>/dev/null || echo 0)
fi
rm -rf "$K140_TMP" "$K140_TMP2"
# Case (a) should NOT have written a raw_dispatch entry; case (b) SHOULD have
if [ "${NEW_WARNINGS_A:-0}" = "${PRIOR_WARNINGS_A:-0}" ] && [ "${NEW_WARNINGS_B:-0}" -ge 1 ]; then
  pass "K140: dispatch-hygiene-guard.sh matcher accepts <correlation_id>cid_*</correlation_id> as envelope-managed (silent); no-envelope prompt still flagged raw_dispatch"
else
  fail "K140: matcher behavior wrong — correlation_id silent=$NEW_WARNINGS_A (expected 0); no-envelope flagged=$NEW_WARNINGS_B (expected >=1)"
fi

# K141: model-profile surface — opus alias current, and the dead per-dispatch
# effort plumbing stays deleted (frontmatter `effort:` is the only effort lever
# the harness honors; the Agent tool has no per-call effort parameter).
K141_OPUS_RESOLVED=$(node -e 'const {resolveModelId}=require("'"$ROOT"'/bin/modules/model-profiles.cjs"); console.log(resolveModelId("opus")==="claude-opus-4-8"?"1":"0");' 2>/dev/null)
K141_EFFORTS_GONE=$(node -e 'const m=require("'"$ROOT"'/bin/modules/model-profiles.cjs"); console.log(m.getEfforts===undefined&&m.EFFORTS===undefined?"1":"0");' 2>/dev/null)
if [ "${K141_OPUS_RESOLVED:-0}" = "1" ] && [ "${K141_EFFORTS_GONE:-0}" = "1" ]; then
  pass "K141: opus alias resolves to claude-opus-4-8 + effort plumbing stays deleted (frontmatter is the effort lever)"
else
  fail "K141: model-profile surface broken — opus_resolved=$K141_OPUS_RESOLVED efforts_gone=$K141_EFFORTS_GONE"
fi

# K142: state assert-verifier-short-circuit fires on substantive clean sidecar.
# Field motivation: Opus 4.8 self-flagging makes empty self_flagged_uncertainties
# a meaningful negative claim — verifier LLM dispatch can be skipped when the
# upstream agent self-certified no coverage gaps.
K142_TMP=$(mktemp -d)
mkdir -p "$K142_TMP/.devt/state"
echo '{"status":"DONE","verdict":"APPROVED","agent":"code-reviewer","self_flagged_uncertainties":[]}' > "$K142_TMP/.devt/state/review.json"
K142_CLEAN=$(cd "$K142_TMP" && node "$ROOT/bin/devt-tools.cjs" state assert-verifier-short-circuit --agent=code-reviewer 2>/dev/null | node -e "let s=''; process.stdin.on('data',d=>s+=d); process.stdin.on('end',()=>{try{console.log(JSON.parse(s).short_circuit===true?'1':'0')}catch{console.log('0')}});" 2>/dev/null)
# Negative case: non-empty self_flagged_uncertainties → MUST NOT short-circuit
echo '{"status":"DONE","verdict":"APPROVED","agent":"code-reviewer","self_flagged_uncertainties":[{"file":"x.ts","line":1,"concern":"y","severity":"high"}]}' > "$K142_TMP/.devt/state/review.json"
K142_FLAGGED=$(cd "$K142_TMP" && node "$ROOT/bin/devt-tools.cjs" state assert-verifier-short-circuit --agent=code-reviewer 2>/dev/null | node -e "let s=''; process.stdin.on('data',d=>s+=d); process.stdin.on('end',()=>{try{console.log(JSON.parse(s).short_circuit===true?'1':'0')}catch{console.log('0')}});" 2>/dev/null)
# PARTIAL status MUST NOT short-circuit (verifier needs to judge)
echo '{"status":"PARTIAL","verdict":"INDETERMINATE","agent":"code-reviewer","self_flagged_uncertainties":[]}' > "$K142_TMP/.devt/state/review.json"
K142_PARTIAL=$(cd "$K142_TMP" && node "$ROOT/bin/devt-tools.cjs" state assert-verifier-short-circuit --agent=code-reviewer 2>/dev/null | node -e "let s=''; process.stdin.on('data',d=>s+=d); process.stdin.on('end',()=>{try{console.log(JSON.parse(s).short_circuit===true?'1':'0')}catch{console.log('0')}});" 2>/dev/null)
# self_flagged_uncertainties FIELD-ABSENT MUST NOT short-circuit (legacy/external
# agents that don't engage with the self-flag contract; verifier safety net).
# Requires the operator's empty [] to be an EXPLICIT negative claim, not the
# default for omission. Without this check, a pre-cal-#30.2 sidecar would
# silently bypass the verifier.
echo '{"status":"DONE","verdict":"APPROVED","agent":"code-reviewer"}' > "$K142_TMP/.devt/state/review.json"
K142_ABSENT=$(cd "$K142_TMP" && node "$ROOT/bin/devt-tools.cjs" state assert-verifier-short-circuit --agent=code-reviewer 2>/dev/null | node -e "let s=''; process.stdin.on('data',d=>s+=d); process.stdin.on('end',()=>{try{console.log(JSON.parse(s).short_circuit===true?'1':'0')}catch{console.log('0')}});" 2>/dev/null)
rm -rf "$K142_TMP"
if [ "${K142_CLEAN:-0}" = "1" ] && [ "${K142_FLAGGED:-1}" = "0" ] && [ "${K142_PARTIAL:-1}" = "0" ] && [ "${K142_ABSENT:-1}" = "0" ]; then
  pass "K142: assert-verifier-short-circuit fires on substantive clean sidecar (DONE + empty self_flags); blocks on non-empty self_flags, PARTIAL status, AND field-absent (legacy/external agent safety net)"
else
  fail "K142: short-circuit broken — clean=$K142_CLEAN flagged=$K142_FLAGGED partial=$K142_PARTIAL absent=$K142_ABSENT"
fi

# K143: M2 sidecar schema documentation present in agent files.
# Locks the prompt language that asks agents to populate self_flagged_uncertainties.
K143_PROG=$(/usr/bin/grep -c "self_flagged_uncertainties" agents/programmer.md 2>/dev/null || true)
K143_TESTER=$(/usr/bin/grep -c "self_flagged_uncertainties" agents/tester.md 2>/dev/null || true)
K143_REVIEWER=$(/usr/bin/grep -c "self_flagged_uncertainties" agents/code-reviewer.md 2>/dev/null || true)
if [ "${K143_PROG:-0}" -ge 1 ] && [ "${K143_TESTER:-0}" -ge 1 ] && [ "${K143_REVIEWER:-0}" -ge 1 ]; then
  pass "K143: self_flagged_uncertainties prompt language present in programmer.md + tester.md + code-reviewer.md"
else
  fail "K143: self-flag prompts missing — programmer=$K143_PROG tester=$K143_TESTER reviewer=$K143_REVIEWER"
fi

# K144: M7 stop_details.category routing — hook surfaces category-specific
# refusal hints. Field-evidenced gap: prior to M7 devt only captured stop_reason
# (refusal vs end_turn) but not the structured stop_details.category that Opus 4.7+
# exposes — so all refusals were undifferentiated noise. M7 routes each category.
K144_INPUT='{"tool_name":"Task","tool_input":{"prompt":"test","subagent_type":"devt:programmer"},"tool_response":{"stop_reason":"refusal","stop_details":{"category":"unclear_instruction"}}}'
K144_OUT=$(echo "$K144_INPUT" | bash "$ROOT/hooks/task-truncation-detector.sh" 2>/dev/null || true)
K144_HAS_HINT=$(echo "$K144_OUT" | /usr/bin/grep -c "devt refusal=unclear_instruction" || true)
# Negative case: stop_reason=end_turn → no refusal hint emitted
K144_INPUT_OK='{"tool_name":"Task","tool_input":{"prompt":"test","subagent_type":"devt:programmer"},"tool_response":{"stop_reason":"end_turn"}}'
K144_OUT_OK=$(echo "$K144_INPUT_OK" | bash "$ROOT/hooks/task-truncation-detector.sh" 2>/dev/null || true)
K144_NO_HINT=$(echo "$K144_OUT_OK" | /usr/bin/grep -c "devt refusal=" || true)
if [ "${K144_HAS_HINT:-0}" -ge 1 ] && [ "${K144_NO_HINT:-1}" = "0" ]; then
  pass "K144: task-truncation-detector surfaces category-specific refusal hint (unclear_instruction routed); end_turn does NOT trigger refusal hint"
else
  fail "K144: refusal routing broken — has_hint=$K144_HAS_HINT no_hint_on_end_turn=$K144_NO_HINT"
fi

# K145: F5 _isDocstringNode catches short test-description sentence slips that
# escaped cal #30.0's >=3 whitespace threshold. "Test successful login." (2
# whitespace) was the field-evidenced miss class. Two gates:
#   (a) lowered whitespace threshold (>=2) catches 2-word labels
#   (b) "Test/Tests/Test methods/...ends with ." heuristic catches the
#       narrower class operators recognize as test docstrings.
K145_TEST_SHORT=$(node -e '
const fs=require("fs");
const src=fs.readFileSync("'"$ROOT"'/bin/modules/graphify.cjs","utf8");
// Strip the function signature + closing brace; eval the body in a Function shell.
const m=src.match(/function _isDocstringNode\(label\) \{([\s\S]*?)\n\}/);
if(!m){console.log("notfound");process.exit(1);}
const f=new Function("label", m[1]);
const cases=[
  ["Test successful login.", true],
  ["Tests for ExportService.list_exports.", true],
  ["Stringify value for streaming CSV output, with formula-escape applied.", true],
  ["AuthService", false],
  ["api_login_handler", false],
  ["foo_bar_baz", false],
];
let ok=true;
for(const [label, want] of cases){
  if(f(label) !== want){ ok=false; console.log("MISS:", label, "expected", want, "got", f(label)); }
}
console.log(ok?"1":"0");
' 2>/dev/null | tail -1)
if [ "${K145_TEST_SHORT:-0}" = "1" ]; then
  pass "K145: F5 _isDocstringNode threshold change catches 'Test X.' (2-whitespace) + 'Tests for X.' patterns; real symbols (AuthService/snake_case) still excluded"
else
  fail "K145: F5 docstring threshold broken — see output"
fi

# K146: F4 graphify status surfaces lag_commits by default; --full surfaces
# node_count/edge_count/trust. Reconciles the source of truth so operators
# don't see {state:ready, out_dir:..., graph_path:...} from `graphify status`
# while preflight-brief.json carries the real freshness data.
K146_TMP=$(mktemp -d)
mkdir -p "$K146_TMP/.devt" "$K146_TMP/graphify-out"
echo '{"graphify":{"enabled":true,"command":"graphify-not-on-path"}}' > "$K146_TMP/.devt/config.json"
# Minimal fixture graph.json — node_count/edge_count surface with --full.
cat > "$K146_TMP/graphify-out/graph.json" <<EOF
{"built_at_commit":"abc1234","nodes":[{"id":"a","label":"A","source_file":"a.py","file_type":"code"},{"id":"b","label":"B","source_file":"b.py","file_type":"code"}],"links":[{"source":"a","target":"b","relation":"calls","confidence":"EXTRACTED"}]}
EOF
K146_DEFAULT=$(cd "$K146_TMP" && node "$ROOT/bin/devt-tools.cjs" graphify status 2>/dev/null)
K146_HAS_LAG=$(echo "$K146_DEFAULT" | node -e "let s=''; process.stdin.on('data',d=>s+=d); process.stdin.on('end',()=>{try{const o=JSON.parse(s); console.log(Object.prototype.hasOwnProperty.call(o,'lag_commits')?'1':'0')}catch{console.log('0')}});" 2>/dev/null)
K146_FULL=$(cd "$K146_TMP" && node "$ROOT/bin/devt-tools.cjs" graphify status --full 2>/dev/null)
K146_HAS_COUNTS=$(echo "$K146_FULL" | node -e "let s=''; process.stdin.on('data',d=>s+=d); process.stdin.on('end',()=>{try{const o=JSON.parse(s); console.log(o.node_count===2 && o.edge_count>=1?'1':'0')}catch{console.log('0')}});" 2>/dev/null)
rm -rf "$K146_TMP"
if [ "${K146_HAS_LAG:-0}" = "1" ] && [ "${K146_HAS_COUNTS:-0}" = "1" ]; then
  pass "K146: F4 graphify status surfaces lag_commits by default + --full surfaces node_count/edge_count"
else
  fail "K146: F4 status surfacing broken — has_lag=$K146_HAS_LAG has_counts=$K146_HAS_COUNTS"
fi

# K147: F1 MCP get_neighbors schema declares max_bytes. Without this, the
# graphify-side max_bytes truncation code (graphify.cjs:519) is unreachable
# from the MCP path — field-evidenced bug: ExportService drill-down (8500
# lines / 293KB) overflowed MCP transport because the operator-facing schema
# didn't expose the truncation knob.
K147_HAS_MAX_BYTES=$(/usr/bin/grep -cE 'max_bytes:\s*\{\s*type:\s*"integer"' "$ROOT/bin/devt-graphify-mcp.cjs" 2>/dev/null || true)
