if [ "${K147_HAS_MAX_BYTES:-0}" -ge 1 ] && [ "${K147_HAS_DEFAULT:-0}" -ge 1 ]; then
  pass "K147: F1 MCP get_neighbors schema declares max_bytes property + server-side default 60000 applied"
else
  fail "K147: F1 MCP max_bytes wiring incomplete — has_schema=$K147_HAS_MAX_BYTES has_default=$K147_HAS_DEFAULT"
fi

# K148: F2 getNeighbors filters primitives + test-path nodes. Without this,
# caller-set drill-downs surface ~95% noise (test methods + docstring nodes
# + primitives) burying the production-caller signal operators need. Field
# motivation: AuthenticationService incoming edges receipt #4.
K148_TMP=$(mktemp -d)
mkdir -p "$K148_TMP/.devt" "$K148_TMP/graphify-out"
echo '{"graphify":{"enabled":true,"command":"graphify-not-on-path"}}' > "$K148_TMP/.devt/config.json"
cat > "$K148_TMP/graphify-out/graph.json" <<'EOF'
{"built_at_commit":"abc","nodes":[{"id":"svc","label":"AuthSvc","source_file":"src/auth.py","file_type":"code"},{"id":"prod","label":"real_login","source_file":"src/login.py","file_type":"code"},{"id":"tst","label":"test_login_success","source_file":"tests/test_auth.py","file_type":"code"},{"id":"prim","label":"int","source_file":"<builtin>","file_type":"code"},{"id":"doc","label":"Test successful login.","source_file":"src/foo.py","file_type":"code"}],"links":[{"source":"prod","target":"svc","relation":"calls","confidence":"EXTRACTED"},{"source":"tst","target":"svc","relation":"calls","confidence":"EXTRACTED"},{"source":"prim","target":"svc","relation":"calls","confidence":"EXTRACTED"},{"source":"doc","target":"svc","relation":"rationale_for","confidence":"EXTRACTED"}]}
EOF
K148_RESULT=$(cd "$K148_TMP" && node -e "const g=require('$ROOT/bin/modules/graphify.cjs'); const r=g.getNeighbors('AuthSvc',{direction:'in'}); console.log(JSON.stringify({labels:r.results.map(x=>x.label),fn:r.filtered_noise,ftp:r.filtered_test_path}));" 2>/dev/null)
rm -rf "$K148_TMP"
K148_ONLY_REAL=$(echo "$K148_RESULT" | node -e "let s=''; process.stdin.on('data',d=>s+=d); process.stdin.on('end',()=>{try{const o=JSON.parse(s); console.log(o.labels.length===1 && o.labels[0]==='real_login'?'1':'0')}catch{console.log('0')}});" 2>/dev/null)
K148_TELEMETRY=$(echo "$K148_RESULT" | node -e "let s=''; process.stdin.on('data',d=>s+=d); process.stdin.on('end',()=>{try{const o=JSON.parse(s); console.log(o.fn>=1 && o.ftp>=1?'1':'0')}catch{console.log('0')}});" 2>/dev/null)
if [ "${K148_ONLY_REAL:-0}" = "1" ] && [ "${K148_TELEMETRY:-0}" = "1" ]; then
  pass "K148: F2 getNeighbors filters primitives + test-path + docstring nodes; only production caller surfaces; filter_noise/filter_test_path telemetry emitted"
else
  fail "K148: F2 filter broken — only_real=$K148_ONLY_REAL telemetry=$K148_TELEMETRY result=$K148_RESULT"
fi

# K149: telemetry calibrate CLI mines hook-trace + emits structured report
# with aggregates + recommendations. Field motivation: cal #30.4 M4 — data-
# driven recalibration of guards/caps requires a single CLI mining the
# accumulated .devt/state/hook-trace/run-hook.jsonl + gate-trace.jsonl +
# dispatch-warnings.jsonl. Fixture seeds known data; assertion checks
# aggregator shape + at least one recommendation kind fires.
K149_TMP=$(mktemp -d)
mkdir -p "$K149_TMP/.devt/state/hook-trace"
# Hook with high non-zero exit rate (should trip hook_error_pattern recommendation)
for i in $(seq 1 60); do
  echo '{"ts":"2026-06-01T00:00:00Z","script":"flaky-hook.sh","profile":"standard","enabled":true,"stdin_bytes":100,"stdout_bytes":50,"stderr_bytes":500,"exit":1}' >> "$K149_TMP/.devt/state/hook-trace/run-hook.jsonl"
done
for i in $(seq 1 40); do
  echo '{"ts":"2026-06-01T00:00:00Z","script":"flaky-hook.sh","profile":"standard","enabled":true,"stdin_bytes":100,"stdout_bytes":50,"stderr_bytes":0,"exit":0}' >> "$K149_TMP/.devt/state/hook-trace/run-hook.jsonl"
done
K149_RESULT=$(cd "$K149_TMP" && node "$ROOT/bin/devt-tools.cjs" telemetry calibrate 2>/dev/null)
rm -rf "$K149_TMP"
K149_HAS_HOOKS=$(echo "$K149_RESULT" | node -e "let s=''; process.stdin.on('data',d=>s+=d); process.stdin.on('end',()=>{try{const o=JSON.parse(s); console.log(o.hooks && o.hooks['flaky-hook.sh'] && o.hooks['flaky-hook.sh'].count===100?'1':'0')}catch{console.log('0')}});" 2>/dev/null)
K149_HAS_ERROR_REC=$(echo "$K149_RESULT" | node -e "let s=''; process.stdin.on('data',d=>s+=d); process.stdin.on('end',()=>{try{const o=JSON.parse(s); console.log((o.recommendations||[]).some(r=>r.kind==='hook_error_pattern'&&r.target==='flaky-hook.sh')?'1':'0')}catch{console.log('0')}});" 2>/dev/null)
if [ "${K149_HAS_HOOKS:-0}" = "1" ] && [ "${K149_HAS_ERROR_REC:-0}" = "1" ]; then
  pass "K149: telemetry calibrate CLI aggregates hook-trace + emits hook_error_pattern recommendation when nonzero rate >10% over >=50 fires"
else
  fail "K149: telemetry analyzer broken — has_hooks=$K149_HAS_HOOKS has_error_rec=$K149_HAS_ERROR_REC"
fi

# K150: telemetry calibrate flags hook_low_value when hook always silent
# (exit=0 + stdout=0 on >=95% of fires). Catches hooks that quietly do
# nothing — disable candidates or evidence of broken instrumentation.
K150_TMP=$(mktemp -d)
mkdir -p "$K150_TMP/.devt/state/hook-trace"
for i in $(seq 1 50); do
  echo '{"ts":"2026-06-01T00:00:00Z","script":"silent-hook.sh","profile":"standard","enabled":true,"stdin_bytes":50,"stdout_bytes":0,"stderr_bytes":0,"exit":0}' >> "$K150_TMP/.devt/state/hook-trace/run-hook.jsonl"
done
K150_RESULT=$(cd "$K150_TMP" && node "$ROOT/bin/devt-tools.cjs" telemetry calibrate 2>/dev/null)
rm -rf "$K150_TMP"
K150_HAS_LOW_VALUE=$(echo "$K150_RESULT" | node -e "let s=''; process.stdin.on('data',d=>s+=d); process.stdin.on('end',()=>{try{const o=JSON.parse(s); console.log((o.recommendations||[]).some(r=>r.kind==='hook_low_value'&&r.target==='silent-hook.sh')?'1':'0')}catch{console.log('0')}});" 2>/dev/null)
if [ "${K150_HAS_LOW_VALUE:-0}" = "1" ]; then
  pass "K150: telemetry calibrate flags hook_low_value when hook exits 0 with stdout=0 on >=95% of fires"
else
  fail "K150: hook_low_value recommendation not emitted on always-silent fixture"
fi

# K151-K154: M3 (cal #30.5) — `dispatch run-lanes` ergonomic launcher
# bundles register-lanes (from --partition) + render-lanes + 4 directive
# shapes (per-lane focus, global task suffix, diff base) into one CLI call.
# Per [[feedback_canonical_path_expressiveness]]: without these, operators
# hand-roll dispatches and devt loses canonical-path adoption.
K151_TMP=$(mktemp -d)
mkdir -p "$K151_TMP/.devt/state"
cat > "$K151_TMP/.devt/state/workflow.yaml" <<EOF
active: true
workflow_id: k151abcd-x
workflow_type: code_review
task: "k151 test"
EOF
cat > "$K151_TMP/partition.yaml" <<EOF
lanes:
  - id: L1
    scope: auth
    files: [src/auth.py]
  - id: L2
    scope: reports
    files: [src/reports.py]
EOF
echo "Check: ADR-001 + CON-002" > "$K151_TMP/suffix.txt"
K151_OUT=$(cd "$K151_TMP" && PRIMARY_BRANCH=develop node "$ROOT/bin/devt-tools.cjs" dispatch run-lanes \
  --partition=partition.yaml \
  --lane-L1-focus="trace event chain" \
  --lane-L2-focus="check p20 coverage" \
  --task-suffix=suffix.txt \
  --base=feature/x 2>&1)
rm -rf "$K151_TMP"

# K151: --partition file registers lanes that render-lanes consumes
K151_HAS_BOTH_LANES=$(echo "$K151_OUT" | /usr/bin/grep -cE "<lane_id>L[12]</lane_id>" || true)
if [ "${K151_HAS_BOTH_LANES:-0}" = "2" ]; then
  pass "K151: dispatch run-lanes --partition=<file> registers + renders both lanes from partition YAML"
else
  fail "K151: --partition did not produce both lane envelopes (got $K151_HAS_BOTH_LANES <lane_id> blocks)"
fi

# K152: --lane-N-focus injects per-lane focus into the matching envelope only
K152_L1_FOCUS=$(echo "$K151_OUT" | /usr/bin/grep -c "<lane_focus>trace event chain</lane_focus>" || true)
K152_L2_FOCUS=$(echo "$K151_OUT" | /usr/bin/grep -c "<lane_focus>check p20 coverage</lane_focus>" || true)
if [ "${K152_L1_FOCUS:-0}" = "1" ] && [ "${K152_L2_FOCUS:-0}" = "1" ]; then
  pass "K152: --lane-N-focus injects each focus directive into its matching lane envelope (no cross-contamination)"
else
  fail "K152: --lane-N-focus broken — L1_focus=$K152_L1_FOCUS L2_focus=$K152_L2_FOCUS"
fi

# K153: --task-suffix file content injected globally (every lane envelope)
K153_SUFFIX_COUNT=$(echo "$K151_OUT" | /usr/bin/grep -c "<task_suffix>Check: ADR-001 + CON-002</task_suffix>" || true)
if [ "${K153_SUFFIX_COUNT:-0}" = "2" ]; then
  pass "K153: --task-suffix=<file> content injected into every lane envelope (2 lanes → 2 occurrences)"
else
  fail "K153: --task-suffix not global — got $K153_SUFFIX_COUNT occurrences, expected 2"
fi

# K154: --base=<ref> overrides PRIMARY_BRANCH env in <diff_base> block
K154_BASE_COUNT=$(echo "$K151_OUT" | /usr/bin/grep -c "<diff_base>feature/x</diff_base>" || true)
if [ "${K154_BASE_COUNT:-0}" = "2" ]; then
  pass "K154: --base=<ref> overrides PRIMARY_BRANCH env in <diff_base> block (2 lanes → 2 occurrences of feature/x)"
else
  fail "K154: --base override broken — got $K154_BASE_COUNT occurrences of feature/x, expected 2"
fi

# K155: CLAUDE.md hook profile table is in sync with hooks/hooks.json.
# Field-evidenced drift: dispatch-scope-guard.sh was merged into
# dispatch-hygiene-guard.sh on 2026-06-15 (commit 4057666); the CLAUDE.md
# hook-profile table at L39 still listed the deleted script 4 days later,
# surfaced only by manual audit. Meta-gate compares the canonical
# registered-hooks set (hooks/hooks.json) against the documented set
# (markdown table rows in CLAUDE.md) and fails on either-direction drift.
K155_REGISTERED=$(node -e "
  const h = JSON.parse(require('fs').readFileSync('$ROOT/hooks/hooks.json','utf8'));
  const scripts = new Set();
  function walk(o){
    if (Array.isArray(o)) o.forEach(walk);
    else if (o && typeof o === 'object') for (const v of Object.values(o)) walk(v);
    else if (typeof o === 'string') { const m = o.match(/([a-z-]+\.sh)\b/); if (m) scripts.add(m[1]); }
  }
  walk(h);
  console.log([...scripts].sort().join('\n'));
" 2>/dev/null || echo "")
K155_DOCUMENTED=$(/usr/bin/grep -oE '^\| `[a-z-]+\.sh`' "$ROOT/CLAUDE.md" 2>/dev/null | tr -d '`' | sed 's/^| //' | sort -u || echo "")
# pipefail-safe: comm + tr + sed in a process-sub pipeline can return nonzero under
# set -o pipefail when one side is empty. Wrap in `|| true` so the assignment
# always succeeds; treat missing data as "no drift" (the only false-negative is
# a CI infra issue, and that surfaces in the K155_REGISTERED/DOCUMENTED probes
# above when they short-circuit to empty string via the `|| echo ""` guards).
K155_MISSING_FROM_DOCS=$( { comm -23 <(echo "$K155_REGISTERED") <(echo "$K155_DOCUMENTED") || true; } | tr '\n' ',' | sed 's/,$//')
K155_STALE_IN_DOCS=$( { comm -13 <(echo "$K155_REGISTERED") <(echo "$K155_DOCUMENTED") || true; } | tr '\n' ',' | sed 's/,$//')
if [ -z "${K155_MISSING_FROM_DOCS:-}" ] && [ -z "${K155_STALE_IN_DOCS:-}" ]; then
  pass "K155: CLAUDE.md hook profile table matches hooks/hooks.json registered scripts (no drift)"
else
  fail "K155: hook table drift — missing_from_docs=[$K155_MISSING_FROM_DOCS] stale_in_docs=[$K155_STALE_IN_DOCS]"
fi

# K156: case-handler ⊃ default-case enumeration drift gate. Walks every
# bin/modules/*.cjs; extracts `case "X":` handlers + the sibling "Unknown
# <mod> subcommand. Use: A | B | C" enumeration; asserts handlers ⊆ enum.
# Catches the class where a new handler ships without updating its enum,
# so `<mod> <typo>` returns a stale subcommand list missing the new entry.
# ALLOW_NO_ENUM: modules with handlers but NO enumeration by design
# (top-level dispatchers, not subcommand routers — init.cjs only).
# Inversion: silent-skip would re-introduce the drift class; explicit
# allow-list makes the exception visible.
K156_RESULT=$(node -e "
const fs = require('fs');
const path = require('path');
const dir = '$ROOT/bin/modules';
const ALLOW_NO_ENUM = new Set(['init.cjs']); // top-level dispatcher; subcommands live in callee modules
const drifts = [];
const missingEnum = [];
for (const f of fs.readdirSync(dir).filter(n => n.endsWith('.cjs'))) {
  const src = fs.readFileSync(path.join(dir, f), 'utf8');
  const handlers = new Set();
  for (const m of src.matchAll(/\n\s+case \"([a-z0-9-]+)\":/g)) handlers.add(m[1]);
  if (handlers.size === 0) continue;
  // Single alternation regex covers both canonical enumeration shapes:
  //   (a) 'Unknown <mod> subcommand' — state/memory/graphify/etc.
  //   (b) 'Usage: <mod> <a|b|c>' (pipe-delimited) — dispatch.cjs
  const unknownIdx = src.search(/Unknown [a-z-]+ subcommand|Usage: [a-z-]+ <[a-z|-]+>/);
  if (unknownIdx === -1) {
    if (!ALLOW_NO_ENUM.has(f)) missingEnum.push(f);
    continue;
  }
  const enumBlock = src.slice(unknownIdx, unknownIdx + 2000);
  // Stop at the closing backtick + semicolon of the template literal
  // (the two trailing >\\\\n alternatives in the prior version were dead —
  // dispatch.cjs's Usage is a single-line string and template-literal
  // terminator hits first; dropped them).
  const enumEnd = enumBlock.search(/\`,\s*\)?\s*;|\`\s*\n\s*\)/);
  const enumText = enumEnd === -1 ? enumBlock : enumBlock.slice(0, enumEnd);
  const enumTokens = new Set();
  for (const m of enumText.matchAll(/[a-z][a-z0-9-]+/g)) enumTokens.add(m[0]);
  const missing = [...handlers].filter(h => !enumTokens.has(h)).sort();
  if (missing.length > 0) drifts.push({ module: f, handlers: handlers.size, missing });
}
// Emit single JSON with both drift kinds so we don't need a second node spawn to count.
console.log(JSON.stringify({ drifts, missingEnum }));
")
K156_DRIFTS=$(echo "$K156_RESULT" | node -e "let s='';process.stdin.on('data',d=>s+=d);process.stdin.on('end',()=>{try{const o=JSON.parse(s);console.log(o.drifts.length+'|'+o.missingEnum.length+'|'+JSON.stringify(o))}catch{console.log('-1|-1|parse-error')}});" 2>/dev/null)
K156_DRIFT_COUNT=$(echo "$K156_DRIFTS" | cut -d'|' -f1)
K156_MISSING_ENUM_COUNT=$(echo "$K156_DRIFTS" | cut -d'|' -f2)
if [ "${K156_DRIFT_COUNT:-1}" = "0" ] && [ "${K156_MISSING_ENUM_COUNT:-1}" = "0" ]; then
  pass "K156: case-handler ⊃ default-case enumeration drift gate (all bin/modules/*.cjs aligned; ALLOW_NO_ENUM covers init.cjs only)"
else
  fail "K156: drift_count=$K156_DRIFT_COUNT missing_enum_count=$K156_MISSING_ENUM_COUNT — $(echo "$K156_DRIFTS" | cut -d'|' -f3-)"
fi

# K157: preflight-brief.json staleness banner fires when artifact mtime is >4h
# older than workflow.yaml::created_at (closes .devt/state/ artifact-age gap
# beyond workflow.yaml-age check). Asserts: 8h-stale fixture → banner emitted.
K157_TMP=$(mktemp -d)
mkdir -p "$K157_TMP/.devt/state"
cat > "$K157_TMP/.devt/state/workflow.yaml" <<EOF
active: true
workflow_id: k157
workflow_type: dev
task: "k157 test"
created_at: "$(date -u +%Y-%m-%dT%H:%M:%S.000Z)"
EOF
echo '{}' > "$K157_TMP/.devt/state/preflight-brief.json"
# Backdate brief by 8h (cross-platform: BSD touch -t vs GNU touch -d)
touch -t "$(date -v-8H +%Y%m%d%H%M 2>/dev/null || date -d '8 hours ago' +%Y%m%d%H%M 2>/dev/null)" "$K157_TMP/.devt/state/preflight-brief.json" 2>/dev/null
K157_OUT=$(cd "$K157_TMP" && echo '{"hook_event_name":"UserPromptSubmit","prompt":"x"}' | bash "$ROOT/hooks/workflow-context-injector.sh" 2>/dev/null || true)
rm -rf "$K157_TMP"
K157_HAS_STALE=$(echo "$K157_OUT" | /usr/bin/grep -c "preflight-brief\.json STALE" || true)
if [ "${K157_HAS_STALE:-0}" -ge 1 ]; then
  pass "K157: workflow-context-injector emits preflight-brief STALE banner when artifact mtime > 4h older than workflow.yaml::created_at"
else
  fail "K157: C2' preflight staleness banner not emitted on 8h-stale fixture"
fi

# K158: dispatch-hygiene-guard KILL message carries per-subagent canonical CLI
