fi

# K191: symbolsInFiles signal-quality overhaul (cal #38.A from receipt #10).
# Three asserts in one synthetic graph: (1) full-path suffix match kills
# cross-module basename pollution — a same-named symbol in a DIFFERENT module
# does not leak in; (2) dedup — a duplicate label appears once; (3) hunk-scoping
# via a real git diff — a god-node defined OUTSIDE the changed hunk is dropped
# while the changed symbol survives.
K191_TMP=$(mktemp -d)
mkdir -p "$K191_TMP/.devt" "$K191_TMP/graphify-out"
echo '{"graphify":{"enabled":true,"command":"graphify"}}' > "$K191_TMP/.devt/config.json"
cd "$K191_TMP"
git init -q; git config user.email t@t.t; git config user.name t
printf 'class Foo:\n    pass\n# f\n# f\n# f\n# f\n# f\n# f\nclass AppError:\n    pass\n' > models.py
git add -A; git commit -qm base >/dev/null 2>&1
K191_BASE=$(git rev-parse HEAD)
printf 'class Foo:\n    x = 1\n# f\n# f\n# f\n# f\n# f\n# f\nclass AppError:\n    pass\n' > models.py
git add -A; git commit -qm change >/dev/null 2>&1
node -e "
const fs=require('fs');
const nodes=[
  {id:'a.Foo',label:'Foo',source_file:'svc/external/models.py',source_location:'L1',file_type:'code'},
  {id:'b.Foo',label:'Foo',source_file:'svc/agenda/models.py',source_location:'L1',file_type:'code'},
  {id:'AppError',label:'AppError',source_file:'models.py',source_location:'L9',file_type:'code'},
  {id:'FooLocal',label:'FooLocal',source_file:'models.py',source_location:'L1',file_type:'code'},
  {id:'Dup',label:'Dup',source_file:'models.py',source_location:'L2',file_type:'code'},
  {id:'Dup2',label:'Dup',source_file:'models.py',source_location:'L2',file_type:'code'},
];
const links=[];
for(let i=0;i<200;i++){nodes.push({id:'e'+i,label:'E'+i,source_file:'z.py',file_type:'code'});links.push({source:'e'+i,target:'AppError',relation:'raises'});}
fs.writeFileSync('graphify-out/graph.json',JSON.stringify({built_at_commit:'abc',nodes,links}));
"
# Test cross-module + dedup (no baseRef): query svc/external/models.py → only that Foo, Dup once
K191_XMOD=$(node -e "const g=require('$ROOT/bin/modules/graphify.cjs');const r=g.symbolsInFiles(['svc/external/models.py']);const l=r.symbols.map(s=>s.symbol);console.log(l.filter(x=>x==='Foo').length);" 2>/dev/null)
# Test hunk-scoping (baseRef): models.py changed at L1-2, AppError defined L9 → dropped
K191_HUNK=$(node -e "const g=require('$ROOT/bin/modules/graphify.cjs');const r=g.symbolsInFiles(['models.py'],25,{baseRef:'$K191_BASE'});const l=r.symbols.map(s=>s.symbol);console.log('foolocal='+(l.includes('FooLocal')?'1':'0')+',apperr='+(l.includes('AppError')?'1':'0')+',dup='+l.filter(x=>x==='Dup').length);" 2>/dev/null)
cd "$ROOT"; rm -rf "$K191_TMP"
if [ "$K191_XMOD" = "1" ] && echo "$K191_HUNK" | /usr/bin/grep -q "foolocal=1,apperr=0,dup=1"; then
  pass "K191: symbolsInFiles full-path-match (cross-module killed) + dedup (Dup once) + hunk-scoping (AppError outside changed hunk dropped, FooLocal kept)"
else
  fail "K191: signal-quality wrong — xmod_Foo=$K191_XMOD (expect 1), hunk=$K191_HUNK (expect foolocal=1,apperr=0,dup=1)"
fi

# K192: god-node alarm-fatigue discrimination (cal #38.B from receipt #10
# finding #4). A synthetic graph with one DOMINANT hub (degree ~1000) + one
# moderate god-node (degree ~60 near the top-10 floor). Asserts: (1) touching
# the dominant hub → god_node_match=true but discriminating=false (ubiquitous,
# downgraded to info note); (2) touching the moderate god-node →
# discriminating=true (⚠️ fires); (3) config ubiquitous_types "!Hub" force-keep
# makes the hub discriminating again (refactor-exempt path).
K192_TMP=$(mktemp -d)
mkdir -p "$K192_TMP/.devt" "$K192_TMP/graphify-out"
echo '{"graphify":{"enabled":true,"command":"graphify"}}' > "$K192_TMP/.devt/config.json"
node -e "
const fs=require('fs');
const nodes=[
  {id:'Hub',label:'Hub',source_file:'errors.py',source_location:'L1',file_type:'code'},
  {id:'Mid',label:'Mid',source_file:'svc.py',source_location:'L1',file_type:'code'}
];
const links=[];
for(let i=0;i<1000;i++){nodes.push({id:'a'+i,label:'A'+i,source_file:'a.py',file_type:'code'});links.push({source:'a'+i,target:'Hub',relation:'raises'});}
for(let i=0;i<60;i++){nodes.push({id:'c'+i,label:'C'+i,source_file:'c.py',file_type:'code'});links.push({source:'c'+i,target:'Mid',relation:'calls'});}
for(let gi=0;gi<8;gi++){const gid='G'+gi;nodes.push({id:gid,label:'God'+gi,source_file:'g'+gi+'.py',file_type:'code'});for(let i=0;i<40+gi;i++){nodes.push({id:gid+'_'+i,label:gid+'_'+i,source_file:'gx.py',file_type:'code'});links.push({source:gid+'_'+i,target:gid,relation:'calls'});}}
fs.writeFileSync('$K192_TMP/graphify-out/graph.json',JSON.stringify({built_at_commit:'abc',nodes,links}));
"
K192_HUB=$(cd "$K192_TMP" && node -e "const g=require('$ROOT/bin/modules/graphify.cjs');const r=g.blastRadius(['Hub']);console.log((r.god_node_match?'1':'0')+(r.discriminating_god_node_match?'1':'0'));" 2>/dev/null)
K192_MID=$(cd "$K192_TMP" && node -e "const g=require('$ROOT/bin/modules/graphify.cjs');const r=g.blastRadius(['Mid']);console.log((r.god_node_match?'1':'0')+(r.discriminating_god_node_match?'1':'0'));" 2>/dev/null)
echo '{"graphify":{"enabled":true,"command":"graphify","ubiquitous_types":["!Hub"]}}' > "$K192_TMP/.devt/config.json"
K192_KEEP=$(cd "$K192_TMP" && node -e "const g=require('$ROOT/bin/modules/graphify.cjs');const r=g.blastRadius(['Hub']);console.log(r.discriminating_god_node_match?'1':'0');" 2>/dev/null)
rm -rf "$K192_TMP"
# Hub: match=1 discriminating=0 → "10"; Mid: match=1 discriminating=1 → "11"; force-keep → "1"
if [ "$K192_HUB" = "10" ] && [ "$K192_MID" = "11" ] && [ "$K192_KEEP" = "1" ]; then
  pass "K192: god-node alarm-fatigue discrimination — dominant hub suppressed (info note), moderate god-node fires ⚠️, config !force-keep exempts a refactored hub"
else
  fail "K192: discrimination wrong — Hub=$K192_HUB (expect 10), Mid=$K192_MID (expect 11), forceKeep=$K192_KEEP (expect 1)"
fi

# K193: cal #38.C robustness trio (receipt #10 findings #3 + #6 + #4-stall).
# (C1) queryGraph token fallback — a multi-word query that matches no single
# node label whole-string resolves via token_and/token_or instead of empty;
# (C2) state disk-check CLI returns a warn-only envelope {ok:true, status,
# free_mb}; (C3) code-reviewer.md carries the incremental-write directive so a
# budget/disk wall costs the last finding, not the whole analysis.
K193_TMP=$(mktemp -d)
mkdir -p "$K193_TMP/.devt" "$K193_TMP/graphify-out"
echo '{"graphify":{"enabled":true,"command":"graphify"}}' > "$K193_TMP/.devt/config.json"
node -e "
const fs=require('fs');
const nodes=[
  {id:'OAuthTokenService',label:'OAuthTokenService',source_file:'a.py',file_type:'code'},
  {id:'OrchestrationService',label:'OrchestrationService',source_file:'b.py',file_type:'code'}
];
fs.writeFileSync('$K193_TMP/graphify-out/graph.json',JSON.stringify({built_at_commit:'abc',nodes,links:[]}));
"
# C1: multi-word query that matches no whole-string label
K193_C1=$(cd "$K193_TMP" && node -e "const g=require('$ROOT/bin/modules/graphify.cjs');const r=g.queryGraph('orchestration service OAuthTokenService');console.log((r.results&&r.results.length>0?'1':'0')+':'+(r.resolution_mode||'none'));" 2>/dev/null)
# C2: disk-check envelope shape (warn-only — ok always true, never blocks)
K193_C2=$(cd "$K193_TMP" && node "$ROOT/bin/devt-tools.cjs" state disk-check 2>/dev/null | node -e "let s='';process.stdin.on('data',d=>s+=d);process.stdin.on('end',()=>{try{const o=JSON.parse(s);console.log((o.ok===true && (o.status==='ok'||o.status==='warn'||o.status==='unknown') && ('free_mb' in o))?'1':'0')}catch{console.log('0')}});" 2>/dev/null)
rm -rf "$K193_TMP"
# C3: incremental-write directive present in code-reviewer.md
K193_C3=$(/usr/bin/grep -c "Write findings incrementally" "$ROOT/agents/code-reviewer.md" 2>/dev/null || echo 0)
if echo "$K193_C1" | /usr/bin/grep -qE "^1:token_(and|or)$" && [ "$K193_C2" = "1" ] && [ "$K193_C3" -ge "1" ]; then
  pass "K193: cal #38.C robustness — queryGraph token fallback (multi-word resolves via token_and/or), disk-check warn-only envelope, code-reviewer incremental-write directive"
else
  fail "K193: robustness trio wrong — C1=$K193_C1 (expect 1:token_and|or), C2=$K193_C2 (expect 1), C3=$K193_C3 (expect ≥1)"
fi

# K194: stays-general guardrail meta-gate (cal #38.D). CI-enforces that the
# product surfaces (bin/modules + workflows + agents) carry NO field-test-
# project coupling — the fix for any field-surfaced bug must be a GENERAL
# mechanism, never hardcoded to the field-test project. Checks for the
# field project's name (as an api/path token) + three of its distinctive
# symbol names (assembled from fragments so this gate's own pattern can't be
# what a future search trips on). Generic-term "greenfield" (a fresh project
# with no existing code) is legitimate and deliberately NOT matched. Prevents
# regression of the cal #38.D decoupling pass.
K194_PAT="green""field-api|/Projects/green""field|Vicasa""CallProvider|Test""MappingExtractors|Nettie""Calendar"
# `|| true`: 0 matches is the PASS case but grep exits 1 there, which
# pipefail+set -e would otherwise treat as a suite abort.
K194_HITS=$({ /usr/bin/grep -rniE "$K194_PAT" "$ROOT/bin/modules/" "$ROOT/workflows/" "$ROOT/agents/" 2>/dev/null || true; } | wc -l | tr -d ' ')
if [ "$K194_HITS" = "0" ]; then
  pass "K194: stays-general guardrail — zero field-test-project coupling (name/path/symbols) in bin/modules + workflows + agents"
else
  fail "K194: field-test-project coupling regressed — $K194_HITS hit(s) in product surfaces; fixes must generalize, not hardcode the field-test project"
fi

# K195: lane state-mutation guard (cal #37 #2). workflow.yaml + workflow_id are
# orchestrator-owned; a lane subagent rotating/resetting them mid-fan-out is
# the concurrent-rotation corruption. The CLI self-guards: when a FRESH
# "running" subagent exists in status.json, `state update` (workflow_id
# rotation) + `state reset-soft` THROW, while `state update-lane` (the safe
# lane path that never touches workflow_id) is allowed. With no status.json
# (normal op) nothing is blocked. Asserts: (1) fresh-running → first-activation
# blocked, (2) fresh-running → reset-soft blocked, (3) update-lane allowed,
# (4) no status.json → allowed, (5) stale running (crash leak) → allowed.
K195_TMP=$(mktemp -d)
mkdir -p "$K195_TMP/.devt/state"
echo '{}' > "$K195_TMP/.devt/config.json"
K195_NOW=$(date -u +"%Y-%m-%dT%H:%M:%SZ")
K195_OLD=$(node -e "console.log(new Date(Date.now()-2*3600*1000).toISOString().replace(/\.[0-9]+Z/,'Z'))")
_k195det() { node -e "let s='';process.stdin.on('data',d=>s+=d);process.stdin.on('end',()=>process.stdout.write(/lane_state_guard/.test(s)?'BLOCKED':'allowed'))"; }
# (4) no status.json → first-activation allowed. `|| true` on each: a BLOCKED
# command correctly exits 1, which pipefail+set -e would otherwise treat as a
# suite abort — the detector already captured the verdict before exit matters.
K195_NOFILE=$(cd "$K195_TMP" && node "$ROOT/bin/devt-tools.cjs" state update active=true workflow_type=code_review task=x 2>&1 | _k195det || true)
# (1) fresh running → first-activation blocked (fresh dir)
K195_T1=$(mktemp -d); mkdir -p "$K195_T1/.devt/state"; echo '{}' > "$K195_T1/.devt/config.json"
printf '{"agents":{"devt_code-reviewer":{"status":"running","timestamp":"%s"}}}' "$K195_NOW" > "$K195_T1/.devt/state/status.json"
K195_BLOCK1=$(cd "$K195_T1" && node "$ROOT/bin/devt-tools.cjs" state update active=true workflow_type=code_review task=x 2>&1 | _k195det || true)
# (2) fresh running → reset-soft blocked (activate first w/o status.json, then add it)
K195_T2=$(mktemp -d); mkdir -p "$K195_T2/.devt/state"; echo '{}' > "$K195_T2/.devt/config.json"
(cd "$K195_T2" && node "$ROOT/bin/devt-tools.cjs" state update active=true workflow_type=code_review task=x >/dev/null 2>&1) || true
printf '{"agents":{"devt_x":{"status":"running","timestamp":"%s"}}}' "$K195_NOW" > "$K195_T2/.devt/state/status.json"
K195_BLOCK2=$(cd "$K195_T2" && node "$ROOT/bin/devt-tools.cjs" state reset-soft 2>&1 | _k195det || true)
# (3) update-lane allowed even with fresh running
K195_LANE=$(cd "$K195_T2" && node "$ROOT/bin/devt-tools.cjs" state update-lane L1 status=substance_pass 2>&1 | _k195det || true)
# (5) stale running → first-activation allowed
K195_T5=$(mktemp -d); mkdir -p "$K195_T5/.devt/state"; echo '{}' > "$K195_T5/.devt/config.json"
printf '{"agents":{"devt_x":{"status":"running","timestamp":"%s"}}}' "$K195_OLD" > "$K195_T5/.devt/state/status.json"
K195_STALE=$(cd "$K195_T5" && node "$ROOT/bin/devt-tools.cjs" state update active=true workflow_type=code_review task=x 2>&1 | _k195det || true)
rm -rf "$K195_TMP" "$K195_T1" "$K195_T2" "$K195_T5"
if [ "$K195_NOFILE" = "allowed" ] && [ "$K195_BLOCK1" = "BLOCKED" ] && [ "$K195_BLOCK2" = "BLOCKED" ] && [ "$K195_LANE" = "allowed" ] && [ "$K195_STALE" = "allowed" ]; then
  pass "K195: lane state-mutation guard — fresh-running blocks update(first-activation)+reset-soft; update-lane allowed; no-status-file + stale-running allowed"
else
  fail "K195: lane_state_guard wrong — nofile=$K195_NOFILE(exp allowed), block1=$K195_BLOCK1(exp BLOCKED), block2=$K195_BLOCK2(exp BLOCKED), lane=$K195_LANE(exp allowed), stale=$K195_STALE(exp allowed)"
fi

# K196: shared ubiquitous-type stoplist on the symbolsInFiles G5 new-file
# fallback (cal #38.B item 6 — closes the gap where the stoplist was wired
# into god-node warnings but NOT the un-indexed-file fallback). The graph has
# no nodes for a new file, so hunk-scoping can't anchor it; a regex-extracted
# declaration whose NAME matches a ubiquitous god-node is dropped from the
# blast anchors while a genuinely-new symbol survives. Synthetic graph: one
# DOMINANT hub (AppError) → ubiquitous; a new file declares NewProvider + a
# colliding AppError. Asserts NewProvider kept, AppError filtered, telemetry
# counter surfaced.
K196_TMP=$(mktemp -d)
mkdir -p "$K196_TMP/.devt" "$K196_TMP/graphify-out"
echo '{"graphify":{"enabled":true,"command":"graphify"}}' > "$K196_TMP/.devt/config.json"
node -e "
const fs=require('fs');
const nodes=[{id:'AppError',label:'AppError',source_file:'errors.py',file_type:'code'}];
const links=[];
for(let i=0;i<1000;i++){nodes.push({id:'a'+i,label:'A'+i,source_file:'a.py',file_type:'code'});links.push({source:'a'+i,target:'AppError',relation:'raises'});}
for(let gi=0;gi<9;gi++){const gid='G'+gi;nodes.push({id:gid,label:'God'+gi,source_file:'g'+gi+'.py',file_type:'code'});for(let i=0;i<40;i++){nodes.push({id:gid+'_'+i,label:gid+'_'+i,source_file:'gx.py',file_type:'code'});links.push({source:gid+'_'+i,target:gid,relation:'calls'});}}
fs.writeFileSync('$K196_TMP/graphify-out/graph.json',JSON.stringify({built_at_commit:'abc',nodes,links}));
fs.writeFileSync('$K196_TMP/new_mod.py','class NewProvider:\n    pass\n\nclass AppError:\n    pass\n');
"
K196_OUT=$(cd "$K196_TMP" && node -e "const g=require('$ROOT/bin/modules/graphify.cjs');const r=g.symbolsInFiles(['new_mod.py']);const l=r.symbols.map(s=>s.symbol);console.log('new='+(l.includes('NewProvider')?'1':'0')+',app='+(l.includes('AppError')?'1':'0')+',filt='+(r.fallback_ubiquitous_filtered||0));" 2>/dev/null)
rm -rf "$K196_TMP"
if echo "$K196_OUT" | /usr/bin/grep -q "new=1,app=0,filt=1"; then
  pass "K196: symbolsInFiles G5 new-file fallback applies the shared ubiquitous-type stoplist (fresh symbol kept; god-node-named declaration dropped + telemetry)"
else
  fail "K196: new-file fallback stoplist wrong — got '$K196_OUT' (expect new=1,app=0,filt=1)"
fi

# K197: docs/STATE-RULES.md documents every RESET_EXEMPT canonical filename
# (doc-drift meta-gate). RESET_EXEMPT grows as forensic logs are added
# (workflow-id-rotations.jsonl, graphify-impact-plan.json, …); without this
# guard STATE-RULES.md silently drifts behind the contract — the exact drift
# this gate was added to catch (the doc claimed "5 entries" at 8 actual).
# Extracts the Set's line-start quoted members (mid-line comment artifacts like
# "args VERBATIM" are not at line-start, so excluded) and asserts each appears
# in STATE-RULES.md. Same structural-guard class as K117/K156/K194.
K197_MISSING=$(node -e "
  const fs=require('fs');
  const src=fs.readFileSync('$ROOT/bin/modules/state.cjs','utf8');
  const doc=fs.readFileSync('$ROOT/docs/STATE-RULES.md','utf8');
  const m=src.match(/const RESET_EXEMPT = new Set\(\[([\s\S]*?)\]\)/);
  const entries=[];
  if(m){ for(const line of m[1].split('\n')){ const q=line.match(/^\s*\"([^\"]+)\"/); if(q) entries.push(q[1]); } }
  process.stdout.write(entries.filter(e=>!doc.includes(e)).join(' '));
" 2>/dev/null)
if [ -z "$K197_MISSING" ]; then
  pass "K197: docs/STATE-RULES.md documents every RESET_EXEMPT canonical filename (no contract↔doc drift)"
else
  fail "K197: STATE-RULES.md missing RESET_EXEMPT entries: $K197_MISSING"
fi

# K198: cal #39.A substance-check hard-fail + lane_failed coverage + Q5a DI-opaque
# surface. Three asserts: (a) checkAgentOutput on a MISSING file returns
# looks_like_stub:true + missing:true (was looks_like_stub:false → silently
# passed the stub-grep consumers, receipt #11 L9 race); (b) a zero-byte file →
# looks_like_stub:true + empty:true; (c) `lane_failed` is an accepted lane
# status (coverage-honesty terminal, distinct from deferred). Plus Q5a:
# blastRadius surfaces di_opaque + caller source_files when DI-collapse
# dominates the visible direct set.
K198_TMP=$(mktemp -d)
mkdir -p "$K198_TMP/.devt/state" "$K198_TMP/graphify-out"
echo '{"graphify":{"enabled":true,"command":"graphify"}}' > "$K198_TMP/.devt/config.json"
# (a) missing
K198_MISS=$(cd "$K198_TMP" && node "$ROOT/bin/devt-tools.cjs" state check-agent-output .devt/state/nope.md 2>/dev/null | node -e "let s='';process.stdin.on('data',d=>s+=d);process.stdin.on('end',()=>{const o=JSON.parse(s);process.stdout.write((o.looks_like_stub===true&&o.missing===true)?'1':'0')})")
# (b) zero-byte
: > "$K198_TMP/.devt/state/empty.md"
K198_EMPTY=$(cd "$K198_TMP" && node "$ROOT/bin/devt-tools.cjs" state check-agent-output .devt/state/empty.md 2>/dev/null | node -e "let s='';process.stdin.on('data',d=>s+=d);process.stdin.on('end',()=>{const o=JSON.parse(s);process.stdout.write((o.looks_like_stub===true&&o.empty===true)?'1':'0')})")
# (c) lane_failed accepted
cd "$K198_TMP" && node "$ROOT/bin/devt-tools.cjs" state update active=true workflow_type=code_review_parallel task=x >/dev/null 2>&1
K198_LF=$(cd "$K198_TMP" && node "$ROOT/bin/devt-tools.cjs" state update-lane L1 status=lane_failed 2>&1 | node -e "let s='';process.stdin.on('data',d=>s+=d);process.stdin.on('end',()=>{process.stdout.write(/invalid status/.test(s)?'0':'1')})")
# Q5a DI-opaque surface
node -e "
const fs=require('fs');
const nodes=[{id:'svc',label:'OrchSvc',source_file:'app/orchestration_service.py',file_type:'code'}];
const links=[];
for(let i=0;i<8;i++){nodes.push({id:'fac'+i,label:'get_orch_'+i,source_file:'app/dependencies.py',file_type:'code'});links.push({source:'fac'+i,target:'svc',relation:'provides'});}
nodes.push({id:'r1',label:'route_a',source_file:'app/api/routes.py',file_type:'code'});links.push({source:'r1',target:'fac0',relation:'calls'});
fs.writeFileSync('$K198_TMP/graphify-out/graph.json',JSON.stringify({built_at_commit:'abc',nodes,links}));
"
K198_DI=$(cd "$K198_TMP" && node -e "const g=require('$ROOT/bin/modules/graphify.cjs');const r=g.blastRadius(['OrchSvc']);process.stdout.write((r.di_opaque===true && Array.isArray(r.di_collapsed_caller_files) && r.di_collapsed_caller_files.length>0)?'1':'0')" 2>/dev/null)
rm -rf "$K198_TMP"
if [ "$K198_MISS" = "1" ] && [ "$K198_EMPTY" = "1" ] && [ "$K198_LF" = "1" ] && [ "$K198_DI" = "1" ]; then
  pass "K198: substance-check hard-fails missing(+missing) + zero-byte(+empty); lane_failed status accepted; blastRadius di_opaque surfaces caller files when DI-collapse dominates"
else
  fail "K198: cal #39.A wrong — miss=$K198_MISS empty=$K198_EMPTY lane_failed=$K198_LF di_opaque=$K198_DI (each expect 1)"
fi

# K199: cal #39.A #4 — SHA-based "new files" caveat. A file added in a commit
# that is an ANCESTOR of the graph's built_at_commit is indexed (not counted);
# only files introduced AFTER the build count toward the caveat. Replaces the
# matched_files proxy that over-fired for indexed-but-symbolless files
# (receipt #11: "6 of 188 new" false alarm). Synthetic git repo: file1 before
# build, file2 after → caveat counts exactly 1.
K199_TMP=$(mktemp -d)
mkdir -p "$K199_TMP/.devt/state" "$K199_TMP/graphify-out"
echo '{"graphify":{"enabled":true,"command":"graphify"},"git":{"primary_branch":"main"}}' > "$K199_TMP/.devt/config.json"
cd "$K199_TMP"
git init -q -b main >/dev/null 2>&1; git config user.email t@t.t; git config user.name t
echo "x=1" > base.py; git add -A; git commit -qm base >/dev/null 2>&1
git checkout -q -b feature 2>/dev/null
echo "class Foo: pass" > file1.py; git add -A; git commit -qm f1 >/dev/null 2>&1
K199_BUILT=$(git rev-parse HEAD)
echo "class Bar: pass" > file2.py; git add -A; git commit -qm f2 >/dev/null 2>&1
node -e "require('fs').writeFileSync('graphify-out/graph.json',JSON.stringify({built_at_commit:'$K199_BUILT',nodes:[{id:'Foo',label:'Foo',source_file:'file1.py',source_location:'L1',file_type:'code'}],links:[]}))"
echo '{"graph_stats":{"state":"ready","trust":"dense"},"topic":{"symbols":[]}}' > .devt/state/preflight-brief.json
K199_CAVEAT=$(node "$ROOT/bin/devt-tools.cjs" state compute-impact-plan --scope="review PR #7" --primary-branch=main 2>/dev/null | node -e "let s='';process.stdin.on('data',d=>s+=d);process.stdin.on('end',()=>{try{const o=JSON.parse(s);const m=(o.pr_diff_caveat||'').match(/^(\d+) of/);process.stdout.write(m?m[1]:'none')}catch{process.stdout.write('err')}})")
cd "$ROOT"; rm -rf "$K199_TMP"
if [ "$K199_CAVEAT" = "1" ]; then
  pass "K199: SHA-based new-files caveat counts only files introduced AFTER built_at_commit (1 of 2 — file1 pre-build indexed, file2 post-build new)"
else
  fail "K199: SHA caveat wrong — counted '$K199_CAVEAT' new files (expect 1; file1 is pre-build/indexed)"
fi

# K200: compound review-context-init wrapper (cal #39.B). Collapses code-review
# context_init data-gathering into one call. Asserts: (1) returns a bundle with
# ok:true + impact_plan + freshness + staleness_tier fields; (2) a 2nd call
# SHORT-CIRCUITS (fresh plan+brief reused, no re-eviction); (3) graphify
# disabled → HONEST ABSENCE (freshness.state is "disabled"/"unknown"/"not_ready",
# NEVER a false-confident "ready"/"fresh"). The gates + staleness prompt + MCP
# execution deliberately stay separate orchestrator steps (not in the bundle).
K200_T=$(mktemp -d)
mkdir -p "$K200_T/.devt/state" "$K200_T/graphify-out"
echo '{"graphify":{"enabled":true,"command":"graphify"},"git":{"primary_branch":"main"}}' > "$K200_T/.devt/config.json"
cd "$K200_T"
git init -q -b main >/dev/null 2>&1; git config user.email t@t.t; git config user.name t
echo "x=1" > base.py; git add -A; git commit -qm base >/dev/null 2>&1
git checkout -q -b feature 2>/dev/null
echo "class NewSvc: pass" > svc.py; git add -A; git commit -qm svc >/dev/null 2>&1
K200_BUILT=$(git rev-parse HEAD)
node -e "require('fs').writeFileSync('graphify-out/graph.json',JSON.stringify({built_at_commit:'$K200_BUILT',nodes:[{id:'NewSvc',label:'NewSvc',source_file:'svc.py',source_location:'L1',file_type:'code'}],links:[]}))"
K200_FIRST=$(node "$ROOT/bin/devt-tools.cjs" state review-context-init --scope="review PR #5" --primary-branch=main 2>/dev/null | node -e "let s='';process.stdin.on('data',d=>s+=d);process.stdin.on('end',()=>{try{const o=JSON.parse(s);process.stdout.write((o.ok===true && o.short_circuited===false && o.impact_plan && typeof o.staleness_tier==='string')?'1':'0')}catch{process.stdout.write('0')}})")
K200_SECOND=$(node "$ROOT/bin/devt-tools.cjs" state review-context-init --scope="review PR #5" --primary-branch=main 2>/dev/null | node -e "let s='';process.stdin.on('data',d=>s+=d);process.stdin.on('end',()=>{try{const o=JSON.parse(s);process.stdout.write(o.short_circuited===true?'1':'0')}catch{process.stdout.write('0')}})")
cd "$ROOT"; rm -rf "$K200_T"
# graphify disabled → honest absence
K200_T2=$(mktemp -d); mkdir -p "$K200_T2/.devt/state"
echo '{"graphify":{"enabled":false}}' > "$K200_T2/.devt/config.json"
cd "$K200_T2"; git init -q -b main >/dev/null 2>&1; git config user.email t@t.t; git config user.name t; echo y > z.py; git add -A; git commit -qm b >/dev/null 2>&1
K200_HONEST=$(node "$ROOT/bin/devt-tools.cjs" state review-context-init --scope="review x" 2>/dev/null | node -e "let s='';process.stdin.on('data',d=>s+=d);process.stdin.on('end',()=>{try{const o=JSON.parse(s);const st=(o.freshness||{}).state;process.stdout.write((o.ok===true && st!=='ready' && st!=='fresh')?'1':'0')}catch{process.stdout.write('0')}})")
cd "$ROOT"; rm -rf "$K200_T2"
if [ "$K200_FIRST" = "1" ] && [ "$K200_SECOND" = "1" ] && [ "$K200_HONEST" = "1" ]; then
  pass "K200: review-context-init returns bundle (impact_plan+staleness_tier), short-circuits on fresh re-call, honest-absence freshness when graphify disabled"
else
  fail "K200: wrapper wrong — first=$K200_FIRST(exp 1) short_circuit=$K200_SECOND(exp 1) honest_absence=$K200_HONEST(exp 1)"
fi

# K201: code-review.md context_init WIRES the review-context-init wrapper (cal
# #39.B) — locks the collapse so context_init can't silently regress to the ~19
# inline CLI round-trips it replaced — AND the bundle carries the init payload
# (governing_rules + models) that the code-reviewer/verifier dispatch envelopes
# fill their {governing_rules}/{models} placeholders from. The wrapper runs
# `init review` internally; if it stopped surfacing that payload the dispatches
# would lose their governing rules + rubric with no other gate noticing.
K201_WIRED=$(/usr/bin/grep -c "state review-context-init" "$ROOT/workflows/code-review.md" 2>/dev/null || echo 0)
K201_T=$(mktemp -d); mkdir -p "$K201_T/.devt/state"
echo '{"graphify":{"enabled":false}}' > "$K201_T/.devt/config.json"
cd "$K201_T"; git init -q -b main >/dev/null 2>&1; git config user.email t@t.t; git config user.name t; echo y > z.py; git add -A; git commit -qm b >/dev/null 2>&1
K201_INIT=$(node "$ROOT/bin/devt-tools.cjs" state review-context-init --scope="review x" 2>/dev/null | node -e "let s='';process.stdin.on('data',d=>s+=d);process.stdin.on('end',()=>{try{const o=JSON.parse(s);process.stdout.write((o.ok===true && o.init && o.init.governing_rules && o.init.models)?'1':'0')}catch{process.stdout.write('0')}})")
cd "$ROOT"; rm -rf "$K201_T"
if [ "${K201_WIRED:-0}" -ge 1 ] && [ "$K201_INIT" = "1" ]; then
  pass "K201: code-review.md context_init calls review-context-init wrapper (${K201_WIRED} ref) + bundle carries init payload (governing_rules + models for the dispatch envelope)"
else
  fail "K201: wiring/payload wrong — wired=$K201_WIRED(exp >=1) bundle_init=$K201_INIT(exp 1)"
fi

# K202: dev-workflow.md + quick-implement.md context_init WIRE the generalized
# `state workflow-context-init` wrapper (the contextInitBundle shared core that
# also powers review-context-init). Locks the collapse so these two highest-
# frequency workflows can't regress to the ~16 / ~11 inline data-gathering
# round-trips they replaced, and verifies the workflow-mode bundle carries the
# init payload (governing_rules for the dispatch envelopes) + a memory_signal
# field (workflow mode gathers the same FTS signal review mode does).
K202_DEV=$(/usr/bin/grep -c "state workflow-context-init" "$ROOT/workflows/dev-workflow.md" 2>/dev/null || echo 0)
K202_QI=$(/usr/bin/grep -c "state workflow-context-init" "$ROOT/workflows/quick-implement.md" 2>/dev/null || echo 0)
K202_T=$(mktemp -d); mkdir -p "$K202_T/.devt/state"
echo '{"graphify":{"enabled":false}}' > "$K202_T/.devt/config.json"
cd "$K202_T"; git init -q -b main >/dev/null 2>&1; git config user.email t@t.t; git config user.name t; echo y > z.py; git add -A; git commit -qm b >/dev/null 2>&1
K202_BUNDLE=$(node "$ROOT/bin/devt-tools.cjs" state workflow-context-init --workflow-type=dev --scope="k202 test" 2>/dev/null | node -e "let s='';process.stdin.on('data',d=>s+=d);process.stdin.on('end',()=>{try{const o=JSON.parse(s);process.stdout.write((o.ok===true && o.init && o.init.governing_rules && o.memory_signal!==undefined && o.memory_signal!==null)?'1':'0')}catch{process.stdout.write('0')}})")
cd "$ROOT"; rm -rf "$K202_T"
if [ "${K202_DEV:-0}" -ge 1 ] && [ "${K202_QI:-0}" -ge 1 ] && [ "$K202_BUNDLE" = "1" ]; then
  pass "K202: dev-workflow + quick-implement context_init call workflow-context-init wrapper (dev=${K202_DEV} quick=${K202_QI}) + bundle carries init payload + memory_signal"
else
  fail "K202: wiring/bundle wrong — dev=$K202_DEV(exp >=1) quick=$K202_QI(exp >=1) bundle=$K202_BUNDLE(exp 1)"
fi

# K203: `preflight scan-prep` CLI — the shared graphify_scan_prep decision tree
# extracted from dev-workflow + quick-implement (was an 84%-identical inline
# bash block). Asserts the 3-way decision: SKIP on empty/sparse (+ writes the
# graphify-skip-reason.txt decision artifact), ACTIVE on dense+dependents+symbols
# (+ resolves central_symbol), RECOVERY on dense+0-symbols.
K203_T=$(mktemp -d); mkdir -p "$K203_T/.devt/state"; echo '{}' > "$K203_T/.devt/config.json"
echo '{"graph_stats":{"trust":"empty"},"blast":{"direct_dependents_count":0},"topic":{"symbols":[]}}' > "$K203_T/.devt/state/preflight-brief.json"
K203_SKIP=$(cd "$K203_T" && node "$ROOT/bin/devt-tools.cjs" preflight scan-prep --scope=x 2>/dev/null | node -e "let s='';process.stdin.on('data',d=>s+=d);process.stdin.on('end',()=>{try{process.stdout.write(JSON.parse(s).decision)}catch{process.stdout.write('err')}})")
K203_ARTIFACT=$([ -f "$K203_T/.devt/state/graphify-skip-reason.txt" ] && echo present || echo absent)
echo '{"graph_stats":{"trust":"dense"},"blast":{"direct_dependents_count":50},"topic":{"symbols":["AuthService","TokenStore"]}}' > "$K203_T/.devt/state/preflight-brief.json"
K203_ACTIVE=$(cd "$K203_T" && node "$ROOT/bin/devt-tools.cjs" preflight scan-prep --scope="fix AuthService" 2>/dev/null | node -e "let s='';process.stdin.on('data',d=>s+=d);process.stdin.on('end',()=>{try{const o=JSON.parse(s);process.stdout.write((o.decision==='ACTIVE'&&o.central_symbol)?'ACTIVE':'no')}catch{process.stdout.write('err')}})")
echo '{"graph_stats":{"trust":"dense"},"blast":{"direct_dependents_count":50},"topic":{"symbols":[]}}' > "$K203_T/.devt/state/preflight-brief.json"
K203_RECOVERY=$(cd "$K203_T" && node "$ROOT/bin/devt-tools.cjs" preflight scan-prep 2>/dev/null | node -e "let s='';process.stdin.on('data',d=>s+=d);process.stdin.on('end',()=>{try{process.stdout.write(JSON.parse(s).decision)}catch{process.stdout.write('err')}})")
cd "$ROOT"; rm -rf "$K203_T"
if [ "$K203_SKIP" = "SKIP" ] && [ "$K203_ARTIFACT" = "present" ] && [ "$K203_ACTIVE" = "ACTIVE" ] && [ "$K203_RECOVERY" = "RECOVERY" ]; then
  pass "K203: preflight scan-prep returns SKIP(+skip-reason.txt) / ACTIVE(+central_symbol) / RECOVERY — shared decision tree extracted from dev-workflow + quick-implement"
else
  fail "K203: scan-prep wrong — skip=$K203_SKIP(exp SKIP) artifact=$K203_ARTIFACT(exp present) active=$K203_ACTIVE(exp ACTIVE) recovery=$K203_RECOVERY(exp RECOVERY)"
fi

# K204: research-task.md context_init wires the `workflow-context-init` wrapper
# AND the researcher dispatch carries `<memory_signal>` (template + compiled
# inline region). Closes the field gap where the researcher investigated
# approaches with NO REJ/ADR governance signal — it could re-recommend an
# approach the project already rejected (a REJ tombstone). Locks both the wiring
# and the memory_signal injection against regression (e.g. a dispatch recompile
# silently dropping it).
K204_WIRED=$(/usr/bin/grep -c "state workflow-context-init" "$ROOT/workflows/research-task.md" 2>/dev/null || echo 0)
K204_INLINE=$(/usr/bin/grep -c "<memory_signal>" "$ROOT/workflows/research-task.md" 2>/dev/null || echo 0)
K204_TMPL=$(/usr/bin/grep -c "<memory_signal>" "$ROOT/templates/dispatch/envelopes/researcher-research.tmpl.md" 2>/dev/null || echo 0)
if [ "${K204_WIRED:-0}" -ge 1 ] && [ "${K204_INLINE:-0}" -ge 1 ] && [ "${K204_TMPL:-0}" -ge 1 ]; then
  pass "K204: research-task wires workflow-context-init (${K204_WIRED}) + researcher dispatch carries <memory_signal> (template + compiled inline) — closes the researcher's missing-governance-signal gap"
else
  fail "K204: research-task wiring/memory_signal wrong — wired=$K204_WIRED(exp>=1) inline=$K204_INLINE(exp>=1) template=$K204_TMPL(exp>=1)"
fi

# K205: the OTHER researcher path — dev-workflow.md's COMPLEX auto-research
# dispatch — also carries `<memory_signal>`. v0.128.0 wired only the
# /devt:research path (K204); the /devt:workflow auto-research researcher stayed
# blind to REJ/ADR even though dev-workflow computes + caches memory_signal_json
# and injects it into programmer/code-reviewer/verifier. Four surfaces must
# agree or the cached signal never reaches the agent (mechanism fires, value
# never converts): the generic researcher template, the compiled inline region
# (region-scoped grep — a sibling dispatch's <memory_signal> must NOT satisfy
# it), the orchestrator-prep substitution instruction, and the io-contracts SSoT.
K205_TMPL=$(/usr/bin/grep -c "<memory_signal>" "$ROOT/templates/dispatch/envelopes/researcher.tmpl.md" 2>/dev/null || echo 0)
K205_REGION=$(/usr/bin/sed -n '/BEGIN dispatch:researcher:dev/,/END dispatch:researcher:dev/p' "$ROOT/workflows/dev-workflow.complex.md" 2>/dev/null | /usr/bin/grep -c "<memory_signal>" 2>/dev/null || echo 0)
K205_PREP=$(/usr/bin/grep -c "Substitute .MEMORY_SIGNAL. into the researcher" "$ROOT/workflows/dev-workflow.complex.md" 2>/dev/null || echo 0)
K205_SSOT=$(/usr/bin/grep -c "context_blocks: \[governing_rules, memory_signal, agent_skills, task\]" "$ROOT/agents/io-contracts.yaml" 2>/dev/null || echo 0)
if [ "${K205_TMPL:-0}" -ge 1 ] && [ "${K205_REGION:-0}" -ge 1 ] && [ "${K205_PREP:-0}" -ge 1 ] && [ "${K205_SSOT:-0}" -ge 1 ]; then
  pass "K205: dev-workflow auto-research researcher carries <memory_signal> (template + region-scoped inline + orchestrator-prep) and io-contracts SSoT agrees — closes the /devt:workflow researcher governance-signal gap"
else
  fail "K205: dev-workflow researcher memory_signal wiring wrong — template=$K205_TMPL(exp>=1) region=$K205_REGION(exp>=1) prep=$K205_PREP(exp>=1) ssot=$K205_SSOT(exp>=1)"
fi

# K206: structural contract gate — every compiled dispatch region carries an XML
# block for each context_block its agent declares in io-contracts.yaml, minus
# that variant's documented context_blocks_exempt entries. Generalizes the
# per-agent presence greps (K204/K205's literal <memory_signal> checks): a
# dispatch silently missing a declared governance block — the class that left
# the researcher blind to REJ/ADR — is now ONE structural failure caught for
# every agent+variant, not one hand-written grep at a time. Runs the real
# `dispatch check-contracts` CLI (exit 1 + violations[] on any gap).
K206_JSON=$(node "$ROOT/bin/devt-tools.cjs" dispatch check-contracts 2>/dev/null)
K206_OK=$(echo "$K206_JSON" | /usr/bin/grep -c '"ok": true' 2>/dev/null || echo 0)
if [ "${K206_OK:-0}" -ge 1 ]; then
  pass "K206: every dispatch region ⊇ its agent's declared context_blocks (minus documented context_blocks_exempt variants) — generalizes K204/K205's per-agent <memory_signal> greps into one structural class gate"
else
  fail "K206: dispatch region(s) missing a declared context_block — $(echo "$K206_JSON" | tr -d '\n' | head -c 400)"
fi

# K207: scope-aware context-init freshness. The short-circuit keys on
# (scope_sig, graph_head) jointly — a review whose changed-file set differs from
# the cached bundle's must NOT reuse it, even when the graph is fresh. Guards the
# field-observed bug where a graph-fresh-only check served a prior PR's
# scope_hint / memory_signal / impact-plan. Also confirms a same-scope re-call
# still short-circuits (the resume optimization is preserved).
K207_T=$(mktemp -d); mkdir -p "$K207_T/.devt/state" "$K207_T/graphify-out"
echo '{"graphify":{"enabled":true,"command":"graphify"},"git":{"primary_branch":"main"}}' > "$K207_T/.devt/config.json"
cd "$K207_T"
git init -q -b main >/dev/null 2>&1; git config user.email t@t.t; git config user.name t
echo base > base.py; git add -A; git commit -qm base >/dev/null 2>&1
git checkout -q -b feat-a; echo a > fileX.py; git add -A; git commit -qm a >/dev/null 2>&1
K207_HEAD_A=$(git rev-parse HEAD)
node -e "require('fs').writeFileSync('graphify-out/graph.json',JSON.stringify({built_at_commit:'$K207_HEAD_A',nodes:[{id:'X',label:'X',source_file:'fileX.py',source_location:'L1',file_type:'code'}],links:[]}))"
K207_FIRST=$(node "$ROOT/bin/devt-tools.cjs" state review-context-init --scope="review A" --primary-branch=main 2>/dev/null | node -e "let s='';process.stdin.on('data',d=>s+=d);process.stdin.on('end',()=>{try{const o=JSON.parse(s);process.stdout.write(o.short_circuited===false?'1':'0')}catch{process.stdout.write('0')}})")
K207_RESUME=$(node "$ROOT/bin/devt-tools.cjs" state review-context-init --scope="review A" --primary-branch=main 2>/dev/null | node -e "let s='';process.stdin.on('data',d=>s+=d);process.stdin.on('end',()=>{try{const o=JSON.parse(s);process.stdout.write(o.short_circuited===true?'1':'0')}catch{process.stdout.write('0')}})")
git checkout -q main >/dev/null 2>&1; git checkout -q -b feat-b >/dev/null 2>&1; echo b > fileY.py; git add -A; git commit -qm b >/dev/null 2>&1
K207_HEAD_B=$(git rev-parse HEAD)
node -e "require('fs').writeFileSync('graphify-out/graph.json',JSON.stringify({built_at_commit:'$K207_HEAD_B',nodes:[{id:'Y',label:'Y',source_file:'fileY.py',source_location:'L1',file_type:'code'}],links:[]}))"
K207_SCOPE=$(node "$ROOT/bin/devt-tools.cjs" state review-context-init --scope="review B" --primary-branch=main 2>/dev/null | node -e "let s='';process.stdin.on('data',d=>s+=d);process.stdin.on('end',()=>{try{const o=JSON.parse(s);process.stdout.write(o.short_circuited===false?'1':'0')}catch{process.stdout.write('0')}})")
cd "$ROOT"; rm -rf "$K207_T"
if [ "$K207_FIRST" = "1" ] && [ "$K207_RESUME" = "1" ] && [ "$K207_SCOPE" = "1" ]; then
  pass "K207: context-init freshness keyed on (scope_sig, graph_head) — same-scope re-call short-circuits; a changed-scope review recomputes even on a fresh graph (no cross-review contamination)"
else
  fail "K207: scope-aware freshness broken — first_full=$K207_FIRST(exp1) resume_shortcircuit=$K207_RESUME(exp1) scope_changed_recompute=$K207_SCOPE(exp1)"
fi

# K208: reset-soft evicts the scope-bound graphify-impact-plan.json (a new
# working session must not inherit the prior scope's impact plan) while
# PRESERVING workflow-spanning phase artifacts (graph-impact.md). Field-observed:
# reset-soft left the stale plan behind and a faithful impact-step anchored the
# whole review's blast-radius on the wrong PR.
K208_T=$(mktemp -d); mkdir -p "$K208_T/.devt/state"
echo '{}' > "$K208_T/.devt/config.json"
cd "$K208_T"
git init -q -b main >/dev/null 2>&1; git config user.email t@t.t; git config user.name t; echo x > a.py; git add -A; git commit -qm x >/dev/null 2>&1
node "$ROOT/bin/devt-tools.cjs" state update active=true workflow_type=code_review task=t >/dev/null 2>&1
echo '{"tier":"pr_scoped_diff"}' > .devt/state/graphify-impact-plan.json
echo 'stale blast map' > .devt/state/graph-impact.md
node "$ROOT/bin/devt-tools.cjs" state reset-soft >/dev/null 2>&1
K208_PLAN_GONE=$([ ! -f .devt/state/graphify-impact-plan.json ] && echo 1 || echo 0)
K208_GRAPH_KEPT=$([ -f .devt/state/graph-impact.md ] && echo 1 || echo 0)
cd "$ROOT"; rm -rf "$K208_T"
if [ "$K208_PLAN_GONE" = "1" ] && [ "$K208_GRAPH_KEPT" = "1" ]; then
  pass "K208: reset-soft evicts scope-bound graphify-impact-plan.json while preserving workflow-spanning graph-impact.md"
else
  fail "K208: reset-soft eviction wrong — plan_evicted=$K208_PLAN_GONE(exp1) graph_impact_preserved=$K208_GRAPH_KEPT(exp1)"
fi

# K209: session-start.sh surfaces a safety-floor notice when dispatch_hygiene_mode
# is lowered below the "block" default, and stays silent at block. Closes the
# field-observed gap where a warn floor was flagged every turn but never
# explained at session start. HOME is redirected to the temp dir so the hook's
# command-symlink + cache side effects don't touch the real environment.
K209_T=$(mktemp -d); mkdir -p "$K209_T/.devt/state"
echo '{"dispatch_hygiene_mode":"warn"}' > "$K209_T/.devt/config.json"
K209_WARN=$(cd "$K209_T" && HOME="$K209_T" bash "$ROOT/hooks/session-start.sh" 2>/dev/null | node -e "let s='';process.stdin.on('data',d=>s+=d);process.stdin.on('end',()=>{try{const c=(JSON.parse(s).hookSpecificOutput||{}).additionalContext||'';process.stdout.write(c.indexOf('safety floor lowered')>=0?'1':'0')}catch{process.stdout.write('0')}})")
echo '{"dispatch_hygiene_mode":"block"}' > "$K209_T/.devt/config.json"
K209_BLOCK=$(cd "$K209_T" && HOME="$K209_T" bash "$ROOT/hooks/session-start.sh" 2>/dev/null | node -e "let s='';process.stdin.on('data',d=>s+=d);process.stdin.on('end',()=>{try{const c=(JSON.parse(s).hookSpecificOutput||{}).additionalContext||'';process.stdout.write(c.indexOf('safety floor lowered')>=0?'0':'1')}catch{process.stdout.write('0')}})")
cd "$ROOT"; rm -rf "$K209_T"
if [ "$K209_WARN" = "1" ] && [ "$K209_BLOCK" = "1" ]; then
  pass "K209: session-start.sh surfaces the dispatch_hygiene_mode safety floor when lowered below block, silent at block"
else
  fail "K209: hygiene-floor surfacing wrong — warn_surfaced=$K209_WARN(exp1) block_silent=$K209_BLOCK(exp1)"
fi

# K210: dev-workflow tier-partition is complete + disjoint. Each STANDARD+ step
# lazy-loaded into dev-workflow.standard.md must appear in EXACTLY ONE file —
# moved out of the spine (0 in dev-workflow.md), present once in the tier file —
# proving the carve lost no step and duplicated none. Spine-only steps must not
# leak into the tier file.
K210_OK=1; K210_BAD=""
for st in risk_warning scan regression_baseline simplify autoskill verify docs_retro_parallel auto_research_plan architect curate; do
  K210_SPINE=$(/usr/bin/grep -c "<step name=\"$st\"" "$ROOT/workflows/dev-workflow.md" || true)
  K210_STD=$(/usr/bin/grep -c "<step name=\"$st\"" "$ROOT/workflows/dev-workflow.standard.md" || true)
  K210_CPX=$(/usr/bin/grep -c "<step name=\"$st\"" "$ROOT/workflows/dev-workflow.complex.md" || true)
  K210_TIER=$((K210_STD + K210_CPX))
  if [ "$K210_SPINE" != "0" ] || [ "$K210_TIER" != "1" ]; then K210_OK=0; K210_BAD="$st(spine=$K210_SPINE,std=$K210_STD,cpx=$K210_CPX)"; fi
done
for sp in context_init implement test review finalize; do
  K210_LS=$(/usr/bin/grep -c "<step name=\"$sp\"" "$ROOT/workflows/dev-workflow.standard.md" 2>/dev/null || true)
  K210_LC=$(/usr/bin/grep -c "<step name=\"$sp\"" "$ROOT/workflows/dev-workflow.complex.md" 2>/dev/null || true)
  if [ "$K210_LS" != "0" ] || [ "$K210_LC" != "0" ]; then K210_OK=0; K210_BAD="spine-step $sp leaked into a tier file"; fi
done
if [ "$K210_OK" = "1" ]; then
  pass "K210: dev-workflow tier-partition complete + disjoint (10 tier steps live exactly once across dev-workflow.standard.md + dev-workflow.complex.md, zero in the spine; no spine step leaked)"
else
  fail "K210: dev-workflow partition broken — $K210_BAD"
fi

# K211: the spine carries the load_tier_steps directive (mandatory Read of the
# tier file) + a TIER-STEP pointer for every relocated step, so a STANDARD+ run
# can never reach an insertion point without the step body already in context.
K211_STEP=$(/usr/bin/grep -c '<step name="load_tier_steps"' "$ROOT/workflows/dev-workflow.md" || true)
K211_READ=$(/usr/bin/grep -cE 'Mandatory action: Read.*dev-workflow\.standard\.md' "$ROOT/workflows/dev-workflow.md" || true)
K211_READC=$(/usr/bin/grep -c 'dev-workflow\.complex\.md' "$ROOT/workflows/dev-workflow.md" || true)
K211_PTRS=0
for st in risk_warning scan regression_baseline simplify autoskill verify docs_retro_parallel auto_research_plan architect curate; do
  K211_P=$(/usr/bin/grep -c "TIER-STEP:$st" "$ROOT/workflows/dev-workflow.md" || true)
  if [ "$K211_P" -ge 1 ]; then K211_PTRS=$((K211_PTRS+1)); fi
done
if [ "$K211_STEP" -ge 1 ] && [ "$K211_READ" -ge 1 ] && [ "$K211_READC" -ge 1 ] && [ "$K211_PTRS" = "10" ]; then
  pass "K211: spine carries load_tier_steps (mandatory Read of dev-workflow.standard.md + dev-workflow.complex.md) + a TIER-STEP pointer for all 10 relocated steps"
else
  fail "K211: tier-load wiring incomplete — load_step=$K211_STEP read_std=$K211_READ read_cpx=$K211_READC pointers=$K211_PTRS/10"
fi

# K212: tier-aware assert-verifier-ran (Stage 2 verify carve). dev SIMPLE/TRIVIAL
# runs no verify step, so the gate opts out (ok:true) even without a verification
# artifact; dev STANDARD/COMPLEX requires it (ok:false when absent) — closing the
# pre-existing dev.complete hole where a STANDARD dev task could silently skip
# verify. code_review is unaffected (still required regardless of tier).
K212_T=$(mktemp -d); mkdir -p "$K212_T/.devt/state"; echo '{}' > "$K212_T/.devt/config.json"
_k212() {
  printf 'active: true\nworkflow_type: %s\ntier: %s\nphase: complete\n' "$1" "$2" > "$K212_T/.devt/state/workflow.yaml"
  (cd "$K212_T" && node "$ROOT/bin/devt-tools.cjs" state assert-verifier-ran 2>/dev/null || true) | node -e "let s='';process.stdin.on('data',d=>s+=d);process.stdin.on('end',()=>{try{process.stdout.write(String(JSON.parse(s).ok))}catch{process.stdout.write('err')}})"
}
K212_SIMPLE=$(_k212 dev SIMPLE)
K212_STANDARD=$(_k212 dev STANDARD)
K212_CR=$(_k212 code_review "")
rm -rf "$K212_T"
if [ "$K212_SIMPLE" = "true" ] && [ "$K212_STANDARD" = "false" ] && [ "$K212_CR" = "false" ]; then
  pass "K212: tier-aware assert-verifier-ran — dev SIMPLE opts out (ok:true), dev STANDARD requires verification.json (ok:false), code_review unaffected (ok:false)"
else
  fail "K212: tier-aware verify gate wrong — dev_simple=$K212_SIMPLE(exp true) dev_standard=$K212_STANDARD(exp false) code_review=$K212_CR(exp false)"
fi

# K213: a workflow_type's .complete gate set must be satisfiable by that workflow.
# Regression guard for the class where a .complete gate requires a marker the
# workflow never writes — assert-auto-curator-considered (a code_review-only
# marker) hard-blocked dev + quick_implement finalize (advanceState THROWS on a
# blocking gate). A STANDARD dev and a quick_implement, each with the markers
# their own workflow writes, must reach `complete` without blocking.
_k213() {
  local d; d=$(mktemp -d); mkdir -p "$d/.devt/state"; echo '{}' > "$d/.devt/config.json"
  printf 'active: true\nworkflow_type: %s\ntier: %s\nphase: finalize\nfirst_created_at: "2026-07-02T00:00:00Z"\ncreated_at: "2026-07-02T00:00:00Z"\n' "$1" "$2" > "$d/.devt/state/workflow.yaml"
  echo 'reason=task_too_routine' > "$d/.devt/state/knowledge-candidates-none.txt"
  [ "$1" = "dev" ] && echo '{"verdict":"VERIFIED","criteria_total":3,"criteria_met":3,"findings":[]}' > "$d/.devt/state/verification.json"
  (cd "$d" && node "$ROOT/bin/devt-tools.cjs" state advance-phase complete active=false 2>&1) | node -e "let s='';process.stdin.on('data',x=>s+=x);process.stdin.on('end',()=>{try{process.stdout.write(JSON.parse(s).advanced===true?'advanced':'blocked')}catch{process.stdout.write('err')}})"
  rm -rf "$d"
}
K213_DEV=$(_k213 dev STANDARD)
K213_QI=$(_k213 quick_implement SIMPLE)
if [ "$K213_DEV" = "advanced" ] && [ "$K213_QI" = "advanced" ]; then
  pass "K213: dev.complete + quick_implement.complete satisfiable by their own workflows (each reaches complete with the markers it writes; the code_review-only auto-curator gate no longer hard-blocks non-review finalize)"
else
  fail "K213: complete-gate unsatisfiable — dev=$K213_DEV(exp advanced) quick_implement=$K213_QI(exp advanced)"
fi

# K214: specify.md's PRD template + illustration are lazy-loaded from references/
# (body-weight deferral). Lock it: the generate step Reads prd-template.md, a
# specify-guide.md pointer is present, and both reference files exist with real
# content — so the deferred body can't silently vanish (a missing template would
# leave the generate step unable to produce a PRD).
K214_READ=$(/usr/bin/grep -c 'references/prd-template.md' "$ROOT/workflows/specify.md" || true)
K214_GUIDE=$(/usr/bin/grep -c 'references/specify-guide.md' "$ROOT/workflows/specify.md" || true)
K214_PRD_OK=$([ -s "$ROOT/references/prd-template.md" ] && /usr/bin/grep -q '## Summary' "$ROOT/references/prd-template.md" && echo 1 || echo 0)
K214_GUIDE_OK=$([ -s "$ROOT/references/specify-guide.md" ] && /usr/bin/grep -q 'Anti-patterns' "$ROOT/references/specify-guide.md" && echo 1 || echo 0)
if [ "$K214_READ" -ge 1 ] && [ "$K214_GUIDE" -ge 1 ] && [ "$K214_PRD_OK" = "1" ] && [ "$K214_GUIDE_OK" = "1" ]; then
  pass "K214: specify.md lazy-loads its PRD template + guide from references/ (generate step Reads prd-template.md; specify-guide.md pointer present; both reference files exist with real content)"
else
  fail "K214: specify.md reference deferral broken — prd_read=$K214_READ guide_ref=$K214_GUIDE prd_file=$K214_PRD_OK guide_file=$K214_GUIDE_OK"
fi

# K215: check-agent-output phrase-vs-length precedence — a stub phrase inside a
# long, substantive document must NOT flag it (field false positive: a 2,242-word
# lane review was flagged because a verdict sentence contained "not yet done");
# a gray-zone doc (100 words + phrase) must still flag. Phrases are decisive
# only below STUB_PHRASE_WORD_CEILING.
K215_T=$(mktemp -d); mkdir -p "$K215_T/.devt/state"; echo '{}' > "$K215_T/.devt/config.json"
{ for i in $(seq 1 400); do printf 'w%d ' "$i"; done; echo; echo "the sanctioning document has not yet done its job"; } > "$K215_T/long.md"
{ for i in $(seq 1 100); do printf 'w%d ' "$i"; done; echo; echo "Stub: analysis in progress."; } > "$K215_T/gray.md"
_k215_flag() {
  (cd "$K215_T" && node "$ROOT/bin/devt-tools.cjs" state check-agent-output "$1" 2>/dev/null) | node -e "let s='';process.stdin.on('data',x=>s+=x);process.stdin.on('end',()=>{try{process.stdout.write(String(JSON.parse(s).looks_like_stub))}catch{process.stdout.write('err')}})"
}
K215_LONG=$(_k215_flag long.md)
K215_GRAY=$(_k215_flag gray.md)
rm -rf "$K215_T"
if [ "$K215_LONG" = "false" ] && [ "$K215_GRAY" = "true" ]; then
  pass "K215: stub-phrase precedence — phrase in 400-word doc not decisive (looks_like_stub=false), 100-word gray-zone doc with phrase still caught"
else
  fail "K215: stub-phrase precedence wrong — long=$K215_LONG(exp false) gray=$K215_GRAY(exp true)"
fi

# K216: auto-reset double-signal — task_changed AND workflow_type_changed AND
# age>1h recommends auto-reset (a prior age>24h leg forced an interactive
# staleness prompt on real session turnover); <1h stays false (typo-retry
# floor); task-change alone stays false even at 30h (single signal keeps the
# operator prompt — counters/artifacts may legitimately continue).
_k216() {
  local d ts; d=$(mktemp -d); mkdir -p "$d/.devt/state"; echo '{}' > "$d/.devt/config.json"
  ts=$(node -e "console.log(new Date(Date.now()-$1*3600*1000).toISOString())")
  printf 'active: true\ntask: "old task"\nworkflow_type: code_review\ncreated_at: "%s"\n' "$ts" > "$d/.devt/state/workflow.yaml"
  (cd "$d" && node "$ROOT/bin/devt-tools.cjs" state staleness-check --task="$2" --workflow-type="$3" 2>/dev/null) | node -e "let s='';process.stdin.on('data',x=>s+=x);process.stdin.on('end',()=>{try{process.stdout.write(String(JSON.parse(s).auto_reset_recommended))}catch{process.stdout.write('err')}})"
  rm -rf "$d"
}
K216_BOTH=$(_k216 2 "new dev task" dev)
K216_FRESH=$(_k216 0.3 "new dev task" dev)
K216_SINGLE=$(_k216 30 "reworded review task" code_review)
if [ "$K216_BOTH" = "true" ] && [ "$K216_FRESH" = "false" ] && [ "$K216_SINGLE" = "false" ]; then
  pass "K216: auto-reset double-signal — task+type changed at 2h recommends (true), 18min stays false, task-only at 30h stays false"
else
  fail "K216: auto-reset condition wrong — both=$K216_BOTH(exp true) fresh=$K216_FRESH(exp false) single=$K216_SINGLE(exp false)"
fi

# K217: review-pipeline phases registered — `state update` with a parallel-review
# phase must not warn "Unknown phase" (unregistered phases also short-circuit
# validateConsistency's phase-gated artifact checks via the indexOf -1 path);
# a bogus phase still warns (registry not blown open).
K217_T=$(mktemp -d); mkdir -p "$K217_T/.devt/state"; echo '{}' > "$K217_T/.devt/config.json"
K217_WARN=$( (cd "$K217_T" && node "$ROOT/bin/devt-tools.cjs" state update phase=substance_check_lanes 2>&1 >/dev/null) | /usr/bin/grep -c 'Unknown phase' || true)
K217_CTRL=$( (cd "$K217_T" && node "$ROOT/bin/devt-tools.cjs" state update phase=zz_not_a_phase 2>&1 >/dev/null) | /usr/bin/grep -c 'Unknown phase' || true)
K217_ALL=$(node -e "const m=require('$ROOT/bin/modules/state.cjs');const need=['scope_check','partition_lanes','dispatch_lanes','substance_check_lanes','redispatch_lanes','consolidate','present_findings'];process.stdout.write(String(need.every(p=>m.PHASE_ORDER.includes(p))))" 2>/dev/null || echo err)
rm -rf "$K217_T"
if [ "$K217_WARN" = "0" ] && [ "$K217_CTRL" = "1" ] && [ "$K217_ALL" = "true" ]; then
  pass "K217: review phases registered — substance_check_lanes accepted silently, all 7 in PHASE_ORDER, bogus phase still warns"
else
  fail "K217: phase registry wrong — warn=$K217_WARN(exp 0) ctrl=$K217_CTRL(exp 1) all7=$K217_ALL(exp true)"
fi

# K218: mcp-stats strict-zero chain hint — a strict --workflow-id query that
# returns 0 entries while the workflow_id_history chain has matches must emit
# a hint naming --include-chain (silent under-report field-observed as "zero
# graphify usage" on a run with 5 real calls); --include-chain must recover.
K218_T=$(mktemp -d); mkdir -p "$K218_T/.devt/state" "$K218_T/.devt/memory"; echo '{}' > "$K218_T/.devt/config.json"
printf 'active: true\ntask: "t"\nworkflow_type: code_review_parallel\nworkflow_id: "B-cur"\noriginal_workflow_id: "A-orig"\nworkflow_id_history: "[\\"A-orig\\",\\"B-cur\\"]"\ncreated_at: "2026-07-02T08:00:00Z"\n' > "$K218_T/.devt/state/workflow.yaml"
echo '{"ts":"2026-07-02T09:00:00Z","tool":"blast_radius","duration_ms":1,"workflow_id":"A-orig"}' > "$K218_T/.devt/memory/_mcp-trace.jsonl"
K218_STRICT=$( (cd "$K218_T" && node "$ROOT/bin/devt-tools.cjs" mcp-stats --workflow-id="B-cur" 2>/dev/null) | node -e "let s='';process.stdin.on('data',x=>s+=x);process.stdin.on('end',()=>{try{const j=JSON.parse(s);process.stdout.write((j.entries_considered===0&&typeof j.hint==='string'&&j.hint.indexOf('--include-chain')>=0)?'hinted':'no')}catch{process.stdout.write('err')}})")
K218_CHAIN=$( (cd "$K218_T" && node "$ROOT/bin/devt-tools.cjs" mcp-stats --workflow-id="B-cur" --include-chain 2>/dev/null) | node -e "let s='';process.stdin.on('data',x=>s+=x);process.stdin.on('end',()=>{try{process.stdout.write(String(JSON.parse(s).entries_considered))}catch{process.stdout.write('err')}})")
rm -rf "$K218_T"
if [ "$K218_STRICT" = "hinted" ] && [ "$K218_CHAIN" = "1" ]; then
  pass "K218: mcp-stats chain hint — strict zero-result emits --include-chain hint; chain query recovers the pre-rotation record"
else
  fail "K218: chain hint wrong — strict=$K218_STRICT(exp hinted) chain=$K218_CHAIN(exp 1)"
fi

# K219: scope_check measures its own scope source — the step runs before
# identify_scope writes code-review-input.md, so the old wc-l read of that
# artifact was always 0 on fresh runs (file-size path to parallel unreachable).
# Lock: artifact-read-as-primary gone; count derives from the changed-files
# union CLI (same source identify_scope consumes).
K219_OLD=$(/usr/bin/grep -c 'wc -l < .devt/state/code-review-input.md' "$ROOT/workflows/code-review.md" || true)
K219_DIFF=$(/usr/bin/grep -cF 'SCOPE_FILE_COUNT=$(node "${CLAUDE_PLUGIN_ROOT}/bin/devt-tools.cjs" state changed-files' "$ROOT/workflows/code-review.md" || true)
if [ "$K219_OLD" = "0" ] && [ "$K219_DIFF" -ge 1 ]; then
  pass "K219: scope_check derives file count from the changed-files union CLI (artifact wc-l read gone)"
else
  fail "K219: scope_check source wrong — old_read=$K219_OLD(exp 0) union_source=$K219_DIFF(exp >=1)"
fi

# K220: update-lane override_reason audit ledger — an override with a reason
# appends a lane-status-overrides.jsonl record carrying prior_status; a
# standalone override_reason (no status/redispatch mutation) is rejected.
K220_T=$(mktemp -d); mkdir -p "$K220_T/.devt/state"; echo '{}' > "$K220_T/.devt/config.json"
printf 'active: true\ntask: "t"\nworkflow_type: code_review_parallel\nlanes:\n  - id: "L1"\n    status: "in_flight"\n    redispatch_count: 0\n' > "$K220_T/.devt/state/workflow.yaml"
K220_OK=$( (cd "$K220_T" && node "$ROOT/bin/devt-tools.cjs" state update-lane L1 status=substance_pass "override_reason=gate false positive" 2>/dev/null) | node -e "let s='';process.stdin.on('data',x=>s+=x);process.stdin.on('end',()=>{try{process.stdout.write(String(JSON.parse(s).ok))}catch{process.stdout.write('err')}})")
K220_REC=$( (cd "$K220_T" && node -e "const j=JSON.parse(require('fs').readFileSync('.devt/state/lane-status-overrides.jsonl','utf8').trim());process.stdout.write((j.lane_id==='L1'&&j.prior_status==='in_flight'&&j.override_reason.length>0)?'audited':'bad')" 2>/dev/null) || echo missing)
K220_SOLO=$( (cd "$K220_T" && node "$ROOT/bin/devt-tools.cjs" state update-lane L1 "override_reason=orphan" 2>/dev/null) | node -e "let s='';process.stdin.on('data',x=>s+=x);process.stdin.on('end',()=>{try{process.stdout.write(JSON.parse(s).ok===false?'rejected':'accepted')}catch{process.stdout.write('err')}})")
rm -rf "$K220_T"
if [ "$K220_OK" = "true" ] && [ "$K220_REC" = "audited" ] && [ "$K220_SOLO" = "rejected" ]; then
  pass "K220: update-lane override_reason — status override audited to lane-status-overrides.jsonl with prior_status; standalone reason rejected"
else
  fail "K220: override_reason wrong — ok=$K220_OK(exp true) rec=$K220_REC(exp audited) solo=$K220_SOLO(exp rejected)"
fi

# K221: config-drift banner once-per-session — with dispatch_hygiene_mode=warn
# the UserPromptSubmit banner fires on the first prompt of a session, is
# suppressed on a repeat prompt of the SAME session_id, and fails loud (fires)
# when no session_id was forwarded on hook stdin.
K221_T=$(mktemp -d); mkdir -p "$K221_T/.devt/state"; printf '{"dispatch_hygiene_mode":"warn"}' > "$K221_T/.devt/config.json"
K221_R1=$( (cd "$K221_T" && echo '{"session_id":"k221-s1"}' | bash "$ROOT/hooks/workflow-context-injector.sh") | /usr/bin/grep -c 'config alert' || true)
K221_R2=$( (cd "$K221_T" && echo '{"session_id":"k221-s1"}' | bash "$ROOT/hooks/workflow-context-injector.sh") | /usr/bin/grep -c 'config alert' || true)
K221_R3=$( (cd "$K221_T" && echo '{}' | bash "$ROOT/hooks/workflow-context-injector.sh") | /usr/bin/grep -c 'config alert' || true)
rm -rf "$K221_T"
if [ "$K221_R1" = "1" ] && [ "$K221_R2" = "0" ] && [ "$K221_R3" = "1" ]; then
  pass "K221: config alert once-per-session — first prompt fires, same-session repeat suppressed, missing session_id fails loud"
else
  fail "K221: alert dedup wrong — r1=$K221_R1(exp 1) r2=$K221_R2(exp 0) r3=$K221_R3(exp 1)"
fi

# K223: render-lanes rules-by-reference default — the rendered lane envelope
# must NOT inline rule bodies or CLAUDE.md (harness auto-injects the latter
# into subagents; the former is byte-identical across N lanes — field-measured
# 73% of a 391KB 5-lane render), must carry rules_hash + read-from-disk stubs
# + the Context-Loaded contract; --inline-rules restores full bodies. The
# contract is template-static (structurally-conditional wording) and rides
# in BOTH modes.
K223_T=$(mktemp -d); mkdir -p "$K223_T/.devt/state" "$K223_T/.devt/rules"; echo '{}' > "$K223_T/.devt/config.json"
printf '# Coding Standards\nK223_RULES_BODY_MARKER every function documented.\n' > "$K223_T/.devt/rules/coding-standards.md"
printf '# Project\nK223_CLAUDEMD_MARKER\n' > "$K223_T/CLAUDE.md"
printf 'active: true\ntask: "t"\nworkflow_type: code_review_parallel\nworkflow_id: "wf-k223aaaa"\n' > "$K223_T/.devt/state/workflow.yaml"
(cd "$K223_T" && node "$ROOT/bin/devt-tools.cjs" state register-lane --id=L1 --scope=core --files=a.py >/dev/null 2>&1)
K223_REF=$( (cd "$K223_T" && node "$ROOT/bin/devt-tools.cjs" dispatch render-lanes 2>/dev/null) )
K223_INL=$( (cd "$K223_T" && node "$ROOT/bin/devt-tools.cjs" dispatch render-lanes --inline-rules 2>/dev/null) )
K223_REF_OK=$(printf '%s' "$K223_REF" | /usr/bin/grep -c 'K223_RULES_BODY_MARKER\|K223_CLAUDEMD_MARKER' || true)
K223_REF_STUB=$(printf '%s' "$K223_REF" | /usr/bin/grep -c 'by-reference: Read' || true)
K223_REF_CONTRACT=$(printf '%s' "$K223_REF" | /usr/bin/grep -c 'context_loaded_contract' || true)
K223_REF_HASH=$(printf '%s' "$K223_REF" | /usr/bin/grep -c 'governing_rules rules_hash=' || true)
K223_INL_BODY=$(printf '%s' "$K223_INL" | /usr/bin/grep -c 'K223_RULES_BODY_MARKER' || true)
K223_INL_CONTRACT=$(printf '%s' "$K223_INL" | /usr/bin/grep -c 'context_loaded_contract' || true)
rm -rf "$K223_T"
if [ "$K223_REF_OK" = "0" ] && [ "$K223_REF_STUB" -ge 1 ] && [ "$K223_REF_CONTRACT" -ge 1 ] && [ "$K223_REF_HASH" -ge 1 ] && [ "$K223_INL_BODY" -ge 1 ] && [ "$K223_INL_CONTRACT" -ge 1 ]; then
  pass "K223: render-lanes rules-by-reference default — no rule/CLAUDE.md bodies inlined, rules_hash + stubs present; --inline-rules restores bodies; template-static Context-Loaded contract rides in both modes"
else
  fail "K223: rules-by-reference wrong — ref_leak=$K223_REF_OK(exp 0) stub=$K223_REF_STUB(exp>=1) contract=$K223_REF_CONTRACT(exp>=1) hash=$K223_REF_HASH(exp>=1) inl_body=$K223_INL_BODY(exp>=1) inl_contract=$K223_INL_CONTRACT(exp>=1)"
fi

# K224: the Context-Loaded contract survives on the prose surfaces — the lane
# dispatch instruction in code-review-parallel.md tells lanes to record reads,
# and the consolidate step carries the advisory check for missing sections
# (without both, by-reference selective reading is unauditable).
K224_TASK=$(/usr/bin/grep -c '## Context Loaded' "$ROOT/workflows/code-review-parallel.md" || true)
K224_BYREF=$(/usr/bin/grep -c 'by-reference' "$ROOT/workflows/code-review-parallel.md" || true)
if [ "$K224_TASK" -ge 2 ] && [ "$K224_BYREF" -ge 2 ]; then
  pass "K224: code-review-parallel.md carries the Context-Loaded contract (lane task instruction + consolidator advisory) and the by-reference lane default"
else
  fail "K224: Context-Loaded prose contract missing — task+advisory=$K224_TASK(exp>=2) byref=$K224_BYREF(exp>=2)"
fi

# K222: Graphify-activity surfaces pass --include-chain — both workflow files'
# mcp-stats calls must union the id chain (their context_init MCP calls land
# under the pre-rotation workflow_id; the strict default would report zero
# graphify usage for a run that demonstrably used it).
K222_SHARED=$(/usr/bin/grep -c -- '--workflow-id="$WID" --include-chain' "$ROOT/workflows/code-review.steps.md" || true)
if [ "$K222_SHARED" = "2" ]; then
  pass "K222: Graphify-activity telemetry uses --include-chain (2 call sites in the shared step file both review paths load)"
else
  fail "K222: --include-chain missing — shared=$K222_SHARED(exp 2)"
fi

# K225: evolution scan — git-history behavioral metrics. On a synthetic repo:
# the frequently-changed large file ranks as top hotspot (freq × LOC), the
# co-change pair is detected with high coupling degree, the changeset-size
# guard excludes the mass commit from coupling, the fix-subject commit counts
# toward fix density, and both report artifacts land in .devt/state/.
K225_T=$(mktemp -d)
(
  cd "$K225_T"
  git init -q . >/dev/null 2>&1
  git config user.email k225@devt.test && git config user.name K225
  mkdir -p src .devt/state
  for i in 1 2 3 4 5 6; do
    seq 1 200 | sed 's/^/line /' > src/hot.js
    echo "// rev $i" >> src/hot.js
    echo "$i" > src/a.js
    echo "$i" > src/b.js
    git add -A >/dev/null && git commit -qm "feat: change $i" >/dev/null
  done
  echo "small" > src/cold.js
  git add -A >/dev/null && git commit -qm "feat: add cold" >/dev/null
  echo "fixline" >> src/hot.js
  git add -A >/dev/null && git commit -qm "fix: repair hot bug" >/dev/null
  for f in $(seq 1 40); do echo x > "src/mass$f.js"; done
  git add -A >/dev/null && git commit -qm "chore: mass add" >/dev/null
) >/dev/null 2>&1
K225_OUT=$( (cd "$K225_T" && node "$ROOT/bin/devt-tools.cjs" evolution scan 2>/dev/null) || echo "")
K225_CHECK=$(node -e "
  const fs = require('fs');
  const out = JSON.parse(process.argv[1] || '{}');
  const j = JSON.parse(fs.readFileSync('$K225_T/.devt/state/evolution-report.json', 'utf8'));
  const failures = [];
  if (!out.ok) failures.push('scan not ok');
  if (!fs.existsSync('$K225_T/.devt/state/evolution-report.md')) failures.push('report md missing');
  if (!j.hotspots.length || j.hotspots[0].file !== 'src/hot.js') failures.push('top hotspot != src/hot.js (got ' + (j.hotspots[0] || {}).file + ')');
  const ab = j.coupling.find(c => (c.a === 'src/a.js' && c.b === 'src/b.js'));
  if (!ab || ab.degree_pct < 80) failures.push('a/b coupling missing or weak: ' + JSON.stringify(ab || null));
  if (j.commits_skipped_large < 1) failures.push('mass commit not excluded from coupling');
  const hot = j.hotspots.find(h => h.file === 'src/hot.js');
  if (!hot || hot.fix_commits < 1) failures.push('fix commit not counted for hot.js');
  console.log(failures.length === 0 ? 'OK' : 'FAIL:' + failures.join('; '));
" "$K225_OUT" 2>&1 || echo "FAIL:node error")
rm -rf "$K225_T"
if [ "$K225_CHECK" = "OK" ]; then
  pass "K225: evolution scan — hotspot ranking, co-change coupling, changeset guard, fix density, report artifacts"
else
  fail "K225: evolution scan wrong — $K225_CHECK"
fi

# K226: arch-health-scan.md carries the evolution wiring — the evolution_scan
# step, the <evolution> line in the architect envelope, and the effort-weight
# instruction. Without all three the module runs but its output is never
# consumed (mechanism firing without value conversion).
K226_STEP=$(/usr/bin/grep -c 'name="evolution_scan"' "$ROOT/workflows/arch-health-scan.md" || true)
K226_ENV=$(/usr/bin/grep -c '<evolution>Read .devt/state/evolution-report.md' "$ROOT/workflows/arch-health-scan.md" || true)
K226_WEIGHT=$(/usr/bin/grep -c 'EFFORT-WEIGHT' "$ROOT/workflows/arch-health-scan.md" || true)
if [ "$K226_STEP" = "1" ] && [ "$K226_ENV" = "1" ] && [ "$K226_WEIGHT" = "1" ]; then
  pass "K226: arch-health-scan.md evolution wiring — scan step + architect envelope block + effort-weight instruction"
else
  fail "K226: evolution wiring incomplete — step=$K226_STEP(exp 1) env=$K226_ENV(exp 1) weight=$K226_WEIGHT(exp 1)"
fi

# K227: symbol_anchored working-tree caveat — the impact plan must attach
# symbol_anchored_caveat when untracked / added-after-build code files are
# invisible to blast_radius (graph indexes commits). Shares one git fixture
# with K228: base commit = graph build anchor; feature branch with
# comment/import-only hunks; one untracked code file. The impact plan must
# attach symbol_anchored_caveat (graph indexes commits — untracked files are
# invisible to blast_radius) and severity_calibration_note (cosmetic-heavy
# diff must not inflate severity off a popularity-driven effect_size).
K227_T=$(mktemp -d); (
  cd "$K227_T" && git init -q -b main . && git config user.email t@t && git config user.name t
  mkdir -p .devt/state app graphify-out
  echo '{"graphify":{"enabled":true}}' > .devt/config.json
  printf 'import os\n\ndef popular_svc():\n    return os.getcwd()\n' > app/svc.py
  git add -A && git commit -qm base
  BUILT=$(git rev-parse HEAD)
  node -e "require('fs').writeFileSync('graphify-out/graph.json', JSON.stringify({built_at_commit:'$BUILT', nodes:[{id:'n1',label:'popular_svc',source_file:'app/svc.py',source_location:'app/svc.py:3'}], edges:[]}))"
  git checkout -qb feature
  printf 'import sys\nimport os\n\n# comment one\n# comment two\ndef popular_svc():\n    return os.getcwd()\n' > app/svc.py
  printf '# prose\nnew doc line\n' > NOTES.md
  git add -A && git commit -qm cosmetic
  printf 'def moved_thing():\n    pass\n' > app/untracked_new.py
  printf '{"topic":{"symbols":["popular_svc"]},"graph_stats":{"state":"ready"}}' > .devt/state/preflight-brief.json
  printf 'active: true\ntask: "review the svc changes"\nworkflow_type: code_review\n' > .devt/state/workflow.yaml
) >/dev/null 2>&1
K227_PLAN=$( (cd "$K227_T" && node "$ROOT/bin/devt-tools.cjs" state compute-impact-plan --primary-branch=main 2>/dev/null) )
K227_EVAL=$(printf '%s' "$K227_PLAN" | node -e "let s='';process.stdin.on('data',x=>s+=x);process.stdin.on('end',()=>{try{const j=JSON.parse(s);const cav=typeof j.symbol_anchored_caveat==='string'&&j.symbol_anchored_caveat.indexOf('1 untracked')>=0;const hc=j.hunk_census&&j.hunk_census.total_hunks>=3&&j.hunk_census.cosmetic_ratio>=0.5;const note=typeof j.severity_calibration_note==='string'&&j.severity_calibration_note.indexOf('caller sets')>=0;process.stdout.write((j.tier==='symbol_anchored'?'T':'t')+(cav?'C':'c')+(hc?'H':'h')+(note?'N':'n'))}catch{process.stdout.write('err')}})")
rm -rf "$K227_T"
if [ "${K227_EVAL:0:2}" = "TC" ]; then
  pass "K227: symbol_anchored working-tree caveat — untracked code file surfaces '1 untracked' caveat on the impact plan (graph indexes commits; blast runs against last-committed layout)"
else
  fail "K227: symbol_anchored caveat missing — eval=$K227_EVAL (expected TC..: Tier/Caveat)"
fi

# K228: hunk-census severity calibration — cosmetic-heavy diff (ratio >= the
# graphify.severity_note_threshold default 0.5) must attach hunk_census
# telemetry + severity_calibration_note carrying the keep-the-caller-sets
# clause. Evaluated from the same fixture plan K227 computed above.
if [ "${K227_EVAL:2:2}" = "HN" ]; then
  pass "K228: hunk-census severity calibration — cosmetic-heavy diff (ratio >=0.5) attaches severity_calibration_note with the keep-the-caller-sets clause + hunk_census telemetry"
else
  fail "K228: severity calibration note missing — eval=$K227_EVAL (expected ..HN: HunkCensus/Note)"
fi

# K229: degree-ranked dependents + framework-builtin filter — blast_radius
# must (a) exclude framework request/response/DI builtins (Depends, Request)
# from direct_dependents with noise telemetry, (b) order direct_dependents by
# in-degree descending, (c) emit direct_dependents_degrees with in_count so
# the drill-down top-3 ranks by structure instead of array position.
K229_T=$(mktemp -d); (
  cd "$K229_T" && mkdir -p .devt graphify-out
  echo '{"graphify":{"enabled":true}}' > .devt/config.json
  node -e "
const nodes=[{id:'n1',label:'PopularSvc',source_file:'app/svc.py',source_location:'app/svc.py:1'},
{id:'n2',label:'CallerA',source_file:'app/a.py',source_location:'app/a.py:1'},
{id:'n3',label:'CallerB',source_file:'app/b.py',source_location:'app/b.py:1'},
{id:'n4',label:'CallerHub',source_file:'app/hub.py',source_location:'app/hub.py:1'},
{id:'n5',label:'Depends',source_file:'',source_location:null},
{id:'n6',label:'Request',source_file:'',source_location:null},
{id:'n7',label:'LeafUser',source_file:'app/leaf.py',source_location:'app/leaf.py:1'}];
const edges=[{source:'n2',target:'n1',confidence:'HIGH'},{source:'n3',target:'n1',confidence:'HIGH'},
{source:'n4',target:'n1',confidence:'HIGH'},{source:'n5',target:'n1',confidence:'HIGH'},
{source:'n6',target:'n1',confidence:'HIGH'},{source:'n7',target:'n4',confidence:'HIGH'},
{source:'n2',target:'n4',confidence:'HIGH'},{source:'n3',target:'n4',confidence:'HIGH'}];
require('fs').writeFileSync('graphify-out/graph.json', JSON.stringify({nodes, edges}));
"
) >/dev/null 2>&1
K229_EVAL=$( (cd "$K229_T" && node -e "
const g=require('$ROOT/bin/modules/graphify.cjs');
const r=g.blastRadius(['PopularSvc']);
const noBuiltins=!r.direct_dependents.includes('Depends')&&!r.direct_dependents.includes('Request');
const ranked=r.direct_dependents[0]==='CallerHub';
const degrees=Array.isArray(r.direct_dependents_degrees)&&r.direct_dependents_degrees[0]&&r.direct_dependents_degrees[0].label==='CallerHub'&&r.direct_dependents_degrees[0].in_count===3;
const telem=r.noise_telemetry&&r.noise_telemetry.filtered_noise>=2;
process.stdout.write((noBuiltins?'B':'b')+(ranked?'R':'r')+(degrees?'D':'d')+(telem?'T':'t'));
" 2>/dev/null) )
rm -rf "$K229_T"
if [ "$K229_EVAL" = "BRDT" ]; then
  pass "K229: blast_radius filters framework builtins (Depends/Request, telemetry counted) + ranks direct_dependents by in-degree + emits direct_dependents_degrees with in_count"
else
  fail "K229: dependent ranking/builtin filter wrong — eval=$K229_EVAL (expected BRDT: Builtins/Ranked/Degrees/Telemetry)"
fi

# K230: get_neighbors confidence split + INFERRED cap — INFERRED (low-confidence
# co-location) neighbors rank BELOW EXTRACTED and the INFERRED tail is capped at
# graphify.inferred_neighbor_cap (default 25); telemetry surfaces the split.
# Field-observed: a 247-neighbor result split 228 INFERRED / 19 EXTRACTED, the
# co-location bulk drowning the trustworthy structural edges.
K230_T=$(mktemp -d); (
  cd "$K230_T" && mkdir -p .devt graphify-out
  echo '{"graphify":{"enabled":true}}' > .devt/config.json
  node -e "
const nodes=[{id:'h',label:'Hub',source_file:'app/hub.py',source_location:'app/hub.py:1'}];
const edges=[];
['Ext1','Ext2','Ext3'].forEach((l,i)=>{nodes.push({id:'e'+i,label:l,source_file:'app/e'+i+'.py',source_location:'app/e'+i+'.py:1'});edges.push({source:'e'+i,target:'h',relation:'calls',confidence:'EXTRACTED'});});
for(let i=0;i<30;i++){nodes.push({id:'i'+i,label:'Inf'+i,source_file:'app/inf/f'+i+'.py',source_location:'app/inf/f'+i+'.py:1'});edges.push({source:'i'+i,target:'h',relation:'uses',confidence:'INFERRED'});}
require('fs').writeFileSync('graphify-out/graph.json',JSON.stringify({nodes,edges}));
"
) >/dev/null 2>&1
K230_EVAL=$( (cd "$K230_T" && node -e "
const g=require('$ROOT/bin/modules/graphify.cjs');
const r=g.getNeighbors('Hub',{direction:'in',depth:1});
const res=r.results||[];
const reliableFirst=res.slice(0,3).every(x=>x.confidence==='EXTRACTED');
const capped=res.filter(x=>x.confidence==='INFERRED').length===25;
const total=res.length===28;
const telem=r.confidence_extracted===3&&r.confidence_inferred_total===30&&r.confidence_inferred_capped===5;
process.stdout.write((reliableFirst?'R':'r')+(capped?'C':'c')+(total?'T':'t')+(telem?'M':'m'));
" 2>/dev/null) )
rm -rf "$K230_T"
if [ "$K230_EVAL" = "RCTM" ]; then
  pass "K230: get_neighbors ranks EXTRACTED before INFERRED + caps INFERRED tail at 25 (default) + surfaces confidence_extracted/_inferred_total/_inferred_capped telemetry"
else
  fail "K230: confidence split wrong — eval=$K230_EVAL (expected RCTM: Reliable-first/Capped/Total/teleMetry)"
fi

# K231: blast_radius relevance-ranked drill-down targets — a dependent co-located
# with a changed symbol (source_file in the changed set → relevance_tier 2)
# outranks an incidental high-in-degree god-node; the god-node is DEMOTED to the
# bottom but stays present (real dependent, never dropped) and carries
# is_god_node + pure_god_node so the F16 step routes it to the --max-bytes
# transport fallback instead of surfacing it ahead of relevant callers.
K231_T=$(mktemp -d); (
  cd "$K231_T" && mkdir -p .devt graphify-out
  echo '{"graphify":{"enabled":true}}' > .devt/config.json
  node -e "
const nodes=[{id:'t',label:'Target',source_file:'app/target.py',source_location:'app/target.py:1'},
 {id:'rc',label:'RelevantCaller',source_file:'app/target.py',source_location:'app/target.py:9'},
 {id:'pc',label:'PlainCaller',source_file:'app/plain.py',source_location:'app/plain.py:1'},
 {id:'gn',label:'GodNode',source_file:'app/god.py',source_location:'app/god.py:1'}];
const edges=[{source:'rc',target:'t',relation:'calls',confidence:'EXTRACTED'},
 {source:'pc',target:'t',relation:'calls',confidence:'EXTRACTED'},
 {source:'gn',target:'t',relation:'calls',confidence:'EXTRACTED'}];
for(let i=0;i<20;i++){nodes.push({id:'gf'+i,label:'GF'+i,source_file:'app/gf'+i+'.py',source_location:'app/gf'+i+'.py:1'});edges.push({source:'gf'+i,target:'gn',relation:'calls',confidence:'EXTRACTED'});}
for(let i=0;i<12;i++){nodes.push({id:'c'+i,label:'C'+i,source_file:'app/c'+i+'.py',source_location:'app/c'+i+'.py:1'});}
for(let i=0;i<12;i++){edges.push({source:'c'+i,target:'c'+((i+1)%12),relation:'calls',confidence:'EXTRACTED'});edges.push({source:'c'+i,target:'c'+((i+2)%12),relation:'calls',confidence:'EXTRACTED'});}
require('fs').writeFileSync('graphify-out/graph.json',JSON.stringify({nodes,edges}));
"
) >/dev/null 2>&1
K231_EVAL=$( (cd "$K231_T" && node -e "
const g=require('$ROOT/bin/modules/graphify.cjs');
const r=g.blastRadius(['Target']);
const dd=r.direct_dependents||[];
const deg=Object.fromEntries((r.direct_dependents_degrees||[]).map(d=>[d.label,d]));
const rcFirst=dd[0]==='RelevantCaller';
const godPresent=dd.includes('GodNode');
const godLast=dd[dd.length-1]==='GodNode';
const rcTier=deg.RelevantCaller&&deg.RelevantCaller.relevance_tier===2;
const godFlag=deg.GodNode&&deg.GodNode.is_god_node===true&&deg.GodNode.pure_god_node===true;
process.stdout.write((rcFirst?'F':'f')+(godPresent?'P':'p')+(godLast?'L':'l')+(rcTier?'T':'t')+(godFlag?'G':'g'));
" 2>/dev/null) )
rm -rf "$K231_T"
if [ "$K231_EVAL" = "FPLTG" ]; then
  pass "K231: blast_radius ranks co-located (relevance_tier 2) dependents above high-in-degree god-nodes; god-node demoted-not-dropped + flagged is_god_node/pure_god_node for --max-bytes routing"
else
  fail "K231: relevance ranking wrong — eval=$K231_EVAL (expected FPLTG: First/Present/Last/Tier/Godflag)"
fi

# K232: evolution scan excludes test files from ALL behavioral metrics (hotspots,
# coupling, fix density, churn) — language-general (Python/Go/JS-TS/Java + tests/
# dirs), config-gated (evolution.exclude_tests, default on) with an
# --include-tests escape hatch and a test_files_excluded telemetry counter. Tests
# churn on every feature + co-change with the code they cover, inflating signal.
K232_T=$(mktemp -d)
(
  cd "$K232_T"
  git init -q . >/dev/null 2>&1
  git config user.email k232@devt.test && git config user.name K232
  mkdir -p app tests src/test
  printf 'x=1\n' > app/service.py
  printf 'y=1\n' > app/handler.go
  printf 'x=1\n' > tests/test_service.py
  printf 'x=1\n' > app/handler_test.go
  printf 'x=1\n' > app/widget.spec.ts
  printf 'x=1\n' > app/widget.test.tsx
  printf 'x=1\n' > tests/conftest.py
  printf 'x=1\n' > src/test/FooTest.java
  git add -A >/dev/null && git commit -qm "init" >/dev/null
  printf 'x=2\n' > app/service.py; printf 'x=2\n' > tests/test_service.py
  git add -A >/dev/null && git commit -qm "fix: service" >/dev/null
) >/dev/null 2>&1
K232_DEF=$( (cd "$K232_T" && node "$ROOT/bin/devt-tools.cjs" evolution scan --no-write 2>/dev/null) || echo "{}")
K232_INC=$( (cd "$K232_T" && node "$ROOT/bin/devt-tools.cjs" evolution scan --no-write --include-tests 2>/dev/null) || echo "{}")
rm -rf "$K232_T"
K232_CHECK=$(node -e "
  const def = JSON.parse(process.argv[1] || '{}');
  const inc = JSON.parse(process.argv[2] || '{}');
  const f = [];
  const hs = (def.top_hotspots || []).map(h => h.file);
  if (!hs.includes('app/service.py')) f.push('prod service.py missing from hotspots');
  if (hs.some(x => /test|spec|conftest/i.test(x))) f.push('test leaked into hotspots: ' + JSON.stringify(hs));
  if (def.test_files_excluded !== 6) f.push('test_files_excluded != 6 (got ' + def.test_files_excluded + ')');
  if (def.files_tracked !== 2) f.push('files_tracked != 2 (got ' + def.files_tracked + ')');
  if (inc.test_files_excluded !== 0) f.push('--include-tests still excluded (got ' + inc.test_files_excluded + ')');
  if (inc.files_tracked <= def.files_tracked) f.push('--include-tests did not add files back');
  console.log(f.length === 0 ? 'OK' : 'FAIL:' + f.join('; '));
" "$K232_DEF" "$K232_INC" 2>&1 || echo "FAIL:node error")
if [ "$K232_CHECK" = "OK" ]; then
  pass "K232: evolution scan excludes 6 multi-language test files from all metrics + test_files_excluded counter + --include-tests escape hatch restores them"
else
  fail "K232: evolution test-exclusion — $K232_CHECK"
fi

# K234: no agent/skill body instructs the model to reproduce its OWN internal
# reasoning as response text. Newer Claude models (Fable 5 era) can trigger a
# reasoning_extraction refusal — and an elevated fallback to a heavier model —
# when a prompt tells them to echo/transcribe/output their internal reasoning,
# chain-of-thought, or thought process verbatim. Bodies that legitimately ask
# an agent to "explain your reasoning for this finding" are fine: the gate only
# fires on a reproduce-verb paired with a QUALIFIED reasoning-noun (internal /
# chain-of-thought / thought-process / trace / tokens / hidden / raw / verbatim),
# never bare "reasoning". Self-tests that a synthetic offender is caught so the
# pattern can't silently rot into an always-pass.
K234_CHECK=$(node -e "
  const fs=require('fs');
  const VERB='(echo|transcribe|reproduce|repeat|dump|print|output|paste|reveal|narrate|verbalize|surface|write out|show)';
  const NOUN='(internal reasoning|chain[- ]of[- ]thought|thought process|thinking process|reasoning trace|reasoning tokens|hidden reasoning|raw reasoning|your reasoning verbatim)';
  const re=new RegExp(VERB+'[^.\\\\n]{0,40}'+NOUN,'i');
  // self-test: the pattern MUST catch a real offender and MUST NOT catch legit prose
  if(!re.test('transcribe your internal reasoning into the output')){console.log('SELFTEST_FAIL:false-negative');process.exit(0);}
  if(re.test('explain your reasoning for each finding in review.md')){console.log('SELFTEST_FAIL:false-positive');process.exit(0);}
  const files=[];
  for(const f of fs.readdirSync('$ROOT/agents')) if(f.endsWith('.md')) files.push('$ROOT/agents/'+f);
  for(const d of fs.readdirSync('$ROOT/skills',{withFileTypes:true})) if(d.isDirectory()){const p='$ROOT/skills/'+d.name+'/SKILL.md'; if(fs.existsSync(p)) files.push(p);}
  const hits=[];
  for(const f of files){for(const line of fs.readFileSync(f,'utf8').split('\\n')) if(re.test(line)) hits.push(f.replace('$ROOT/','')+': '+line.trim().slice(0,80));}
  console.log(hits.length===0?'OK':'HITS:'+hits.join(' | '));
" 2>&1 || echo "FAIL:node error")
if [ "$K234_CHECK" = "OK" ]; then
  pass "K234: no agent/skill body instructs the model to reproduce its internal reasoning (reasoning_extraction refusal guard)"
else
  fail "K234: reasoning-extraction footgun — $K234_CHECK"
fi

# K235: blast_radius transparency + degree coherence (greenfield field receipt).
# Synthetic graph carries a homonym (an edgeless namesake of the real caller,
# ordered first so a label re-resolution would pick it). Asserts three fixes:
#   (1) a surviving direct dependent's edge_count is computed from the BFS-
#       visited node id, NOT a label re-resolution that returns the first
#       edgeless homonym — the field-observed "dependent with edge_count:0"
#       contradiction. (Distinguishes the fix: pre-fix this is 0.)
#   (2) every filtered dependent is surfaced in a reason-coded dropped_sample,
#       so a wrongly-filtered real consumer is auditable instead of a black box.
#   (3) when raw dependent count ≤ threshold, raw_direct_dependents exposes the
#       full unfiltered set (filter demoted to advisory), keyed on dependent
#       count not file count.
K235_T=$(mktemp -d)
mkdir -p "$K235_T/.devt" "$K235_T/graphify-out"
printf '{"graphify":{"enabled":true}}' > "$K235_T/.devt/config.json"
node -e '
  const fs=require("fs");
  fs.writeFileSync(process.argv[1], JSON.stringify({
    nodes:[
      {id:"n_homonym",label:"handle_request",source_file:"app/other.py"},
      {id:"n_seed",label:"TargetService",source_file:"app/svc.py"},
      {id:"n_call",label:"handle_request",source_file:"app/routes.py"},
      {id:"n_int",label:"int",source_file:""},
      {id:"n_test",label:"test_it",source_file:"tests/test_svc.py"}
    ],
    links:[
      {source:"n_call",target:"n_seed",relation:"calls",confidence:"EXTRACTED"},
      {source:"n_int",target:"n_seed",relation:"uses",confidence:"EXTRACTED"},
      {source:"n_test",target:"n_seed",relation:"calls",confidence:"EXTRACTED"}
    ],
    built_at_commit:"testsha"
  }));
' "$K235_T/graphify-out/graph.json"
K235_OUT=$( (cd "$K235_T" && node "$ROOT/bin/devt-tools.cjs" graphify blast-radius TargetService 2>/dev/null) || echo "{}")
rm -rf "$K235_T"
K235_CHECK=$(node -e '
  let r; try { r=JSON.parse(process.argv[1]||"{}"); } catch(e){ console.log("FAIL:parse "+e.message); process.exit(0); }
  const f=[];
  const direct=r.direct_dependents||[];
  if(!direct.includes("handle_request")) f.push("real caller not in direct_dependents: "+JSON.stringify(direct));
  const deg=(r.direct_dependents_degrees||[]).find(d=>d.label==="handle_request");
  if(!deg) f.push("no degree entry for handle_request");
  else if(deg.edge_count<1) f.push("edge_count:0 bug — label re-resolution hit the edgeless homonym");
  const ds=r.dropped_sample||[];
  const reasons=new Set(ds.map(d=>d.reason));
  if(!reasons.has("noise")) f.push("dropped_sample missing noise reason");
  if(!reasons.has("test_path")) f.push("dropped_sample missing test_path reason");
  if(!ds.some(d=>d.label==="int")) f.push("filtered int not in dropped_sample");
  const raw=r.raw_direct_dependents;
  if(!Array.isArray(raw)) f.push("raw_direct_dependents not exposed at raw_count "+r.raw_direct_count);
  else {
    if(raw.length!==3) f.push("raw_direct_dependents length "+raw.length+" != 3");
    const hr=raw.find(x=>x.label==="handle_request");
    const it=raw.find(x=>x.label==="int");
    if(hr && hr.filtered_reason!==null) f.push("survivor marked filtered: "+hr.filtered_reason);
    if(it && it.filtered_reason!=="noise") f.push("int filtered_reason != noise");
  }
  console.log(f.length===0?"OK":"FAIL:"+f.join("; "));
' "$K235_OUT" 2>&1 || echo "FAIL:node error")
if [ "$K235_CHECK" = "OK" ]; then
  pass "K235: blast_radius degree coherence (BFS-id not homonym re-resolution) + dropped_sample transparency + small-diff raw_direct_dependents exposure"
else
  fail "K235: blast-radius transparency/coherence — $K235_CHECK"
fi

# K236: review-weight is FAIL-SAFE (greenfield field receipt — "scale ceremony to
# change size"). Light is EARNED by proving absence of danger, never granted by a
# single metric. Asserts: a small clean change is light-eligible; a risk-surface
# path (auth) OR a god-node OR too-many-domains forces heavy (hard gates); a
# graph-blind change (tier=skip / no blast headline) is NOT eligible (absence of
# a headline is not evidence of safety); a lockfile-heavy diff (many files but
# few LOGIC files) stays light-eligible (file-count is the wrong trigger); and
# effect_size is ADVISORY-only (popularity-derived — a junk anchor inflates it;
# second field receipt caught it blocking as a sole gate against its own docs).
K236_CHECK=$(node -e '
  const { assessReviewWeight } = require("'"$ROOT"'/bin/modules/review-weight.cjs");
  const f = [];
  const E = (name, opts, want) => { const r = assessReviewWeight(opts); if (r.eligible !== want) f.push(name + " eligible=" + r.eligible + " want " + want + " [" + (r.blocked_by||[]).join("|") + "]"); };
  const graph = { effectSize: "small", godNodeMatch: false, tier: "symbol_anchored" };
  E("small-clean", { files: ["app/svc/a.py","app/svc/b.py"], ...graph }, true);
  E("auth-risk-surface", { files: ["app/auth/token.py"], ...graph }, false);
  E("migration", { files: ["app/migrations/0001.py"], ...graph }, false);
  E("god-node", { files: ["app/x.py"], effectSize: "small", godNodeMatch: true, tier: "symbol_anchored" }, false);
  E("graph-blind-skip", { files: ["app/x.py"], effectSize: null, godNodeMatch: null, tier: "skip" }, false);
  const el = assessReviewWeight({ files: ["app/x.py"], effectSize: "large", godNodeMatch: false, tier: "symbol_anchored" });
  if (!el.eligible) f.push("effect-large must be ADVISORY not blocking [" + (el.blocked_by||[]).join("|") + "]");
  if (!(el.advisories||[]).some(a => a.includes("effect_size: large"))) f.push("effect-large advisory missing");
  E("lockfile-heavy", { files: ["uv.lock","requirements.txt","VERSION","README.md","app/svc/a.py"], ...graph }, true);
  E("empty-diff", { files: [], ...graph }, false);
  // risk-surface pattern removable via config-style "!" (removal honored)
  const withRemoval = assessReviewWeight({ files: ["app/auth/token.py"], ...graph });
  if (!(withRemoval.risk_surface_hits||[]).length) f.push("auth path did not register a risk hit");
  console.log(f.length === 0 ? "OK" : "FAIL:" + f.join("; "));
' 2>&1 || echo "FAIL:node error")
if [ "$K236_CHECK" = "OK" ]; then
  pass "K236: review-weight fail-safe verdict — small-clean light; auth/god-node/domains force heavy; graph-blind + empty-diff not eligible; effect_size advisory-only; lockfile-heavy stays light"
else
  fail "K236: review-weight — $K236_CHECK"
fi

# K237: memory-pre-flight skill keeps the HOT protocol inline (preloaded by 8-9
# agents per dispatch) but lazy-loads its cold detail. Asserts: the skill body
# retains the PREFLIGHT scratchpad-line format + the deny-recovery source table
# (the protocol an agent needs mid-edit); it points to the on-demand
# `references/memory-pre-flight-details.md`; that reference exists with real
# content (the 5-lane table + config + multi-root moved out of the preloaded
# body); and the skill stays under a body-weight ceiling so the cold detail
# can't silently creep back into every dispatch.
K237_SKILL="$ROOT/skills/memory-pre-flight/SKILL.md"
K237_REF="$ROOT/references/memory-pre-flight-details.md"
K237_FAIL=""
grep -q "PREFLIGHT <ISO-timestamp> <action> <file_path>" "$K237_SKILL" || K237_FAIL="$K237_FAIL no-PREFLIGHT-format;"
grep -q "preflight-denies.jsonl" "$K237_SKILL" || K237_FAIL="$K237_FAIL no-deny-recovery;"
grep -q "references/memory-pre-flight-details.md" "$K237_SKILL" || K237_FAIL="$K237_FAIL no-reference-pointer;"
[ -f "$K237_REF" ] || K237_FAIL="$K237_FAIL reference-missing;"
grep -q "5-Lane File Pre-Flight" "$K237_REF" 2>/dev/null || K237_FAIL="$K237_FAIL reference-no-5lane;"
K237_LINES=$(wc -l < "$K237_SKILL" 2>/dev/null | tr -d ' ')
[ "${K237_LINES:-999}" -le 160 ] || K237_FAIL="$K237_FAIL skill-over-160-lines($K237_LINES);"
if [ -z "$K237_FAIL" ]; then
  pass "K237: memory-pre-flight keeps hot protocol inline (PREFLIGHT format + deny recovery), lazy-loads cold detail to references/ (${K237_LINES} lines)"
else
  fail "K237: memory-pre-flight slim broke —$K237_FAIL"
fi

# K238: `graphify augment-impact-map` reproduces substep-7's six deterministic
# sections (folded out of ~110 lines of inline jq). Functional test on a
# synthetic graph + brief: a god-node file emits the file + symbol warnings;
# a >5 dropped-symbol list emits the truncation banner + section; a partial
# hyperedge and an ambiguous binding emit with byte-identical wording; and the
# preflight-god fallback is correctly suppressed when diff god-nodes are present.
# Behavior-preservation guard so the fold can't silently drop a reviewer signal.
K238_T=$(mktemp -d)
mkdir -p "$K238_T/.devt/state" "$K238_T/graphify-out"
printf '{"graphify":{"enabled":true}}' > "$K238_T/.devt/config.json"
node -e '
  const fs=require("fs");
  const nodes=[{id:"n_route",label:"handler",source_file:"app/routes.py"}];
  const links=[];
  for(let i=0;i<60;i++){nodes.push({id:"c"+i,label:"c"+i,source_file:"app/c"+i+".py"});links.push({source:"c"+i,target:"n_route",relation:"calls",confidence:"EXTRACTED"});}
  fs.writeFileSync(process.argv[1], JSON.stringify({nodes,links,built_at_commit:"x"}));
' "$K238_T/graphify-out/graph.json"
printf '%s' '{"hyperedges_matched":[{"label":"lf","member_count":4,"members":["a","b","c","d"],"members_in_scope":["a"],"completeness":0.25}],"blast":{"ambiguous_bindings":1,"ambiguous_details":[{"symbol":"Foo","node":{"source_file":"app/legacy.py","label":"Foo"}}]},"god_nodes":[{"symbol":"GT","edge_count":120}]}' > "$K238_T/.devt/state/preflight-brief.json"
printf '# Impact\nheadline\n' > "$K238_T/.devt/state/graph-impact.md"
printf '%s' '["s1","s2","s3","s4","s5","s6","s7"]' > "$K238_T/.devt/state/topic-symbols-dropped.json"
K238_CHECK=$(node -e '
  const path = require("path"), fs = require("fs");
  const root = process.argv[1];
  // loadGraph() resolves the graph from process.cwd(), so chdir into the fixture
  // before requiring/calling (matches how the CLI runs — from the project root).
  process.chdir(root);
  const g = require("'"$ROOT"'/bin/modules/graphify.cjs");
  g.augmentImpactMap({ projectRoot: root, files: ["app/routes.py"], edgeThreshold: 50, rawCount: "20" });
  const gi = fs.readFileSync(path.join(root, ".devt/state/graph-impact.md"), "utf8");
  const f = [];
  const want = [
    ["## God-node warning", "- `app/routes.py` — `handler` has 60 edges; signature changes ripple to all callers. Prefer additive changes."],
    ["## Symbol-level god-nodes", "- `handler` (app/routes.py) has 60 edges; any non-additive change cascades through every caller."],
    ["> **Subject symbols truncated**: 7 of 20", null],
    ["## Subject symbols dropped (truncation notice)", null],
    ["## Hyperedge completeness (partial-coverage semantic groupings)", "- **lf** — 1 of 4 members in scope (25% complete). Out-of-scope members: b, c, d"],
    ["## Ambiguous bindings", "- `Foo` → resolves at `app/legacy.py` (label: `Foo`)"],
  ];
  for (const [hdr, row] of want) {
    if (!gi.includes(hdr)) f.push("missing section: " + hdr);
    if (row && !gi.includes(row)) f.push("wrong row for " + hdr);
  }
  if (gi.includes("from preflight, not diff-anchored")) f.push("preflight fallback fired despite present god-nodes");
  console.log(f.length === 0 ? "OK" : "FAIL:" + f.join("; "));
' "$K238_T" 2>&1 || echo "FAIL:node error")
rm -rf "$K238_T"
if [ "$K238_CHECK" = "OK" ]; then
  pass "K238: graphify augment-impact-map emits substep-7's six sections byte-identically (god-node file+symbol, truncation banner+section, hyperedge, ambiguous; fallback suppressed when god-nodes present)"
else
  fail "K238: augment-impact-map fold — $K238_CHECK"
fi

# K239: model surface currency + effort-lever integrity — sonnet alias resolves
# to claude-sonnet-5, no {efforts.*} substitution survives in dispatch.cjs, and
# every agent pins its effort in frontmatter (the only lever the harness honors).
K239_SONNET=$(node -e 'const {resolveModelId}=require("'"$ROOT"'/bin/modules/model-profiles.cjs"); console.log(resolveModelId("sonnet")==="claude-sonnet-5"?"1":"0");' 2>/dev/null)
K239_EFFORT_SUBST=$(/usr/bin/grep -c "{efforts\." "$ROOT/bin/modules/dispatch.cjs" || true)
K239_FRONTMATTER=$(/usr/bin/grep -l "^effort:" "$ROOT"/agents/*.md 2>/dev/null | wc -l | tr -d " ")
if [ "$K239_SONNET" = "1" ] && [ "${K239_EFFORT_SUBST:-1}" = "0" ] && [ "$K239_FRONTMATTER" = "11" ]; then
  pass "K239: sonnet→claude-sonnet-5 + no {efforts.*} substitution in dispatch.cjs + all 11 agents pin frontmatter effort"
else
  fail "K239: model/effort surface drift — sonnet5=$K239_SONNET effort_subst_hits=$K239_EFFORT_SUBST frontmatter_agents=$K239_FRONTMATTER"
fi

# K240: governing-rules inlining excludes static-compress .original.md backups
# (field bug: backups doubled the corpus per dispatch and cap-evicted live
# rules) while surfacing them in paths_excluded (telemetry-on-reduction), and
# scanDevRules listings skip them.
K240_T=$(mktemp -d)
mkdir -p "$K240_T/.devt/rules"
printf 'live rule body\n' > "$K240_T/.devt/rules/team-rules.md"
printf 'backup body\n' > "$K240_T/.devt/rules/team-rules.original.md"
K240_CHECK=$(node -e '
const { loadGoverningRules } = require(process.argv[2] + "/bin/modules/init.cjs");
// realpath the tmpdir — macOS mktemp returns symlinked paths (/var -> /private/var)
// that fail validatePath confinement inside loadGoverningRules.
const r = loadGoverningRules(require("fs").realpathSync(process.argv[1]));
const inlined = Object.keys(r.content);
const hasLive = inlined.includes(".devt/rules/team-rules.md");
const hasBackup = inlined.some(n => n.endsWith(".original.md"));
const excluded = (r.paths_excluded || []).some(e => e.reason === "static_compress_backup" && e.name.endsWith("team-rules.original.md"));
console.log(hasLive && !hasBackup && excluded ? "OK" : "FAIL:live=" + hasLive + " backup=" + hasBackup + " excluded=" + excluded);
' "$K240_T" "$ROOT" 2>&1 || echo "FAIL:node error")
rm -rf "$K240_T"
if [ "$K240_CHECK" = "OK" ]; then
  pass "K240: .original.md backups excluded from governing-rules inline set + surfaced in paths_excluded (static_compress_backup)"
else
  fail "K240: backup exclusion broken — $K240_CHECK"
fi

# K241: legacy surfaces stay deleted — the debugger's pre-agent-memory
# debug-knowledge-base.md compat shim and the context-monitor hook (harness
# auto-compaction owns the context lifecycle) must not resurface.
K241_DKB=$({ /usr/bin/grep -rl "debug-knowledge-base" "$ROOT/agents" "$ROOT/workflows" "$ROOT/docs/COMMANDS.md" 2>/dev/null || true; } | wc -l | tr -d " ")
K241_CM_FILE=0
if [ -f "$ROOT/hooks/context-monitor.sh" ]; then K241_CM_FILE=1; fi
K241_CM_REFS=$({ /usr/bin/grep -c "context-monitor" "$ROOT/hooks/hooks.json" "$ROOT/hooks/run-hook.js" 2>/dev/null || true; } | /usr/bin/awk -F: '{s+=$NF} END {print s+0}')
if [ "$K241_DKB" = "0" ] && [ "$K241_CM_FILE" = "0" ] && [ "${K241_CM_REFS:-1}" = "0" ]; then
  pass "K241: legacy surfaces stay deleted — no debug-knowledge-base refs (agents/workflows/COMMANDS) + no context-monitor (script/hooks.json/run-hook.js)"
