K243_TOOLS=$({ /usr/bin/grep -l "^tools:.*LSP" "$ROOT/agents/code-reviewer.md" "$ROOT/agents/debugger.md" "$ROOT/agents/programmer.md" 2>/dev/null || true; } | wc -l | tr -d " ")
