K248_SCHEMA=$(node -e 'const s=require("'"$ROOT"'/bin/modules/state.cjs"); const e=(s.JSON_INPUT_SCHEMAS||{})["acceptance-criteria.json"]; console.log(e && Array.isArray(e.required) && e.required.includes("criteria") ? "1" : "0");' 2>/dev/null)
