   && /usr/bin/grep -q "Frozen-criteria contract" "$ROOT/agents/verifier.md" \
   && /usr/bin/grep -q "acceptance-criteria.json" "$ROOT/agents/verifier.md" \
   && /usr/bin/grep -q "acceptance-criteria.json" "$ROOT/docs/STATE-RULES.md"; then
