K269_T=$(cd "$K269_T" && pwd -P)
mkdir -p "$K269_T/.devt/state"
echo '{}' > "$K269_T/.devt/config.json"
(cd "$K269_T" && node "$CLI" init workflow "k269") >/dev/null 2>&1
printf 'lane one done\n' > "$K269_T/.devt/state/review-lane-a.md"
cat >> "$K269_T/.devt/state/workflow.yaml" <<'EOF'
lanes:
  - id: "L1"
    community: "a"
    review_file: ".devt/state/review-lane-a.md"
    status: "substance_pass"
  - id: "L2"
    community: "b"
    review_file: ".devt/state/review-lane-b.md"
    status: "in_flight"
EOF
printf 'Reconciliation directive: prefer lane A severity.\n' > "$K269_T/notes.txt"
K269_OUT=$(cd "$K269_T" && node "$CLI" dispatch render-filled code-reviewer:code_review_parallel --notes-file=notes.txt 2>/dev/null || echo "")
K269_CHECK=$(printf '%s' "$K269_OUT" | node -e '
let s=""; process.stdin.on("data",d=>s+=d); process.stdin.on("end",()=>{
  const f = [];
  if (s.includes("{lane_files_newline_separated}")) f.push("placeholder not filled");
  if (!s.includes("review-lane-a.md")) f.push("terminal lane missing");
  if (s.includes("review-lane-b.md")) f.push("non-terminal lane leaked");
  if (!s.includes("<orchestrator_notes>") || !s.includes("Reconciliation directive")) f.push("notes not injected");
  console.log(f.length === 0 ? "OK" : "FAIL:" + f.join("; "));
});' 2>/dev/null || echo "FAIL:node error")
rm -rf "$K269_T"
if [ "$K269_CHECK" = "OK" ]; then
  pass "K269: consolidator render — lane_files pre-filled (terminal only), --notes-file injects <orchestrator_notes>"
else
  fail "K269: consolidator render broken — $K269_CHECK"
fi

# K270: structural synthesis trigger + single-source partition — the
# consolidator contract activates on the <lane_files> structure (custom task
# prose can't silently skip the marker), and the auto-partitioner routes
# through register-lanes instead of hand-building a lanes YAML splice (one
# sizing implementation, sidecars + diff artifacts for both partition paths).
if /usr/bin/grep -q "trigger is STRUCTURAL" "$ROOT/agents/code-reviewer.md" \
   && /usr/bin/grep -qF 'register-lanes --from="$PARTITION_JSON"' "$ROOT/workflows/code-review-parallel.md" \
   && ! /usr/bin/grep -q "devt-lanes-block.yaml" "$ROOT/workflows/code-review-parallel.md" \
   && /usr/bin/grep -q "render-filled code-reviewer:code_review_parallel" "$ROOT/workflows/code-review-parallel.md"; then
  pass "K270: structural synthesis trigger in agent body + auto-partitioner routes through register-lanes + consolidate documents the render path"
else
  fail "K270: synthesis trigger or partition single-sourcing regressed"
fi

# K271: python-fastapi template currency — the FastAPI/Pydantic best-practice
# calibration holds: no unmaintained security stack (python-jose gone; pwdlib
# is the hashing prescription), the Pydantic conventions add-on exists with
# its load-bearing sections, mechanical rule enforcement is wired (ruff FAST +
# ASYNC groups), the async trap kit is prescribed (lazy="raise"), and the
# pytest-asyncio 1.x config idiom is present.
K271_T="$ROOT/templates/python-fastapi"
# python-jose may appear ONLY as a prohibition ("Never `python-jose`"), never
# as a prescription — compare total mentions against prohibition-line mentions.
K271_JOSE_ALL=$({ /usr/bin/grep -rh "python-jose" "$K271_T" 2>/dev/null || true; } | wc -l | tr -d " ")
K271_JOSE_BANNED=$({ /usr/bin/grep -rh "python-jose" "$K271_T" 2>/dev/null || true; } | { /usr/bin/grep -c "Never" || true; } | tr -d " ")
if [ -f "$K271_T/pydantic-patterns.md" ] \
   && /usr/bin/grep -q "exclude_unset" "$K271_T/pydantic-patterns.md" \
   && /usr/bin/grep -q "validate_by_name" "$K271_T/pydantic-patterns.md" \
   && [ "$K271_JOSE_ALL" = "$K271_JOSE_BANNED" ] \
   && /usr/bin/grep -q "pwdlib" "$K271_T/architecture.md" \
   && /usr/bin/grep -q '"FAST", "ASYNC"' "$K271_T/architecture.md" \
   && /usr/bin/grep -q 'lazy="raise"' "$K271_T/coding-standards.md" \
   && /usr/bin/grep -q "asyncio_default_fixture_loop_scope" "$K271_T/architecture.md" \
   && /usr/bin/grep -q "RFC 9457" "$K271_T/architecture.md" \
   && /usr/bin/grep -q "Never block inside a streaming generator" "$K271_T/architecture.md"; then
  pass "K271: python-fastapi template currency — pydantic-patterns add-on + PyJWT/pwdlib stack + FAST/ASYNC enforcement + async trap kit + pytest-asyncio 1.x idiom + RFC 9457 shape + streaming/SSE rules"
else
  fail "K271: template currency regressed (stale security stack, missing pydantic-patterns, dropped enforcement wiring, or missing error-shape/streaming sections)"
fi

# K272: graphify MCP scaffold correctness — the graph-path arg carries the
# platform-documented ${CLAUDE_PROJECT_DIR:-.} prefix (bare-relative resolves
# against the server's cwd, which the platform does not guarantee is the
# project root), and no surface recommends the removed `graphify mcp`
# subcommand as a registration form (health's fix message previously
# instructed users to register a server that cannot start).
if /usr/bin/grep -q 'CLAUDE_PROJECT_DIR:-\.}/graphify-out/graph.json' "$ROOT/bin/modules/setup.cjs" \
   && ! /usr/bin/grep -q '"mcp", "--project"' "$ROOT/bin/modules/health.cjs" \
   && ! /usr/bin/grep -q '\\"mcp\\", \\"--project\\"' "$ROOT/bin/modules/health.cjs" \
   && /usr/bin/grep -q 'graphify.serve' "$ROOT/bin/modules/health.cjs"; then
  pass "K272: graphify MCP scaffold — CLAUDE_PROJECT_DIR-prefixed graph path + no dead 'graphify mcp' registration hint"
else
  fail "K272: graphify MCP scaffold regressed (bare-relative graph path or dead registration form reintroduced)"
fi

# K273: template copy excludes ephemeral/tooling dirs — a working repo drops
# __pycache__/.ruff_cache beside template sources (arch-scan tests execute in
# CI), and agents running with cwd inside a template scaffold a nested .devt/;
# without copy-layer exclusion these SHIP into every scaffolded project
# (field: fresh setup delivered compiled bytecode caches into .devt/rules/).
# Also guards against over-exclusion: intentional template content
# (tests/architecture, detectors, pydantic-patterns) must still ship.
K273_T=$(mktemp -d)
K273_T=$(cd "$K273_T" && pwd -P)
mkdir -p "$ROOT/templates/python-fastapi/__pycache__" 2>/dev/null || true
touch "$ROOT/templates/python-fastapi/__pycache__/junk.pyc" 2>/dev/null || true
mkdir -p "$ROOT/templates/python-fastapi/.devt/state" 2>/dev/null || true
printf '{}' > "$ROOT/templates/python-fastapi/.devt/state/status.json" 2>/dev/null || true
(cd "$K273_T" && git init -q && node "$CLI" setup --template python-fastapi --mode create) >/dev/null 2>&1
K273_POLLUTION=$(cd "$K273_T" && { find .devt/rules -name "__pycache__" -o -name ".ruff_cache" -o -name ".devt" 2>/dev/null || true; } | wc -l | tr -d " ")
K273_CONTENT=1
[ -f "$K273_T/.devt/rules/tests/architecture/test_arch_scan_internals.py" ] || K273_CONTENT=0
[ -f "$K273_T/.devt/rules/detectors/layer_imports.py" ] || K273_CONTENT=0
[ -f "$K273_T/.devt/rules/pydantic-patterns.md" ] || K273_CONTENT=0
rm -rf "$K273_T" "$ROOT/templates/python-fastapi/.devt"
rm -f "$ROOT/templates/python-fastapi/__pycache__/junk.pyc"
if [ "$K273_POLLUTION" = "0" ] && [ "$K273_CONTENT" = "1" ]; then
  pass "K273: template copy exclusion — no __pycache__/.ruff_cache/.devt ships into scaffolds; intentional tests/detectors/pydantic-patterns content still does"
else
  fail "K273: copy exclusion broken — pollution=$K273_POLLUTION (exp 0) content=$K273_CONTENT (exp 1)"
fi

# K274: receipt-driven signal-integrity batch — each sub-check pins one cal
# fix whose shared root cause was "a signal that's only safe because a smart
# consumer happens to distrust it" (artifacts must carry their own guard
# rails):
#  a) synthesis-mode score contract: consolidated review.json carries
#     score:null + lane_scores[] (a merged deduction score saturates at the
#     0 floor and misleads any automation that trusts the field)
#  b) repro-spec contract: finder must attach exact placement/config to
#     behaviorally-testable claims; verifier must reproduce that spec
#     VERBATIM (improvised-placement refutation shipped a wrong withdrawal
#     twice in the field)
#  c) cost preview never ships without the value caveat + no mid-loop cost
#     readout (one-sided cost biases toward false economy)
#  d) code-review-input.md session-distance eviction (prep-window rule:
#     stale leftovers die, deliberate pre-writes survive)
#  e) the --raw-count glob sentinel is quoted with a non-glob default
#     (unquoted ? made zsh abort the augment step)
K274_OK=1
K274_WHY=""
/usr/bin/grep -q '"score": null' "$ROOT/agents/code-reviewer.md" || { K274_OK=0; K274_WHY="a:score-null"; }
/usr/bin/grep -q 'lane_scores' "$ROOT/agents/code-reviewer.md" || { K274_OK=0; K274_WHY="a:lane_scores"; }
/usr/bin/grep -q 'NO merged 0-100 score' "$ROOT/templates/dispatch/envelopes/code-reviewer-code_review_parallel.tmpl.md" || { K274_OK=0; K274_WHY="a:template"; }
/usr/bin/grep -q 'Lane score distribution' "$ROOT/workflows/code-review.steps.md" || { K274_OK=0; K274_WHY="a:present_findings"; }
/usr/bin/grep -q 'Repro-spec contract' "$ROOT/agents/code-reviewer.md" || { K274_OK=0; K274_WHY="b:finder"; }
/usr/bin/grep -q 'reproduce the finding.s exact spec' "$ROOT/agents/verifier.md" || { K274_OK=0; K274_WHY="b:verifier"; }
/usr/bin/grep -q 'NEVER present cost alone' "$ROOT/workflows/code-review.md" || { K274_OK=0; K274_WHY="c:preview"; }
/usr/bin/grep -q 'Do NOT add mid-verify-loop cost readouts' "$ROOT/workflows/code-review.md" || { K274_OK=0; K274_WHY="c:no-midloop"; }
/usr/bin/grep -q 'code-review-input.md: session-distance eviction' "$ROOT/bin/modules/state.cjs" || { K274_OK=0; K274_WHY="d:eviction"; }
/usr/bin/grep -q '"--raw-count=\${TOPIC_SYMBOLS_RAW_COUNT:-unknown}"' "$ROOT/workflows/code-review.md" || { K274_OK=0; K274_WHY="e:glob"; }
if /usr/bin/grep -q -- '--raw-count=\${TOPIC_SYMBOLS_RAW_COUNT:-?}' "$ROOT/workflows/code-review.md"; then K274_OK=0; K274_WHY="e:unquoted-sentinel-back"; fi
if [ "$K274_OK" = "1" ]; then
  pass "K274: signal-integrity batch — score-null synthesis contract + repro-spec both sides + cost-with-value preview + session-distance eviction + glob sentinel"
else
  fail "K274: signal-integrity batch regressed at $K274_WHY"
fi

# K274b: session-distance eviction BEHAVIORAL — stale leftover (>1h) dies on
# reset-soft, minutes-old deliberate pre-write survives.
K274B_T=$(mktemp -d)
K274B_T=$(cd "$K274B_T" && pwd -P)
mkdir -p "$K274B_T/.devt/state"
echo '{}' > "$K274B_T/.devt/config.json"
printf 'active: false\nworkflow_type: code_review\ntask: "old"\nphase: complete\ncreated_at: "2026-01-01T10:00:00.000Z"\n' > "$K274B_T/.devt/state/workflow.yaml"
echo "# stale scope" > "$K274B_T/.devt/state/code-review-input.md"
touch -t 202601011200 "$K274B_T/.devt/state/code-review-input.md"
(cd "$K274B_T" && node "$CLI" state reset-soft) >/dev/null 2>&1
K274B_STALE_GONE=$([ -f "$K274B_T/.devt/state/code-review-input.md" ] && echo 0 || echo 1)
echo "# deliberate pre-write" > "$K274B_T/.devt/state/code-review-input.md"
(cd "$K274B_T" && node "$CLI" state reset-soft) >/dev/null 2>&1
K274B_FRESH_KEPT=$([ -f "$K274B_T/.devt/state/code-review-input.md" ] && echo 1 || echo 0)
rm -rf "$K274B_T"
if [ "$K274B_STALE_GONE" = "1" ] && [ "$K274B_FRESH_KEPT" = "1" ]; then
  pass "K274b: code-review-input eviction behavioral — stale leftover evicted, fresh pre-write survives reset-soft"
else
  fail "K274b: eviction behavior wrong — stale_gone=$K274B_STALE_GONE fresh_kept=$K274B_FRESH_KEPT"
fi

# K275: review shared-steps partition integrity — the verify +
# present_findings bodies live ONCE in code-review.steps.md; both parents
# carry SHARED-STEP pointers + the mandatory-Read directive and contain NO
# resident copy of body-only content (the copy-paste era let the parallel
# path silently lose four gates the single path gained — this gate makes
# that drift class structurally impossible).
K275_OK=1; K275_WHY=""
S="$ROOT/workflows/code-review.steps.md"
/usr/bin/grep -q '<step name="verify"' "$S" || { K275_OK=0; K275_WHY="steps:verify-missing"; }
/usr/bin/grep -q '<step name="present_findings"' "$S" || { K275_OK=0; K275_WHY="steps:pf-missing"; }
/usr/bin/grep -q 'assert-verifier-graded-all-axes' "$S" || { K275_OK=0; K275_WHY="steps:axes-gate-missing"; }
/usr/bin/grep -q 'assert-no-raw-dispatches-this-session' "$S" || { K275_OK=0; K275_WHY="steps:rd-gate-missing"; }
/usr/bin/grep -q 'assert-claim-checks-resolved' "$S" || { K275_OK=0; K275_WHY="steps:cc-gate-missing"; }
/usr/bin/grep -q 'PARALLEL ONLY' "$S" || { K275_OK=0; K275_WHY="steps:mode-branches-missing"; }
for wf in code-review.md code-review-parallel.md; do
  P="$ROOT/workflows/$wf"
  /usr/bin/grep -q 'SHARED-STEP:verify' "$P" || { K275_OK=0; K275_WHY="$wf:verify-pointer"; }
  /usr/bin/grep -q 'SHARED-STEP:present_findings' "$P" || { K275_OK=0; K275_WHY="$wf:pf-pointer"; }
  /usr/bin/grep -q 'Read `${CLAUDE_PLUGIN_ROOT}/workflows/code-review.steps.md` now' "$P" || { K275_OK=0; K275_WHY="$wf:mandatory-read"; }
  # Disjointness: body-only markers must NOT reappear in the parents
  # (a resident copy silently shadows the shared source and drift restarts).
  /usr/bin/grep -q 'assert-verifier-graded-all-axes' "$P" && { K275_OK=0; K275_WHY="$wf:resident-verify-body"; }
  /usr/bin/grep -q 'Graphify activity surface' "$P" && { K275_OK=0; K275_WHY="$wf:resident-pf-body"; }
done
if [ "$K275_OK" = "1" ]; then
  pass "K275: review shared-steps partition — bodies single-sourced in code-review.steps.md (incl. axes/raw-dispatch/claim-check gates for BOTH paths), parents carry pointers + mandatory-Read, no resident copies"
else
  fail "K275: shared-steps partition regressed at $K275_WHY"
fi

# K276/K277/K278: memory-lifecycle behavioral trio — one fixture, three gates.
