if /usr/bin/grep -qF 'correlation_id>${cidRF}' "$ROOT/bin/modules/dispatch.cjs" \
   && /usr/bin/grep -qF '".devt", "state", "dispatch"' "$ROOT/bin/modules/dispatch.cjs" \
